pages.Directory:
import React, { useState, useEffect, useCallback } from "react";
import { Practitioner, Review } from "@/entities/all";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search, SlidersHorizontal, UserCircle, MapPin, RefreshCw, Loader2 } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { getCurrentLocation, sortByDistance } from "../components/utils/locationUtils";

import PractitionerCard from "../components/directory/PractitionerCard";
import PractitionerModal from "../components/directory/PractitionerModal";
import FilterModal from "../components/directory/FilterModal";
import MapView from "../components/directory/MapView";
import DailyQuote from "../components/directory/DailyQuote";

const formatAddress = (address) => {
    if (!address) return "Location not specified";
    const parts = [address.city, address.state_province, address.country];
    return parts.filter(Boolean).join(", ") || "Location not specified";
};

const ListPractitionerCard = ({ practitioner, averageRating, reviewCount, onClick }) => (
    <div onClick={onClick} className="flex items-center gap-4 p-6 rounded-2xl hover:bg-white cursor-pointer transition-all duration-200 hover:shadow-md border border-transparent hover:border-gray-200">
        <div className="w-16 h-16 rounded-full bg-gray-100 flex-shrink-0 overflow-hidden">
             {practitioner.profile_image_url ? (
                <img src={practitioner.profile_image_url} alt={practitioner.full_name} className="w-full h-full object-cover" />
            ) : (
                 <div className="w-full h-full flex items-center justify-center bg-gray-200">
                    <UserCircle className="w-10 h-10 text-gray-400" />
                 </div>
            )}
        </div>
        <div className="flex-1">
            <h3 className="font-semibold text-gray-900 text-lg">{practitioner.full_name}</h3>
             <p className="text-sm text-gray-500 flex items-center gap-1 mb-1"><MapPin className="w-3 h-3"/>{formatAddress(practitioner.address)}</p>
              {/* Only show ratings for verified practitioners */}
              {practitioner.is_verified && reviewCount > 0 && (
                <div className="flex items-center gap-1 mt-1">
                  <div className="flex">
                    {[...Array(5)].map((_, i) => (
                      <div
                        key={i}
                        className={`w-3 h-3 ${
                          i < Math.floor(averageRating) ? 'text-yellow-400' : 'text-gray-300'
                        }`}
                      >
                        ★
                      </div>
                    ))}
                  </div>
                  <span className="text-sm font-medium text-gray-900 ml-1">{averageRating}</span>
                  <span className="text-sm text-gray-500">({reviewCount})</span>
                </div>
              )}
        </div>
    </div>
);

export default function Directory() {
  const navigate = useNavigate();
  const [practitioners, setPractitioners] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [filteredPractitioners, setFilteredPractitioners] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedPractitioner, setSelectedPractitioner] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [showFilterModal, setShowFilterModal] = useState(false);
  const [viewMode, setViewMode] = useState("list");
  const [mapBounds, setMapBounds] = useState(null);
  const [mapPractitioners, setMapPractitioners] = useState([]);
  const [userLocation, setUserLocation] = useState(null);
  const [locationError, setLocationError] = useState(null);
  const [isGettingLocation, setIsGettingLocation] = useState(false);
  const [filters, setFilters] = useState({
    sortBy: "nearest",
    minRating: 0,
    priceRange: [0, 3],
    verificationLevel: "all"
  });

  // Get user location on component mount
  useEffect(() => {
    const getUserLocation = async () => {
      if (filters.sortBy !== "nearest") return;

      setIsGettingLocation(true);
      try {
        const location = await getCurrentLocation();
        setUserLocation(location);
        setLocationError(null);
        console.log("User location obtained:", location);
      } catch (error) {
        console.warn("Could not get user location:", error.message);
        setLocationError(error.message);
        setUserLocation(null);
      } finally {
        setIsGettingLocation(false);
      }
    };

    getUserLocation();
  }, [filters.sortBy]);

  const getPractitionerReviews = useCallback((practitionerId) => {
    return reviews.filter(review => review.practitioner_id === practitionerId);
  }, [reviews]);

  const getAverageRating = useCallback((practitionerId) => {
    const practitionerReviews = getPractitionerReviews(practitionerId);
    if (practitionerReviews.length === 0) return 0;
    const sum = practitionerReviews.reduce((acc, review) => acc + review.rating, 0);
    return (sum / practitionerReviews.length).toFixed(1);
  }, [getPractitionerReviews]);

  const loadData = async () => {
    console.log("Loading data...");
    setIsLoading(true);
    try {
      const practitionersData = await Practitioner.list("-created_date");
      console.log("Fetched practitioners:", practitionersData.length);

      // Get real IDs for mock review assignment
      const practitionerIds = practitionersData.map(p => p.id);

      // FIX: Find IDs for our spotlighted practitioners to ensure they get reviews
      const vanceId = practitionersData.find(p => p.email === 'elena.vance.pro@example.com')?.id;
      const silvaId = practitionersData.find(p => p.email === 'antonio.silva.master@example.com')?.id;
      const moonfeatherId = practitionersData.find(p => p.email === 'sarah.moonfeather.phd@example.com')?.id;
      const santosId = practitionersData.find(p => p.email === 'maria.santos.curandera@example.com')?.id;
      const riverwindId = practitionersData.find(p => p.email === 'james.riverwind.master@example.com')?.id;


      // Ensure essential fields have defaults and assign appropriate listing tiers
      const practitionersWithDetails = practitionersData.map(p => {
        if (!p.address) {
          p.address = {};
        }

        // Assign listing tier based on verification status and experience if not already set
        if (!p.listing_tier && p.is_verified) {
          // For demo purposes, give verified practitioners premium tier
          // In production, this would be based on their subscription/payment
          if (p.years_experience >= 8) {
            p.listing_tier = 'premium';
          } else if (p.years_experience >= 3) {
            p.listing_tier = 'featured';
          } else {
            p.listing_tier = 'verified';
          }
        } else if (!p.listing_tier) {
          p.listing_tier = 'verified'; // Default to 'verified' if no tier and not explicitly verified
        }

        return p;
      });

      const mockReviews = [
        // FIX: Add 5-star reviews for all spotlighted practitioners
        { id: 'rev_vance1', practitioner_id: vanceId, rating: 5, comment: 'Dr. Vance is a true master. Her approach is both profoundly spiritual and psychologically sound. Life-changing.', created_date: '2024-03-01T10:00:00Z', reviewer_name: 'Sophia R.' },
        { id: 'rev_vance2', practitioner_id: vanceId, rating: 5, comment: 'The safest I have ever felt in a ceremony. The integration support was invaluable.', created_date: '2024-03-05T11:00:00Z', reviewer_name: 'Michael B.' },

        { id: 'rev_silva1', practitioner_id: silvaId, rating: 5, comment: 'An authentic and powerful experience. Chief Silva carries the spirit of the medicine with immense integrity.', created_date: '2024-03-10T12:00:00Z', reviewer_name: 'David L.' },
        { id: 'rev_silva2', practitioner_id: silvaId, rating: 5, comment: 'Truly traditional. It was an honor to sit with a lineage holder of this caliber.', created_date: '2024-03-15T13:00:00Z', reviewer_name: 'Jennifer S.' },

        { id: 'rev_moonfeather1', practitioner_id: moonfeatherId, rating: 5, comment: 'The blend of deep psychological insight and sacred ceremony is unparalleled. Highly recommended for anyone with trauma.', created_date: '2024-03-20T14:00:00Z', reviewer_name: 'Anonymous' },
        { id: 'rev_moonfeather2', practitioner_id: moonfeatherId, rating: 5, comment: 'Dr. Moonfeather helped me understand my experience in a way no one else could. The integration was key.', created_date: '2024-03-25T15:00:00Z', reviewer_name: 'Emily P.' },

        { id: 'rev_santos1', practitioner_id: santosId, rating: 5, comment: 'Grandmother Maria is a treasure. Her wisdom and the love she pours into her work is palpable.', created_date: '2024-04-01T16:00:00Z', reviewer_name: 'Maria G.' },
        { id: 'rev_santos2', practitioner_id: santosId, rating: 5, comment: 'A deeply healing and nurturing ceremony. Her space in Taos is magical.', created_date: '2024-04-05T17:00:00Z', reviewer_name: 'Chloe W.' },

        { id: 'rev_riverwind1', practitioner_id: riverwindId, rating: 5, comment: 'James has a profound gift for holding space. The breathwork integration took the healing to another level.', created_date: '2024-04-10T18:00:00Z', reviewer_name: 'Ben C.' },
        { id: 'rev_riverwind2', practitioner_id: riverwindId, rating: 5, comment: 'If you struggle with addiction, this is the man to see. His compassion and strength are a guiding light.', created_date: '2024-04-15T19:00:00Z', reviewer_name: 'Anonymous' },

        // Original Mock Reviews
        { id: 'rev1', practitioner_id: practitionerIds[0], rating: 5, comment: 'An incredibly insightful and healing experience. This practitioner created such a safe and supportive space.', created_date: '2023-01-15T10:00:00Z', reviewer_name: 'Alex' },
        { id: 'rev2', practitioner_id: practitionerIds[0], rating: 4, comment: 'Very professional and knowledgeable. I felt a significant shift. Would recommend!', created_date: '2023-02-20T11:00:00Z', reviewer_name: 'Sarah' },
        { id: 'rev3', practitioner_id: practitionerIds[0], rating: 5, comment: 'Life-changing! This practitioner guided me with such grace and wisdom. Truly grateful.', created_date: '2023-03-01T12:00:00Z', reviewer_name: 'Michael' },

        { id: 'rev4', practitioner_id: practitionerIds[1], rating: 5, comment: 'This practitioner is a true master. The session was profound and exactly what I needed.', created_date: '2023-04-05T13:00:00Z', reviewer_name: 'Jessica' },
        { id: 'rev5', practitioner_id: practitionerIds[1], rating: 3, comment: 'The session was intense, and while I felt some benefits, the aftercare guidance could be clearer.', created_date: '2023-05-10T14:00:00Z', reviewer_name: 'David' },

        { id: 'rev6', practitioner_id: practitionerIds[2], rating: 4, comment: 'Good experience overall. This practitioner was attentive and explained everything well.', created_date: '2023-06-15T15:00:00Z', reviewer_name: 'Emily' },
        { id: 'rev7', practitioner_id: practitionerIds[2], rating: 5, comment: 'Highly professional and deeply caring. Felt very safe throughout the process.', created_date: '2023-07-20T16:00:00Z', reviewer_name: 'Chris' },

        { id: 'rev8', practitioner_id: practitionerIds[3], rating: 2, comment: 'The session felt rushed, and I didn\'t feel a strong connection. Hope for better next time.', created_date: '2023-08-25T17:00:00Z', reviewer_name: 'Laura' },

        { id: 'rev9', practitioner_id: practitionerIds[4], rating: 5, comment: 'An exceptional practitioner! Helped me achieve a level of clarity I hadn\'t known before.', created_date: '2023-09-30T18:00:00Z', reviewer_name: 'Ryan' },
        { id: 'rev10', practitioner_id: practitionerIds[4], rating: 5, comment: 'Beyond amazing. The most powerful Kambo session I\'ve had. Truly gifted.', created_date: '2023-10-05T19:00:00Z', reviewer_name: 'Megan' },
        { id: 'rev11', practitioner_id: practitionerIds[4], rating: 4, comment: 'Solid and very effective. Would book again for deep cleansing.', created_date: '2023-11-10T20:00:00Z', reviewer_name: 'Jason' },

        { id: 'rev12', practitioner_id: practitionerIds[5], rating: 4, comment: 'Provided a calming presence. I felt very supported through the process.', created_date: '2023-12-15T21:00:00Z', reviewer_name: 'Nicole' },
        { id: 'rev13', practitioner_id: practitionerIds[5], rating: 5, comment: 'Wonderful experience. Very attentive to my needs.', created_date: '2024-01-01T09:00:00Z', reviewer_name: 'Daniel' },

        { id: 'rev14', practitioner_id: practitionerIds[6], rating: 3, comment: 'The space was nice, but the overall experience was just okay. Nothing particularly stood out.', created_date: '2024-01-20T10:00:00Z', reviewer_name: 'Olivia' },

        { id: 'rev15', practitioner_id: practitionerIds[7], rating: 1, comment: 'Unfortunately, this was not a positive experience for me. I did not feel comfortable or supported.', created_date: '2024-02-05T11:00:00Z', reviewer_name: 'Andrew' },
        { id: 'rev16', practitioner_id: practitionerIds[7], rating: 2, comment: 'I had high hopes but left feeling somewhat disappointed. Communication prior to the session was unclear.', created_date: '2024-02-15T12:00:00Z', reviewer_name: 'Sophia' },
      ].filter(review => review.practitioner_id); // Filter out reviews if IDs don't exist

      setPractitioners(practitionersWithDetails);
      setReviews(mockReviews);
      console.log("Data loaded successfully");
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
    }
  };

  const filterPractitioners = useCallback(() => {
    let filtered = practitioners.filter(practitioner => {
      // Text search
      const lowerCaseSearchTerm = searchTerm.toLowerCase();
      const matchesSearch = !searchTerm ||
        practitioner.full_name?.toLowerCase().includes(lowerCaseSearchTerm) ||
        practitioner.address?.city?.toLowerCase().includes(lowerCaseSearchTerm) ||
        practitioner.address?.state_province?.toLowerCase().includes(lowerCaseSearchTerm) ||
        practitioner.address?.country?.toLowerCase().includes(lowerCaseSearchTerm);

      // Rating filter
      const practitionerRating = getAverageRating(practitioner.id);
      const matchesRating = filters.minRating === 0 || practitionerRating >= filters.minRating;

      // Price range filter
      const priceRangeMap = { "$": 0, "$$": 1, "$$$": 2, "$$$$": 3 };
      const practitionerPrice = practitioner.pricing_range ? (priceRangeMap[practitioner.pricing_range] || 0) : 0;
      const matchesPrice = practitionerPrice >= filters.priceRange[0] && filters.priceRange[1] >= practitionerPrice;

      // Verification filter
      let matchesVerification = true;
      if (filters.verificationLevel === "verified") {
        matchesVerification = practitioner.is_verified;
      } else if (filters.verificationLevel === "advanced") {
        matchesVerification = practitioner.is_verified && practitioner.verification_level === "advanced";
      } else if (filters.verificationLevel === "master") {
        matchesVerification = practitioner.is_verified && practitioner.verification_level === "master";
      }

      return matchesSearch && matchesRating && matchesPrice && matchesVerification;
    });

    // Apply sorting
    switch (filters.sortBy) {
      case "nearest":
        if (userLocation) {
          filtered = sortByDistance(
            filtered, 
            userLocation, 
            (practitioner) => practitioner.latitude && practitioner.longitude ? {
              latitude: practitioner.latitude,
              longitude: practitioner.longitude
            } : null
          );
        }
        break;
      case "rating":
        filtered.sort((a, b) => getAverageRating(b.id) - getAverageRating(a.id));
        break;
      case "experience":
        filtered.sort((a, b) => (b.years_experience || 0) - (a.years_experience || 0));
        break;
      case "newest":
        filtered.sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
        break;
    }

    setFilteredPractitioners(filtered);
  }, [searchTerm, practitioners, filters, getAverageRating, userLocation]);

  useEffect(() => {
    loadData();
  }, []);

  useEffect(() => {
    filterPractitioners();
  }, [searchTerm, practitioners, filters, filterPractitioners]);

  const handleRefresh = async () => {
    console.log("Refresh button clicked");
    setIsRefreshing(true);
    await loadData();
  };

  const handleSubmitReview = async (reviewData) => {
    // For mock data, we might just append it or reload the mock reviews
    // In a real app, this would hit the backend and then reload reviews from backend
    await Review.create(reviewData); // Still call the API if it exists, but then reload mock for consistent state
    const newReview = { 
        ...reviewData, 
        id: `mock_rev_${Date.now()}`, // Generate a unique ID for mock review
        created_date: new Date().toISOString()
    };
    setReviews(prevReviews => [...prevReviews, newReview]);
  };

  const handleRequestBooking = (practitioner) => {
    if (!practitioner) return;
    navigate(createPageUrl(`BookingRequest?practitionerId=${practitioner.id}`));
    setSelectedPractitioner(null); // Close the modal
  };

  const handleApplyFilters = (newFilters) => {
    setFilters(newFilters);
  };

  const handleMapPractitionersUpdate = (practitioners) => {
    // This function can be used if we want the map to filter the main list,
    // but for now we'll keep them separate.
    console.log("Practitioners in map view:", practitioners.length);
  };

  // Updated handler for clicking a practitioner to open the modal
  const handlePractitionerClick = (practitioner, fromMap = false) => {
    setSelectedPractitioner(practitioner);
    // If opened from map, switch back to list view for better UX
    if (fromMap) {
      setViewMode("list");
    }
  };

  // Updated categorization logic for 5 sections
  const spotlightedPractitioners = filteredPractitioners
    .filter(p => p.is_verified && p.listing_tier === 'premium' && getAverageRating(p.id) >= 4.0 && (p.years_experience >= 5))
    .sort((a, b) => (b.years_experience || 0) - (a.years_experience || 0));

  const recommendedPractitioners = filteredPractitioners
    .filter(p => p.is_verified && (p.listing_tier === 'premium' || p.listing_tier === 'featured') && getAverageRating(p.id) >= 3.5 && !spotlightedPractitioners.some(spotP => spotP.id === p.id))
    .sort((a, b) => getAverageRating(b.id) - getAverageRating(a.id));

  const featuredPractitioners = filteredPractitioners
    .filter(p => p.is_verified && p.listing_tier === 'featured' && !spotlightedPractitioners.some(spotP => spotP.id === p.id) && !recommendedPractitioners.some(recP => recP.id === p.id))
    .sort((a, b) => getAverageRating(b.id) - getAverageRating(a.id));

  const vettedPractitioners = filteredPractitioners
    .filter(p => p.is_verified && (p.listing_tier === 'verified' || !p.listing_tier) && 
      !spotlightedPractitioners.some(spotP => spotP.id === p.id) && 
      !recommendedPractitioners.some(recP => recP.id === p.id) && 
      !featuredPractitioners.some(featP => featP.id === p.id))
    .sort((a, b) => (b.years_experience || 0) - (a.years_experience || 0));

  // Fixed: Ensure unvetted practitioners are those who are NOT verified
  const unvettedPractitioners = filteredPractitioners
    .filter(p => !p.is_verified)
    .sort((a, b) => new Date(b.created_date) - new Date(a.created_date));

  return (
    <div className="bg-gray-50 min-h-screen">
      {/* Hero Section */}
      <div className="relative h-96 bg-gradient-to-br from-emerald-50 via-white to-teal-50 flex flex-col items-center justify-center text-center p-6 overflow-hidden">
         <div className="absolute inset-0 bg-gradient-to-br from-emerald-900/5 via-transparent to-teal-900/5"></div>
         <div className="absolute inset-0 bg-cover bg-center opacity-10" style={{backgroundImage: "url('https://images.unsplash.com/photo-1441974231531-c6227db76b6e?q=80&w=2071&auto=format&fit=crop')"}}></div>
        <motion.h1 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7 }}
          className="text-4xl sm:text-5xl font-bold text-gray-900 mb-4 z-10"
        >
          Connect with Trusted Practitioners
        </motion.h1>
        <motion.p 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7, delay: 0.2 }}
          className="text-lg text-gray-600 mb-4 max-w-lg z-10"
        >
          Find verified Kambo practitioners in your area
        </motion.p>

        {/* Location Status */}
        {filters.sortBy === "nearest" && (
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.3 }}
            className="mb-4 z-10"
          >
            {isGettingLocation ? (
              <p className="text-sm text-gray-500 flex items-center gap-2"><Loader2 className="w-4 h-4 animate-spin" /> Getting your location...</p>
            ) : userLocation ? (
              <p className="text-sm text-green-600">✓ Location detected - showing nearest practitioners</p>
            ) : locationError ? (
              <p className="text-sm text-orange-600">⚠ Location unavailable - showing all practitioners</p>
            ) : null}
          </motion.div>
        )}

        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.7, delay: 0.4 }}
          className="w-full max-w-lg z-10"
        >
          <div className="relative">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
            <Input
              placeholder="Search by name, location, or specialty..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-12 pr-14 py-4 h-14 text-base rounded-2xl shadow-sm border-0 bg-white/80 backdrop-blur-sm focus:bg-white transition-all"
            />
            <Button 
              variant="ghost" 
              size="sm" 
              className="absolute right-2 top-1/2 transform -translate-y-1/2 hover:bg-gray-100 rounded-xl w-10 h-10"
              onClick={() => setShowFilterModal(true)}
            >
              <SlidersHorizontal className="w-5 h-5 text-gray-500" />
            </Button>
          </div>
        </motion.div>
      </div>

      {/* Daily Quote Section */}
      <DailyQuote />

      {/* Main Content Area */}
      <div className="p-4 sm:p-6">
        <div className="max-w-6xl mx-auto">
          {viewMode === 'list' ? (
            <div className="space-y-12">
              {/* Spotlighted Practitioners */}
              {spotlightedPractitioners.length > 0 && (
                <section>
                  <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-6 gap-4">
                    <div className="flex-1">
                      <h2 className="text-2xl font-bold text-gray-900">Spotlighted Practitioners</h2>
                      <p className="text-gray-600">Elite practitioners with exceptional expertise and perfect ratings</p>
                    </div>
                    <div className="flex items-center gap-2 w-full sm:w-auto">
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={handleRefresh}
                        disabled={isRefreshing}
                        className="flex items-center gap-2 flex-1 sm:flex-none"
                      >
                        <RefreshCw className={`w-4 h-4 ${isRefreshing ? 'animate-spin' : ''}`} />
                        {isRefreshing ? 'Refreshing...' : 'Refresh'}
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setViewMode('map')}
                        className="flex items-center gap-2 flex-1 sm:flex-none"
                      >
                        <MapPin className="w-4 h-4" />
                        Map View
                      </Button>
                    </div>
                  </div>

                  <div className="flex gap-6 overflow-x-auto pb-4">
                      {spotlightedPractitioners.map(practitioner => (
                        <PractitionerCard 
                          key={practitioner.id}
                          practitioner={practitioner}
                          averageRating={getAverageRating(practitioner.id)}
                          reviewCount={getPractitionerReviews(practitioner.id).length}
                          onClick={() => handlePractitionerClick(practitioner)}
                          size="large"
                        />
                      ))}
                  </div>
                </section>
              )}

              {/* Recommended Practitioners */}
              {recommendedPractitioners.length > 0 && (
                <section className="pt-8 border-t border-gray-200">
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">Recommended Practitioners</h2>
                  <p className="text-gray-600 mb-6">Premium verified practitioners with excellent ratings</p>

                  {isLoading ? (
                     <div className="flex gap-4 overflow-x-auto pb-4">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className="w-48 h-60 bg-gray-200 rounded-2xl animate-pulse flex-shrink-0"></div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {recommendedPractitioners.map(practitioner => (
                        <PractitionerCard 
                            key={practitioner.id}
                            practitioner={practitioner}
                            averageRating={getAverageRating(practitioner.id)}
                            reviewCount={getPractitionerReviews(practitioner.id).length}
                            onClick={() => handlePractitionerClick(practitioner)}
                            size="medium"
                        />
                        ))}
                    </div>
                  )}
                </section>
              )}

              {/* Featured Practitioners */}
              {featuredPractitioners.length > 0 && (
                <section className="pt-8 border-t border-gray-200">
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">Featured Practitioners</h2>
                  <p className="text-gray-600 mb-6">Verified practitioners with enhanced profiles</p>

                  {isLoading ? (
                     <div className="flex gap-4 overflow-x-auto pb-4">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className="w-48 h-60 bg-gray-200 rounded-2xl animate-pulse flex-shrink-0"></div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {featuredPractitioners.map(practitioner => (
                        <PractitionerCard 
                            key={practitioner.id}
                            practitioner={practitioner}
                            averageRating={getAverageRating(practitioner.id)}
                            reviewCount={getPractitionerReviews(practitioner.id).length}
                            onClick={() => handlePractitionerClick(practitioner)}
                            size="medium"
                        />
                        ))}
                    </div>
                  )}
                </section>
              )}

              {/* Vetted Practitioners */}
              {vettedPractitioners.length > 0 && (
                <section className="pt-8 border-t border-gray-200">
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">Vetted Practitioners</h2>
                  <p className="text-gray-600 mb-6">Verified practitioners who have met our safety standards</p>

                  {isLoading ? (
                     <div className="flex gap-4 overflow-x-auto pb-4">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className="w-48 h-60 bg-gray-200 rounded-2xl animate-pulse flex-shrink-0"></div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {vettedPractitioners.map(practitioner => (
                            <PractitionerCard 
                            key={practitioner.id}
                            practitioner={practitioner}
                            averageRating={getAverageRating(practitioner.id)}
                            reviewCount={getPractitionerReviews(practitioner.id).length}
                            onClick={() => handlePractitionerClick(practitioner)}
                            size="medium"
                            />
                        ))}
                    </div>
                  )}
                </section>
              )}

              {/* Unvetted Practitioners */}
              {unvettedPractitioners.length > 0 && (
                <section className="pt-8 border-t border-gray-200">
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">Unvetted Practitioners</h2>
                  <p className="text-gray-600 mb-6">New practitioners awaiting verification - exercise extra caution</p>

                  {isLoading ? (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {[...Array(3)].map((_, i) => (
                            <div key={i} className="w-48 h-60 bg-gray-200 rounded-2xl animate-pulse flex-shrink-0"></div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex gap-4 overflow-x-auto pb-4">
                        {unvettedPractitioners.map(practitioner => (
                            <PractitionerCard 
                            key={practitioner.id}
                            practitioner={practitioner}
                            averageRating={getAverageRating(practitioner.id)}
                            reviewCount={getPractitionerReviews(practitioner.id).length}
                            onClick={() => handlePractitionerClick(practitioner)}
                            size="medium"
                            />
                        ))}
                    </div>
                  )}
                </section>
              )}

              {/* Overall No Results Message */}
              {!isLoading && filteredPractitioners.length === 0 && (
                    <div className="text-center py-16">
                        <Search className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                        <h3 className="text-lg font-semibold text-gray-800 mb-2">No practitioners found</h3>
                        <p className="text-gray-500">Try adjusting your search terms or filters.</p>
                    </div>
              )}
            </div>
          ) : (
            <MapView 
              practitioners={filteredPractitioners}
              onPractitionerSelect={(practitioner) => handlePractitionerClick(practitioner, true)}
              onMapPractitionersUpdate={handleMapPractitionersUpdate}
            />
          )}
        </div>
      </div>

      {/* Practitioner Detail Modal */}
      <AnimatePresence>
        {selectedPractitioner && (
            <PractitionerModal
            key={selectedPractitioner.id}
            practitioner={selectedPractitioner}
            reviews={getPractitionerReviews(selectedPractitioner.id)}
            averageRating={getAverageRating(selectedPractitioner.id)}
            onClose={() => setSelectedPractitioner(null)}
            onSubmitReview={handleSubmitReview}
            onRequestBooking={() => handleRequestBooking(selectedPractitioner)}
            />
        )}
      </AnimatePresence>

      {/* Filter Modal */}
      <FilterModal
        isOpen={showFilterModal}
        onClose={() => setShowFilterModal(false)}
        onApplyFilters={handleApplyFilters}
        currentFilters={filters}
      />
    </div>
  );
}

pages.Verification:
import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { User, Practitioner, Notification } from "@/entities/all";
import { SendEmail } from "@/integrations/Core";
import { createPageUrl } from "@/utils";
import {
  ShieldCheck, AlertCircle, Loader2, User as UserIcon, Check, X, ExternalLink, ArrowLeft
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";

const DetailSection = ({ title, children }) => (
  <div>
    <h3 className="text-sm font-semibold uppercase text-gray-500 tracking-wider mb-2">{title}</h3>
    <div className="p-4 bg-gray-50 rounded-lg text-gray-700 leading-relaxed text-sm">
      {children || <span className="italic text-gray-400">Not provided</span>}
    </div>
  </div>
);

const ApplicationDetails = ({ application, onApprove, onReject, onBack }) => {
  const [rejectionReason, setRejectionReason] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);

  const handleReject = async () => {
    if (!rejectionReason.trim()) {
      alert("Please provide a reason for rejection.");
      return;
    }
    setIsProcessing(true);
    await onReject(application.id, rejectionReason);
    setIsProcessing(false);
  };

  const handleApprove = async () => {
    setIsProcessing(true);
    await onApprove(application.id);
    setIsProcessing(false);
  };

  return (
    <Card className="shadow-lg">
      <CardHeader>
        <div className="flex justify-between items-start">
          <div>
            <Button variant="ghost" onClick={onBack} className="mb-4 text-gray-600">
              <ArrowLeft className="w-4 h-4 mr-2" /> Back to List
            </Button>
            <CardTitle className="text-2xl">{application.full_name}</CardTitle>
            <CardDescription>{application.email}</CardDescription>
          </div>
          <div className="text-right">
            <Badge variant="secondary">Pending Verification</Badge>
            <p className="text-sm text-gray-500 mt-1">Applied: {new Date(application.created_date).toLocaleDateString()}</p>
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-6">
        <div className="grid md:grid-cols-2 gap-6">
          <DetailSection title="Professional Bio">{application.bio}</DetailSection>
          <DetailSection title="Why They Practice Kambo">{application.why_practitioner}</DetailSection>
        </div>
        <DetailSection title="Training Background">{application.training_background}</DetailSection>
        <DetailSection title="Safety Protocols & Procedures">{application.safety_protocols}</DetailSection>

        <Separator />

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          <DetailSection title="Years of Experience">{application.years_experience} years</DetailSection>
          <DetailSection title="Pricing Range">{application.pricing_range}</DetailSection>
          <DetailSection title="Website">
            {application.website_url ? <a href={application.website_url} target="_blank" rel="noopener noreferrer" className="text-emerald-600 hover:underline">{application.website_url}</a> : "Not provided"}
          </DetailSection>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
            <DetailSection title="Specializations">
                <div className="flex flex-wrap gap-2">{application.specializations?.map(s => <Badge key={s}>{s}</Badge>)}</div>
            </DetailSection>
            <DetailSection title="Languages">
                <div className="flex flex-wrap gap-2">{application.languages?.map(l => <Badge key={l} variant="outline">{l}</Badge>)}</div>
            </DetailSection>
        </div>

        <Separator />

        <h3 className="font-semibold text-lg mb-4">Documents</h3>
        <div className="grid md:grid-cols-2 gap-4">
            <a href={application.cpr_certification_url} target="_blank" rel="noopener noreferrer" className="block">
                <Button variant="outline" className="w-full justify-between">
                    View CPR Certification <ExternalLink className="w-4 h-4"/>
                </Button>
            </a>
            <a href={application.kambo_certification_url} target="_blank" rel="noopener noreferrer" className="block">
                <Button variant="outline" className="w-full justify-between">
                    View Kambo Certification <ExternalLink className="w-4 h-4"/>
                </Button>
            </a>
        </div>
        <p className="text-sm text-gray-500">CPR Expiration: {application.cpr_expiration_date}</p>

        <Separator />

        <div className="space-y-4 pt-4">
          <h3 className="font-semibold text-lg">Admin Actions</h3>
          <div>
            <Label htmlFor="rejectionReason">Rejection Reason (Required if rejecting)</Label>
            <Textarea 
              id="rejectionReason"
              value={rejectionReason}
              onChange={(e) => setRejectionReason(e.target.value)}
              placeholder="Provide clear feedback for the applicant..."
              className="mt-1"
            />
          </div>
          <div className="flex justify-end gap-4">
            <Button variant="destructive" onClick={handleReject} disabled={isProcessing || !rejectionReason.trim()}>
              {isProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2"/> : <X className="w-4 h-4 mr-2"/>} Reject Application
            </Button>
            <Button onClick={handleApprove} disabled={isProcessing} className="bg-emerald-600 hover:bg-emerald-700">
               {isProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2"/> : <Check className="w-4 h-4 mr-2"/>} Approve Application
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

export default function VerificationPage() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [pending, setPending] = useState([]);
  const [selectedApplication, setSelectedApplication] = useState(null);

  const loadData = useCallback(async () => {
    setIsLoading(true);
    try {
      const currentUser = await User.me();
      if (currentUser.role !== 'admin') {
        setUser(null);
        navigate(createPageUrl("Directory"));
        return;
      }
      setUser(currentUser);
      const pendingApps = await Practitioner.filter({ verification_level: "pending" });
      setPending(pendingApps);
    } catch (e) {
      setUser(null);
      navigate(createPageUrl("Directory"));
    } finally {
      setIsLoading(false);
    }
  }, [navigate]); // navigate is stable and won't cause infinite re-renders

  useEffect(() => {
    loadData();
  }, [loadData]); // loadData is now memoized by useCallback

  const handleApprove = async (id) => {
    const application = pending.find(p => p.id === id);
    if (!application) return;

    await Practitioner.update(id, { is_verified: true, verification_level: "basic" });

    await SendEmail({
        to: application.email,
        subject: "Your KamboConnect Application has been Approved!",
        body: `<h1>Congratulations, ${application.full_name}!</h1><p>We are pleased to inform you that your application to become a practitioner on KamboConnect has been approved. Your profile is now live and visible in our directory.</p><p>Welcome to the community!</p><p>The KamboConnect Team</p>`
    });

    await Notification.create({
        user_id: application.id, // Assuming practitioner user id is the same as the record id for now
        title: "Application Approved!",
        message: "Congratulations! Your practitioner profile is now live.",
        type: "system",
        priority: "high",
        action_url: createPageUrl("PractitionerDashboard")
    });

    setSelectedApplication(null);
    loadData(); // Refresh list
  };

  const handleReject = async (id, reason) => {
    const application = pending.find(p => p.id === id);
    if (!application) return;

    await Practitioner.update(id, { verification_level: "rejected", rejection_reason: reason });

    await SendEmail({
        to: application.email,
        subject: "Update on your KamboConnect Application",
        body: `<h1>Update on Your KamboConnect Application</h1><p>Hello ${application.full_name},</p><p>Thank you for your interest in becoming a practitioner on KamboConnect. After reviewing your application, we are unable to approve it at this time.</p><p><strong>Reason:</strong> ${reason}</p><p>We invite you to address these points and re-apply in the future if you wish.</p><p>Sincerely,<br/>The KamboConnect Team</p>`
    });

    setSelectedApplication(null);
    loadData(); // Refresh list
  };

  if (isLoading) {
    return <div className="flex items-center justify-center h-screen"><Loader2 className="w-10 h-10 text-gray-400 animate-spin" /></div>;
  }

  if (!user) {
    return (
      <div className="flex flex-col items-center justify-center h-screen text-center p-6 bg-red-50 text-red-700">
        <AlertCircle className="w-16 h-16 mb-4" />
        <h1 className="text-3xl font-bold">Access Denied</h1>
        <p>You must be an administrator to view this page.</p>
      </div>
    );
  }

  if (selectedApplication) {
    return (
      <div className="p-4 sm:p-6">
        <ApplicationDetails 
          application={selectedApplication} 
          onApprove={handleApprove} 
          onReject={handleReject}
          onBack={() => setSelectedApplication(null)}
        />
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-2xl">
            <ShieldCheck className="w-7 h-7 text-emerald-600" />
            Practitioner Verification
          </CardTitle>
          <CardDescription>Review and approve pending practitioner applications.</CardDescription>
        </CardHeader>
        <CardContent>
          {pending.length > 0 ? (
            <div className="space-y-4">
              {pending.map(app => (
                <div 
                  key={app.id} 
                  className="flex items-center justify-between p-4 border rounded-lg hover:bg-gray-50 cursor-pointer transition-colors"
                  onClick={() => setSelectedApplication(app)}
                >
                  <div className="flex items-center gap-4">
                    <UserIcon className="w-6 h-6 text-gray-500" />
                    <div>
                      <p className="font-semibold text-gray-800">{app.full_name}</p>
                      <p className="text-sm text-gray-500">{app.email}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-gray-500">Applied on</p>
                    <p className="font-medium">{new Date(app.created_date).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-12 text-gray-500">
              <ShieldCheck className="w-12 h-12 mx-auto mb-4 text-gray-400" />
              <p className="font-semibold">No pending applications.</p>
              <p>All applications have been reviewed.</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

