pages.NewPost:
import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { User } from "@/entities/User";
import { Post } from "@/entities/Post";
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css';

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ArrowLeft, Send } from "lucide-react";

export default function NewPost() {
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("General Discussion");
  const [user, setUser] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
      } catch (error) {
        // Not logged in, redirect or handle
        navigate(createPageUrl("Community"));
      }
    };
    fetchUser();
  }, [navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title.trim() || !content.trim() || !user) return;

    setIsSubmitting(true);
    try {
      const newPost = await Post.create({
        title,
        content,
        category,
        author_id: user.id,
        author_name: user.full_name,
        last_reply_date: new Date().toISOString()
      });
      navigate(createPageUrl(`Post?id=${newPost.id}`));
    } catch (error) {
      console.error("Failed to create post:", error);
      // Handle error, e.g., show a toast message
    } finally {
      setIsSubmitting(false);
    }
  };

  const quillModules = {
    toolbar: [
      [{ 'header': [1, 2, false] }],
      ['bold', 'italic', 'underline','strike', 'blockquote'],
      [{'list': 'ordered'}, {'list': 'bullet'}],
      ['link'],
      ['clean']
    ],
  };

  return (
    <div className="bg-white min-h-screen p-4 sm:p-6">
      <div className="max-w-4xl mx-auto">
        <div className="mb-6">
          <Link to={createPageUrl("Community")} className="flex items-center gap-2 text-gray-600 hover:text-gray-900">
            <ArrowLeft className="w-4 h-4" />
            Back to Community
          </Link>
        </div>

        <Card>
          <CardHeader>
            <CardTitle className="text-2xl">Create a New Post</CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="sm:col-span-2">
                  <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                  <Input
                    id="title"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Enter a descriptive title"
                    required
                  />
                </div>
                <div>
                  <label htmlFor="category" className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                  <Select value={category} onValueChange={setCategory}>
                    <SelectTrigger id="category">
                      <SelectValue placeholder="Select a category" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="General Discussion">General Discussion</SelectItem>
                      <SelectItem value="Experience Sharing">Experience Sharing</SelectItem>
                      <SelectItem value="Q&A">Q&A</SelectItem>
                      <SelectItem value="Integration">Integration</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
                <div className="bg-white">
                   <ReactQuill 
                    theme="snow" 
                    value={content} 
                    onChange={setContent}
                    modules={quillModules}
                  />
                </div>
              </div>

              <div className="flex justify-end">
                <Button
                  type="submit"
                  disabled={isSubmitting || !title.trim() || content.trim() === "<p><br></p>" || !content.trim()}
                  className="bg-emerald-600 hover:bg-emerald-700"
                >
                  <Send className="w-4 h-4 mr-2" />
                  {isSubmitting ? "Posting..." : "Create Post"}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

pages.Post:
import React, { useState, useEffect, useCallback } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { Post, Reply, User, Notification } from "@/entities/all";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Textarea } from "@/components/ui/textarea";
import { ArrowLeft, Loader2, MessageSquare } from "lucide-react";
import { format } from "date-fns";
import 'react-quill/dist/quill.snow.css';

export default function PostPage() {
  const location = useLocation();
  const navigate = useNavigate();
  const [post, setPost] = useState(null);
  const [replies, setReplies] = useState([]);
  const [user, setUser] = useState(null);
  const [newReply, setNewReply] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false); // Changed from isReplying to isSubmitting

  const postId = new URLSearchParams(location.search).get("id");

  const loadData = useCallback(async () => {
    if (!postId) {
      navigate(createPageUrl("Community"));
      return;
    }
    setIsLoading(true);
    try {
      const [currentUser, postData, postReplies] = await Promise.all([
        User.me().catch(() => null),
        Post.get(postId),
        Reply.filter({ post_id: postId }, "created_date"),
      ]);
      setUser(currentUser);
      setPost(postData);
      setReplies(postReplies);
    } catch (error) {
      console.error("Failed to load post data:", error);
      navigate(createPageUrl("Community"));
    } finally {
      setIsLoading(false);
    }
  }, [postId, navigate]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const handleReplySubmit = async (e) => {
    e.preventDefault(); // Keep preventDefault for form submission
    if (!newReply.trim() || !user || !post) return; // Added !post check for safety
    setIsSubmitting(true); // Use isSubmitting
    try {
      const createdReply = await Reply.create({
        post_id: post.id, // Use post.id directly
        content: newReply,
        author_id: user.id,
        author_name: user.full_name,
      });

      // Update post's reply_count and last_reply_date
      await Post.update(post.id, {
        reply_count: (post.reply_count || 0) + 1,
        last_reply_date: new Date().toISOString(),
      });

      // Notify original post author
      if (user.id !== post.author_id) {
          await Notification.create({
              user_id: post.author_id,
              title: "New reply on your post", // Updated title
              message: `${user.full_name} replied to your post: "${post.title}"`, // Updated message
              type: 'community',
              related_id: post.id,
              action_url: createPageUrl(`Post?id=${post.id}`),
              sender_image_url: user.profile_image_url, // Changed from || null
          });
      }

      // Optimistically add the new reply to the list
      // Include author_profile_image_url for avatar rendering
      setReplies(prev => [...prev, { ...createdReply, author_profile_image_url: user.profile_image_url }]);
      setNewReply("");
      // loadData() is no longer needed here due to optimistic update
    } catch (error) {
      console.error("Failed to submit reply:", error);
    } finally {
      setIsSubmitting(false); // Use isSubmitting
    }
  };

  if (isLoading) {
    return (
      <div className="flex justify-center items-center min-h-[calc(100vh-150px)]">
        <Loader2 className="w-10 h-10 text-gray-400 animate-spin" />
      </div>
    );
  }

  if (!post) {
    return (
      <div className="p-6 text-center">
        <h2 className="text-2xl font-bold">Post not found</h2>
        <p className="text-gray-600">The post you're looking for doesn't exist.</p>
        <Button asChild className="mt-4">
          <Link to={createPageUrl("Community")}>Back to Community</Link>
        </Button>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-6 bg-gray-50 min-h-screen">
      <div className="max-w-4xl mx-auto">
        <div className="mb-4">
          <Button variant="ghost" asChild>
            <Link to={createPageUrl("Community")}>
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Community
            </Link>
          </Button>
        </div>

        <Card>
          <CardHeader>
            <CardTitle className="text-3xl">{post.title}</CardTitle>
            <div className="flex items-center gap-3 text-sm text-gray-500 mt-2">
              <Avatar className="h-8 w-8">
                <AvatarFallback>{post.author_name.charAt(0)}</AvatarFallback>
                {post.author_profile_image_url && (
                    <AvatarImage src={post.author_profile_image_url} alt={post.author_name} />
                )}
              </Avatar>
              <span>{post.author_name}</span>
              <span>•</span>
              <span>{format(new Date(post.created_date), "MMM d, yyyy")}</span>
            </div>
          </CardHeader>
          <CardContent>
            <div
              className="prose max-w-none"
              dangerouslySetInnerHTML={{ __html: post.content }}
            />
          </CardContent>
        </Card>

        <div className="mt-8">
          <h3 className="text-2xl font-bold mb-4">{replies.length} Replies</h3>
          <div className="space-y-6">
            {replies.map((reply) => (
              <Card key={reply.id} className="bg-white">
                <CardHeader className="flex flex-row items-start gap-4 space-y-0 p-4">
                   <Avatar className="h-10 w-10">
                    <AvatarFallback>{reply.author_name.charAt(0)}</AvatarFallback>
                    {reply.author_profile_image_url && (
                        <AvatarImage src={reply.author_profile_image_url} alt={reply.author_name} />
                    )}
                  </Avatar>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className="font-semibold">{reply.author_name}</span>
                      <span className="text-xs text-gray-500">
                        {format(new Date(reply.created_date), "MMM d, yyyy, p")}
                      </span>
                    </div>
                    <p className="text-gray-700 mt-1">{reply.content}</p>
                  </div>
                </CardHeader>
              </Card>
            ))}
          </div>
        </div>

        {user && (
          <Card className="mt-8">
            <CardHeader>
              <CardTitle>Leave a Reply</CardTitle>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleReplySubmit} className="space-y-4">
                <Textarea
                  value={newReply}
                  onChange={(e) => setNewReply(e.target.value)}
                  placeholder="Share your thoughts..."
                  rows={4}
                  required
                />
                <Button type="submit" disabled={isSubmitting}> {/* Use isSubmitting */}
                  {isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  Post Reply
                </Button>
              </form>
            </CardContent>
          </Card>
        )}
        {!user && (
            <div className="text-center mt-8 p-6 bg-gray-100 rounded-lg">
                <MessageSquare className="w-8 h-8 mx-auto text-gray-400 mb-2"/>
                <p className="font-semibold">Want to join the conversation?</p>
                <p className="text-sm text-gray-600 mb-4">You must be logged in to reply.</p>
                <Button onClick={() => User.login()}>Log In</Button>
            </div>
        )}
      </div>
    </div>
  );
}

pages.Bookings:
import React, { useState, useEffect } from "react";
import { User } from "@/entities/User";
import { Booking } from "@/entities/Booking";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Briefcase, CalendarCheck, User as UserIcon, LogIn } from "lucide-react";
import { Button } from "@/components/ui/button";
import ClientBookingsView from "../components/bookings/ClientBookingsView";
import PractitionerBookingsView from "../components/bookings/PractitionerBookingsView";

export default function BookingsPage() {
  const [user, setUser] = useState(null);
  const [clientBookings, setClientBookings] = useState([]);
  const [practitionerBookings, setPractitionerBookings] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const currentUser = await User.me();
      setUser(currentUser);

      if (currentUser) {
        try {
          // Fetch real data linked to the current user
          const [realClientData, realPractitionerData] = await Promise.all([
            Booking.filter({ client_id: currentUser.id }, "-created_date"),
            Booking.filter({ practitioner_id: currentUser.id }, "-created_date")
          ]);

          // Fallback to mock data for clients if no real data exists
          if (realClientData.length > 0) {
              setClientBookings(realClientData);
          } else {
              const mockClientData = await Booking.filter({ client_id: "current_user_id" }, "-created_date");
              setClientBookings(mockClientData);
          }

          // Fallback to mock data for practitioners if no real data exists
          if (realPractitionerData.length > 0) {
              setPractitionerBookings(realPractitionerData);
          } else {
              const mockPractitionerData = await Booking.filter({ practitioner_id: "current_user_id" }, "-created_date");
              setPractitionerBookings(mockPractitionerData);
          }
        } catch (bookingError) {
          // If booking fetch fails, just set empty arrays
          console.log("No booking data found for user or failed to fetch, using empty state:", bookingError);
          setClientBookings([]);
          setPractitionerBookings([]);
        }
      } else {
        // If currentUser is null after User.me() (e.g., not logged in), clear bookings
        setClientBookings([]);
        setPractitionerBookings([]);
      }
    } catch (authError) {
      // User is not logged in or User.me() failed - this is expected if unauthenticated
      console.log("User not authenticated or failed to fetch user, showing login prompt:", authError);
      setUser(null);
      setClientBookings([]);
      setPractitionerBookings([]);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleBookingUpdate = () => {
    // Reload all data after any booking status change, but debounce it
    setTimeout(() => {
      loadData();
    }, 500); // Add small delay to prevent rapid successive calls
  };

  if (isLoading) {
    return (
        <div className="p-6">
            <div className="h-8 w-1/3 bg-gray-200 rounded animate-pulse mb-2"></div>
            <div className="h-6 w-1/2 bg-gray-200 rounded animate-pulse mb-6"></div>
            <div className="w-full h-96 bg-gray-100 rounded-lg animate-pulse"></div>
        </div>
    );
  }

  if (!user) {
     return (
        <div className="flex flex-col items-center justify-center min-h-[calc(100vh-150px)] text-center p-6 bg-gray-50">
          <UserIcon className="w-16 h-16 text-gray-300 mb-4" />
          <h1 className="text-2xl font-bold text-gray-800 mb-2">Please Log In</h1>
          <p className="text-gray-500 max-w-md mb-6">
            You need to be logged in to view your bookings or manage your practice.
          </p>
          <Button onClick={() => User.login()} className="bg-emerald-600 hover:bg-emerald-700">
            <LogIn className="w-4 h-4 mr-2" />
            Log In
          </Button>
        </div>
      );
  }

  // Determine if the user has practitioner bookings to enable the "My Practice" tab
  // The original code used `practitionerBookings.length > 0`. 
  // It's more accurate to check if the user is *intended* to be a practitioner
  // or if practitioner bookings were successfully loaded.
  // For simplicity, sticking to the existing check, but noting this could be improved if `User` entity had a `is_practitioner` flag.
  const isPractitioner = practitionerBookings.length > 0; 

  return (
    <div className="p-4 sm:p-6">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">My Bookings</h1>
      <p className="text-gray-600 mb-6">Track your sessions and manage booking requests.</p>

      <Tabs defaultValue="my-sessions" className="w-full">
        <TabsList className="grid w-full grid-cols-2 bg-gray-100">
          <TabsTrigger value="my-sessions">
            <CalendarCheck className="w-4 h-4 mr-2" />
            My Sessions
          </TabsTrigger>
          <TabsTrigger value="my-practice" disabled={!isPractitioner}>
            <Briefcase className="w-4 h-4 mr-2" />
            My Practice
          </TabsTrigger>
        </TabsList>
        <TabsContent value="my-sessions" className="py-6">
            <ClientBookingsView bookings={clientBookings} onUpdate={handleBookingUpdate} />
        </TabsContent>
        <TabsContent value="my-practice" className="py-6">
            <PractitionerBookingsView bookings={practitionerBookings} onUpdate={handleBookingUpdate} />
        </TabsContent>
      </Tabs>
    </div>
  );
}

