import React, { useState, useEffect, useCallback } from "react";
import { useLocation } from "react-router-dom";
import { User, Conversation, Message, Practitioner } from "@/entities/all";
import { Button } from "@/components/ui/button";
import { Loader2, User as UserIcon, MessageSquarePlus } from "lucide-react";
import ConversationList from "../components/messages/ConversationList";
import MessageThread from "../components/messages/MessageThread";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { NotificationService } from "../components/notifications/NotificationService";

const NewConversationModal = ({ open, onOpenChange, practitioners, onSelect }) => {
  const [searchTerm, setSearchTerm] = useState("");
  const filteredPractitioners = practitioners.filter(p => p.full_name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Start a New Conversation</DialogTitle>
          <DialogDescription>Select a practitioner to message.</DialogDescription>
        </DialogHeader>
        <Input 
          placeholder="Search practitioners..." 
          value={searchTerm} 
          onChange={(e) => setSearchTerm(e.target.value)}
          className="my-4"
        />
        <ScrollArea className="h-72">
          <div className="space-y-2">
            {filteredPractitioners.map(p => (
              <div 
                key={p.id} 
                onClick={() => onSelect(p.id, p.full_name)}
                className="flex items-center gap-3 p-3 rounded-lg hover:bg-gray-100 cursor-pointer"
              >
                <UserIcon className="w-5 h-5 text-gray-500"/>
                <span className="font-medium">{p.full_name}</span>
              </div>
            ))}
          </div>
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
};

export default function Messages() {
  const location = useLocation();
  const [user, setUser] = useState(null);
  const [conversations, setConversations] = useState([]);
  const [selectedConversation, setSelectedConversation] = useState(null);
  const [messages, setMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isMessagesLoading, setIsMessagesLoading] = useState(false);
  const [isNewConvoModalOpen, setIsNewConvoModalOpen] = useState(false);
  const [practitioners, setPractitioners] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [dataLoadAttempted, setDataLoadAttempted] = useState(false); // Prevent multiple load attempts

  const loadConversations = useCallback(async (currentUser) => {
    try {
      // Add a small delay to prevent rapid-fire API calls
      await new Promise(resolve => setTimeout(resolve, 100));

      // The `queryData` method is not available. We'll achieve the OR query by doing two separate filters and merging them.
      // Fetch conversations where the current user is participant 1
      const convosAsP1 = await Conversation.filter({ participant_1_id: currentUser.id });

      // Add another small delay before the second call
      await new Promise(resolve => setTimeout(resolve, 100));

      // Fetch conversations where the current user is participant 2
      const convosAsP2 = await Conversation.filter({ participant_2_id: currentUser.id });

      // Merge the two arrays and remove duplicates using a Map
      const allConversations = [...convosAsP1, ...convosAsP2];
      const uniqueConversations = Array.from(new Map(allConversations.map(c => [c.id, c])).values());

      // Sort the merged list by the last message date in descending order
      uniqueConversations.sort((a, b) => new Date(b.last_message_date) - new Date(a.last_message_date));

      setConversations(uniqueConversations);
      return uniqueConversations;
    } catch (error) {
      console.error("Failed to load conversations:", error);
      return [];
    }
  }, []);

  const loadMessages = useCallback(async (conversation) => {
    if (!conversation || !user || isMessagesLoading) return; // Prevent concurrent calls

    setIsMessagesLoading(true);
    try {
      // Add delay to prevent rate limiting
      await new Promise(resolve => setTimeout(resolve, 150));

      const fetchedMessages = await Message.filter(
        { conversation_id: conversation.id },
        "created_date" // oldest first
      );
      setMessages(fetchedMessages);
    } catch (error) {
      console.error("Failed to load messages:", error);
      setMessages([]);
    } finally {
      setIsMessagesLoading(false);
    }
  }, [user, isMessagesLoading]);

  const handleConversationSelect = useCallback((conversation) => {
    setSelectedConversation(conversation);
    loadMessages(conversation);
  }, [loadMessages]);

  // Load initial data only once on mount
  useEffect(() => {
    const loadInitialData = async () => {
      if (dataLoadAttempted) return; // Prevent multiple attempts

      setIsLoading(true);
      setDataLoadAttempted(true);

      try {
        // Load user first
        const currentUser = await User.me();
        setUser(currentUser);

        // Add delay before next API call
        await new Promise(resolve => setTimeout(resolve, 200));

        // Load conversations
        await loadConversations(currentUser);

        // Add delay before final API call
        await new Promise(resolve => setTimeout(resolve, 200));

        // Load practitioners
        const allPractitioners = await Practitioner.list();
        setPractitioners(allPractitioners.filter(p => p.id !== currentUser.id));

      } catch (error) {
        console.error("Failed to load initial data:", error);
        setUser(null);
      } finally {
        setIsLoading(false);
      }
    };

    loadInitialData();
  }, [dataLoadAttempted, loadConversations]); // Fixed dependencies for useEffect

  // This effect handles selecting a conversation from the URL
  useEffect(() => {
    if (conversations.length > 0 && !isLoading) {
      const searchParams = new URLSearchParams(location.search);
      const conversationIdFromUrl = searchParams.get('conversation_id');

      if (conversationIdFromUrl) {
        const conversationToSelect = conversations.find(c => c.id === conversationIdFromUrl);
        if (conversationToSelect && selectedConversation?.id !== conversationToSelect.id) {
          handleConversationSelect(conversationToSelect);
        }
      } else if (!selectedConversation && conversations.length > 0) {
        // If no ID in URL and none selected, default to the first one
        handleConversationSelect(conversations[0]);
      }
    }
  }, [conversations, isLoading, location.search, selectedConversation, handleConversationSelect]); // Fixed dependencies for useEffect

  const sendMessage = async (messageData) => {
    if (!selectedConversation || !user) return;

    try {
      // 1. Create the new message
      const newMessage = await Message.create({
        ...messageData,
        conversation_id: selectedConversation.id,
      });

      // 2. Optimistically add to UI
      setMessages(prev => [...prev, newMessage]);

      // 3. Update conversation's last message in the background (with delay to avoid rate limiting)
      setTimeout(() => {
        Conversation.update(selectedConversation.id, {
          last_message: messageData.content,
          last_message_date: new Date().toISOString(),
        });
      }, 100);

      // 4. Notify the other participant (with delay)
      setTimeout(() => {
        const otherParticipantId = selectedConversation.participant_1_id === user.id 
            ? selectedConversation.participant_2_id 
            : selectedConversation.participant_1_id;

        if (otherParticipantId) {
          NotificationService.createMessageNotification(otherParticipantId, {
            sender_name: user.full_name,
            content: messageData.content,
            conversation_id: selectedConversation.id
          });
        }
      }, 200);

    } catch (error) {
      console.error("Failed to send message:", error);
      // Optional: handle UI reversal on failure
    }
  };

  const startNewConversation = async (practitionerId, practitionerName) => {
    setIsNewConvoModalOpen(false);
    if (!user) return;

    try {
      // Check if conversation already exists with delays to prevent rate limiting
      const existingConvo1 = await Conversation.filter({
          participant_1_id: user.id,
          participant_2_id: practitionerId
      });

      await new Promise(resolve => setTimeout(resolve, 100));

      const existingConvo2 = await Conversation.filter({
          participant_1_id: practitionerId,
          participant_2_id: user.id
      });

      const existingConvo = [...existingConvo1, ...existingConvo2];

      if (existingConvo.length > 0) {
        handleConversationSelect(existingConvo[0]);
        return;
      }

      // Create a new one if it doesn't exist
      const newConversation = await Conversation.create({
          participant_1_id: user.id,
          participant_2_id: practitionerId,
          participant_1_name: user.full_name,
          participant_2_name: practitionerName,
          last_message: "Conversation started.",
          last_message_date: new Date().toISOString()
      });

      setConversations(prev => [newConversation, ...prev]);
      handleConversationSelect(newConversation);
    } catch (error) {
        console.error("Failed to start new conversation:", error);
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <Loader2 className="w-10 h-10 animate-spin text-emerald-600" />
      </div>
    );
  }

  if (!user) {
    return (
      <div className="flex flex-col items-center justify-center h-screen text-center p-6 bg-gray-50">
        <UserIcon className="w-16 h-16 text-gray-300 mb-4" />
        <h1 className="text-2xl font-bold text-gray-800 mb-2">Please Log In</h1>
        <p className="text-gray-500 max-w-md mb-6">
          You need to be logged in to view your messages.
        </p>
        <Button onClick={() => User.login()} className="bg-emerald-600 hover:bg-emerald-700">
          Log In
        </Button>
      </div>
    );
  }

  const isMobile = typeof window !== 'undefined' && window.innerWidth < 768;
  const showConversationList = isMobile ? !selectedConversation : true;
  const showMessageThread = isMobile ? !!selectedConversation : true;

  return (
    <>
      <NewConversationModal 
        open={isNewConvoModalOpen}
        onOpenChange={setIsNewConvoModalOpen}
        practitioners={practitioners}
        onSelect={startNewConversation}
      />
      <div className="h-screen flex bg-white">
        {/* Sidebar */}
        {showConversationList && (
            <aside className="w-full md:w-80 lg:w-96 flex-col border-r border-gray-200 h-full flex">
              <ConversationList
                conversations={conversations}
                selectedConversation={selectedConversation}
                onConversationSelect={handleConversationSelect}
                currentUser={user}
                onNewConversation={() => setIsNewConvoModalOpen(true)}
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
              />
            </aside>
        )}

        {/* Main Content */}
        {showMessageThread && (
            <main className="flex-1 flex flex-col h-full">
                {selectedConversation ? (
                    <MessageThread 
                        conversation={selectedConversation}
                        messages={messages}
                        currentUser={user}
                        onSendMessage={sendMessage}
                        isLoading={isMessagesLoading}
                        onBack={() => setSelectedConversation(null)}
                    />
                ) : conversations.length > 0 ? (
                     <div className="hidden md:flex flex-col items-center justify-center h-full text-center text-gray-500 p-6">
                        <MessageSquarePlus className="w-16 h-16 mb-4 text-gray-300" />
                        <h2 className="text-xl font-semibold">Select a conversation</h2>
                        <p>Choose a conversation from the left to start chatting.</p>
                    </div>
                ) : (
                     <div className="hidden md:flex flex-col items-center justify-center h-full text-center text-gray-500 p-6">
                        <MessageSquarePlus className="w-16 h-16 mb-4 text-gray-300" />
                        <h2 className="text-xl font-semibold">No conversations yet</h2>
                        <p className="mb-4">Start a new conversation with a practitioner.</p>
                        <Button onClick={() => setIsNewConvoModalOpen(true)}>
                            Start a new conversation
                        </Button>
                    </div>
                )}
            </main>
        )}
      </div>
    </>
  );
}

pages.BookingRequest:
import React, { useState, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { User, Practitioner, Booking, Notification } from "@/entities/all";
import { createPageUrl } from "@/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { format } from "date-fns";
import { Calendar as CalendarIcon, Send, ArrowLeft, UserCircle, Loader2 } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";

export default function BookingRequestPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const practitionerId = new URLSearchParams(location.search).get("practitionerId");

  const [practitioner, setPractitioner] = useState(null);
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const [formData, setFormData] = useState({
    client_name: "",
    client_email: "",
    client_phone: "",
    service_type: "Private Session",
    requested_date: null,
    message: ""
  });

  useEffect(() => {
    if (!practitionerId) {
      navigate(createPageUrl("Directory"));
      return;
    }

    const loadInitialData = async () => {
      setIsLoading(true);
      try {
        const [practitionerData] = await Practitioner.filter({ id: practitionerId });
        if (!practitionerData) {
          // Handle case where practitioner is not found
          navigate(createPageUrl("Directory"));
          return;
        }
        setPractitioner(practitionerData);

        const currentUser = await User.me();
        setUser(currentUser);
        setFormData(prev => ({
          ...prev,
          client_name: currentUser.full_name || "",
          client_email: currentUser.email || ""
        }));
      } catch (error) {
        // User not logged in, but can still book.
        console.log("User not logged in, proceeding with manual entry.");
      } finally {
        setIsLoading(false);
      }
    };

    loadInitialData();
  }, [practitionerId, navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.requested_date || !practitioner) return;

    setIsSubmitting(true);
    try {
      const newBooking = await Booking.create({
        ...formData,
        practitioner_id: practitioner.id,
        practitioner_name: practitioner.full_name,
        client_id: user?.id,
        price: 150, // Default price, can be adjusted
        payment_status: "unpaid"
      });

      // Notify practitioner
      await Notification.create({
        user_id: practitioner.id, // The practitioner gets the notification
        title: "New Booking Request",
        message: `${formData.client_name} has requested a session with you.`,
        type: "booking",
        priority: "high",
        related_id: newBooking.id,
        action_url: createPageUrl('PractitionerDashboard'),
        sender_image_url: user?.profile_image_url
      });

      setSubmitted(true);
      navigate(createPageUrl("Bookings"));
    } catch (error) {
      console.error("Failed to submit booking:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading) {
    return <div className="flex justify-center items-center h-screen"><Loader2 className="w-10 h-10 animate-spin"/></div>;
  }

  if (!practitioner) {
    return <div>Practitioner not found.</div>;
  }

  return (
    <div className="bg-gray-50 min-h-screen p-4 sm:p-6">
      <div className="max-w-3xl mx-auto">
        <div className="mb-6">
          <Button variant="ghost" onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-600 hover:text-gray-900">
            <ArrowLeft className="w-4 h-4" />
            Back
          </Button>
        </div>

        <Card>
          <CardHeader className="text-center">
            <Avatar className="w-24 h-24 mx-auto mb-4 border-4 border-white shadow-lg">
                <AvatarImage src={practitioner.profile_image_url} alt={practitioner.full_name} />
                <AvatarFallback><UserCircle className="w-full h-full text-gray-300" /></AvatarFallback>
            </Avatar>
            <CardTitle className="text-2xl">Request a Booking</CardTitle>
            <p className="text-gray-500">with {practitioner.full_name}</p>
          </CardHeader>
          <CardContent>
            <Alert className="mb-6">
              <AlertDescription>
                Submit this form to request a session. The practitioner will contact you via email to confirm details and arrange payment.
              </AlertDescription>
            </Alert>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="name">Full Name *</Label>
                  <Input id="name" value={formData.client_name} onChange={e => setFormData({...formData, client_name: e.target.value})} required />
                </div>
                <div>
                  <Label htmlFor="email">Email Address *</Label>
                  <Input id="email" type="email" value={formData.client_email} onChange={e => setFormData({...formData, client_email: e.target.value})} required />
                </div>
              </div>

              <div>
                <Label htmlFor="phone">Phone Number</Label>
                <Input id="phone" type="tel" value={formData.client_phone} onChange={e => setFormData({...formData, client_phone: e.target.value})} />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="service">Service Type</Label>
                  <Select value={formData.service_type} onValueChange={value => setFormData({...formData, service_type: value})}>
                    <SelectTrigger id="service"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Private Session">Private Session</SelectItem>
                      <SelectItem value="Group Circle">Group Circle</SelectItem>
                      <SelectItem value="Consultation">Consultation</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label htmlFor="date">Preferred Date *</Label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button id="date" variant={"outline"} className="w-full justify-start text-left font-normal">
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {formData.requested_date ? format(formData.requested_date, "PPP") : <span>Pick a date</span>}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0">
                      <Calendar mode="single" selected={formData.requested_date} onSelect={date => setFormData({...formData, requested_date: date})} initialFocus disabled={(date) => date < new Date()} />
                    </PopoverContent>
                  </Popover>
                </div>
              </div>

              <div>
                <Label htmlFor="message">Message</Label>
                <Textarea id="message" value={formData.message} onChange={e => setFormData({...formData, message: e.target.value})} placeholder="Introduce yourself, mention any specific needs, or ask a question." />
              </div>

              <div className="pt-4 flex justify-end gap-2">
                <Button type="button" variant="outline" onClick={() => navigate(-1)} disabled={isSubmitting}>
                  Cancel
                </Button>
                <Button type="submit" disabled={isSubmitting || !formData.client_name || !formData.client_email || !formData.requested_date} className="bg-emerald-600 hover:bg-emerald-700">
                  <Send className="w-4 h-4 mr-2" />
                  {isSubmitting ? "Sending..." : "Send Request"}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

