import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { User, Report, Practitioner } from "@/entities/all";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent } from "@/components/ui/card";
import { 
  Shield, 
  Users, 
  AlertTriangle, 
  MessageSquare, 
  ShieldCheck, 
  BarChart3,
  Loader2,
  Settings
} from "lucide-react";

import UserManagement from "../components/admin/UserManagement";
import DisputeResolution from "../components/admin/DisputeResolution";
import ContentModeration from "../components/admin/ContentModeration";
import VerificationManagement from "../components/admin/VerificationManagement";
import PlatformAnalytics from "../components/admin/PlatformAnalytics";
import AdminSettings from "../components/admin/AdminSettings";

export default function AdminDashboard() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [stats, setStats] = useState({
    totalUsers: 0,
    pendingReports: 0,
    pendingVerifications: 0,
    activeDisputes: 0
  });

  const loadStats = async () => {
     try {
        const [users, reports, practitioners, allReports] = await Promise.all([
          User.list(),
          Report.filter({ status: 'pending' }),
          Practitioner.filter({ verification_level: 'pending' }),
          Report.filter({ status: 'investigating' }) // Use investigating for active disputes
        ]);

        setStats({
          totalUsers: users.length,
          pendingReports: reports.length,
          pendingVerifications: practitioners.length,
          activeDisputes: allReports.length
        });
      } catch (error) {
        console.error("Failed to load dashboard stats:", error);
      }
  }

  useEffect(() => {
    const checkAdminAccess = async () => {
      try {
        const currentUser = await User.me();
        if (!currentUser || currentUser.role !== 'admin') {
          navigate("/Directory");
          return;
        }
        setUser(currentUser);
        await loadStats();
      } catch (error)
      {
        navigate("/Directory");
      } finally {
        setIsLoading(false);
      }
    };

    checkAdminAccess();
  }, [navigate]);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <Loader2 className="w-10 h-10 animate-spin text-emerald-600" />
      </div>
    );
  }

  if (!user) {
    return null;
  }

  return (
    <div className="p-4 sm:p-6">
      <div className="max-w-7xl mx-auto">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            <Shield className="w-8 h-8 text-emerald-600" />
            Admin Dashboard
          </h1>
          <p className="text-gray-600">Platform management and oversight tools</p>
        </div>

        {/* Quick Stats */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">Total Users</p>
                  <p className="text-2xl font-bold">{stats.totalUsers}</p>
                </div>
                <Users className="w-8 h-8 text-blue-600" />
              </div>
