import React from "react";
import { motion } from "framer-motion";
import { Card } from "@/components/ui/card";
import { Star, UserCircle, MapPin } from "lucide-react";
import { formatDistance } from "../utils/locationUtils"; // Changed path from ../../ to ../
import FavoriteButton from "../favorites/FavoriteButton";

export default function PractitionerCard({
  practitioner,
  averageRating,
  reviewCount,
  onClick,
  size = "medium",
}) {
  const sizeStyles = {
    large: {
      container: "w-64",
      image: "h-64",
      font: "text-base",
    },
    medium: {
      container: "w-48",
      image: "h-48",
      font: "text-sm",
    },
  };

  const currentStyles = sizeStyles[size] || sizeStyles.medium;

  const formatAddress = (address) => {
    if (!address) return "Location not specified";
    const parts = [address.city, address.state_province, address.country];
    return parts.filter(Boolean).join(", ");
  };

  return (
    <motion.div
      whileHover={{ y: -4, scale: 1.02 }}
      className={`cursor-pointer flex-shrink-0 ${currentStyles.container} relative group`}
      onClick={onClick}
    >
      <Card className="overflow-hidden border-gray-200 shadow-sm hover:shadow-lg transition-all duration-300 bg-white h-full">
        <div className={`w-full bg-gray-100 ${currentStyles.image} relative`}>
            {practitioner.profile_image_url ? (
                <img src={practitioner.profile_image_url} alt={practitioner.full_name} className="w-full h-full object-cover" />
            ) : (
                 <div className="w-full h-full flex items-center justify-center bg-gray-100">
                    <UserCircle className="w-16 h-16 text-gray-400" />
                 </div>
            )}
            {/* Verified badge */}
            {practitioner.is_verified && (
              <div className="absolute top-3 left-3">
                <div className="bg-emerald-500 text-white text-xs px-2 py-1 rounded-full font-medium">
                  Verified
                </div>
              </div>
            )}
            {/* Distance badge */}
            {practitioner.distance !== null && practitioner.distance !== undefined && (
              <div className="absolute top-3 right-12">
                <div className="bg-blue-500 text-white text-xs px-2 py-1 rounded-full font-medium">
                  {formatDistance(practitioner.distance)}
                </div>
              </div>
            )}
            {/* Favorite button */}
            <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
              <FavoriteButton
                itemId={practitioner.id}
                itemType="practitioner"
                itemTitle={practitioner.full_name}
                metadata={{
                  location: formatAddress(practitioner.address),
                  image_url: practitioner.profile_image_url
                }}
                size="sm"
                className="bg-white/90 hover:bg-white shadow-sm"
              />
            </div>
        </div>
        <div className="p-4">
          <h3 className={`font-semibold truncate text-gray-900 ${currentStyles.font}`}>{practitioner.full_name}</h3>
          <div className="flex items-center justify-between">
            <p className="text-xs text-gray-500 truncate flex-1">{formatAddress(practitioner.address)}</p>
            {practitioner.distance !== null && practitioner.distance !== undefined && (
              <div className="flex items-center gap-1 text-xs text-blue-600 ml-2">
                <MapPin className="w-3 h-3" />
                {formatDistance(practitioner.distance)}
              </div>
            )}
          </div>
          {/* Only show ratings for verified practitioners */}
          {practitioner.is_verified && reviewCount > 0 && (
            <div className="flex items-center gap-1 mt-2">
              <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
              <span className="text-sm font-medium text-gray-900">{averageRating}</span>
              <span className="text-xs text-gray-500">({reviewCount})</span>
            </div>
          )}
        </div>
      </Card>
    </motion.div>
  );
}

