import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Star
} from "lucide-react";

export default function FilterModal({ isOpen, onClose, onApplyFilters, currentFilters }) {
  const [sortBy, setSortBy] = useState(currentFilters.sortBy || "nearest");
  const [minRating, setMinRating] = useState(currentFilters.minRating || 0);
  const [priceRange, setPriceRange] = useState(currentFilters.priceRange || [80, 450]);
  const [verificationLevel, setVerificationLevel] = useState(currentFilters.verificationLevel || "all");

  const handleApplyFilters = () => {
    onApplyFilters({
      sortBy,
      minRating,
      priceRange,
      verificationLevel
    });
    onClose();
  };

  const clearAllFilters = () => {
    setSortBy("nearest");
    setMinRating(0);
    setPriceRange([80, 450]);
    setVerificationLevel("all");
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 z-50"
            onClick={onClose}
          />

          {/* Modal */}
          <motion.div
            initial={{ y: "100%" }}
            animate={{ y: 0 }}
            exit={{ y: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed inset-x-0 bottom-0 z-50 bg-white rounded-t-xl max-h-[85vh] overflow-y-auto"
          >
            <div className="p-6">
              {/* Header */}
              <div className="flex items-center justify-between mb-8">
                <Button variant="ghost" onClick={clearAllFilters} className="text-gray-600">
                  Cancel
                </Button>
                <h2 className="text-lg font-semibold text-gray-900">Filter</h2>
                <Button variant="ghost" onClick={clearAllFilters} className="text-gray-600">
                  Reset
                </Button>
              </div>

              {/* Sort By */}
              <div className="mb-8">
                <h3 className="text-sm font-semibold text-gray-700 mb-4 uppercase tracking-wide">Sort By</h3>
                <Select value={sortBy} onValueChange={setSortBy}>
                  <SelectTrigger className="w-full bg-gray-50">
                    <SelectValue placeholder="Select sorting option" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="nearest">Nearby your location</SelectItem>
                    <SelectItem value="rating">Highest rated</SelectItem>
                    <SelectItem value="experience">Most experienced</SelectItem>
                    <SelectItem value="newest">Newest first</SelectItem>
                  </SelectContent>
                </Select>

                <div className="mt-3 p-3 bg-gray-50 rounded-lg">
                  <span className="text-sm text-gray-600">100 Mile Radius</span>
                </div>
              </div>

              {/* Rating Filter */}
              <div className="mb-8">
                <h3 className="text-sm font-semibold text-gray-700 mb-4 uppercase tracking-wide">Rating</h3>
                <div className="flex gap-2">
                  <Button
                    variant={minRating === 0 ? "default" : "outline"}
                    onClick={() => setMinRating(0)}
                    className={`flex-1 h-12 text-sm ${
                      minRating === 0 
                        ? "bg-orange-500 hover:bg-orange-600 text-white" 
                        : "border-gray-200 hover:bg-gray-50"
                    }`}
                  >
                    NONE
                  </Button>
                  {[1, 2, 3, 4, 5].map((rating) => (
                    <Button
                      key={rating}
                      variant={minRating === rating ? "default" : "outline"}
                      onClick={() => setMinRating(rating)}
                      className={`flex-1 h-12 ${
                        minRating === rating 
                          ? "bg-orange-500 hover:bg-orange-600 text-white" 
                          : "border-gray-200 hover:bg-gray-50"
                      }`}
                    >
                      <Star className={`w-4 h-4 ${
                        minRating === rating ? "fill-white" : "fill-orange-400 text-orange-400"
                      }`} />
                    </Button>
                  ))}
