              </div>

              {/* Price Range */}
              <div className="mb-8">
                <h3 className="text-sm font-semibold text-gray-700 mb-6 uppercase tracking-wide">Price Range</h3>
                <div className="px-4">
                  <div className="relative mb-6">
                    <Slider
