components.directory/ReviewForm:
import React, { useState, useEffect } from 'react';
import { User, Review, Notification } from "@/entities/all";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Star, Send } from "lucide-react"; // Added Send, removed Loader2
import { createPageUrl } from "@/utils"; // Added createPageUrl

export default function ReviewForm({ practitioner, bookingId, onSubmit, onCancel }) { // Changed prop names
  const [user, setUser] = useState(null);
  const [rating, setRating] = useState(0); // Changed initial rating to 0
  const [comment, setComment] = useState(""); // Renamed reviewText to comment
  const [reviewerName, setReviewerName] = useState(""); // Added reviewerName state
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
        setReviewerName(currentUser.full_name); // Set reviewerName from current user
      } catch (error) { // Changed 'e' to 'error'
        console.log("User not logged in"); // Updated console message
      }
    };
    fetchUser();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    // Removed the !user || !practitioner check as per outline,
    // relying on `user?.id` and `reviewerName` possibly being empty/undefined
    setIsSubmitting(true);

    try {
      const reviewData = {
        practitioner_id: practitioner.id,
        booking_id: bookingId, // This might be null for general reviews
        reviewer_name: reviewerName,
        reviewer_id: user?.id, // Optional chaining for user id
        session_date: new Date().toISOString(), // Changed date format
        overall_rating: rating,
        review_text: comment, // Using 'comment' state
        would_recommend: true, // Assuming default, could add a checkbox
      };

      await Review.create(reviewData);

      // Create notification for the practitioner
      if (practitioner) { // Wrapped notification creation in a check for practitioner
          await Notification.create({
              user_id: practitioner.id,
              title: "You've received a new review!",
              message: `${reviewerName} left a ${rating}-star review on your profile.`, // Used reviewerName
              type: 'review',
              priority: 'high', // Added priority
              related_id: practitioner.id,
              action_url: createPageUrl(`PractitionerProfile?id=${practitioner.id}`), // Used createPageUrl
              sender_image_url: user?.profile_image_url, // Optional chaining for sender image
          });
      }

      onSubmit(reviewData); // Called onSubmit prop
      // Reset form
      setRating(0); // Reset rating
      setComment(""); // Reset comment
      // reviewerName is implicitly reset if user logs out or if form is unmounted
    } catch (error) {
      console.error("Failed to submit review:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <Label>Rating</Label>
        <div className="flex items-center gap-1 mt-2">
          {[1, 2, 3, 4, 5].map((star) => (
            <Star
              key={star}
              className={`w-6 h-6 cursor-pointer ${
                star <= rating ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300'
              }`}
              onClick={() => setRating(star)}
            />
          ))}
        </div>
      </div>
      <div>
        <Label htmlFor="comment">Your Review</Label> {/* Changed htmlFor to comment */}
        <Textarea
          id="comment" // Changed id to comment
          value={comment} // Used comment state
          onChange={(e) => setComment(e.target.value)} // Updated onChange to setComment
          placeholder="Share your experience..."
          required
          rows={4}
        />
      </div>
      <div className="flex justify-end gap-2"> {/* Added flex container for buttons */}
        {onCancel && ( // Conditionally render Cancel button if onCancel prop is provided
          <Button type="button" variant="outline" onClick={onCancel} disabled={isSubmitting}>
            Cancel
          </Button>
        )}
        <Button type="submit" disabled={isSubmitting || rating === 0 || comment.trim() === ""}> {/* Added disable logic for empty rating/comment */}
          {isSubmitting && <Send className="mr-2 h-4 w-4 animate-spin" />} {/* Changed Loader2 to Send */}
          Send Review {/* Changed button text */}
        </Button>
      </div>
    </form>
  );
}

components.directory/MapView:
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import { Button } from '@/components/ui/button';
import { 
  Crosshair, Search, Loader2, MapPin
} from 'lucide-react';
import L from 'leaflet';

// Fix default marker icons to ensure they render correctly.
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

// Component to handle map invalidation
const MapInitializer = () => {
  const map = useMap();

  useEffect(() => {
    // Invalidate size when component mounts to ensure proper rendering
    const timer = setTimeout(() => {
      map.invalidateSize();
    }, 100);

    return () => clearTimeout(timer);
  }, [map]);

  return null;
};

const MapEventHandler = ({ onBoundsChange, setMapBounds }) => {
  const map = useMap();

  const handleMoveEnd = useCallback(() => {
    const bounds = map.getBounds();
    const newBounds = {
      north: bounds.getNorth(),
      south: bounds.getSouth(),
      east: bounds.getEast(),
      west: bounds.getWest(),
      center: map.getCenter()
    };
    setMapBounds(newBounds);
    onBoundsChange(newBounds);
  }, [map, onBoundsChange, setMapBounds]);

  useMapEvents({
    moveend: handleMoveEnd,
    zoomend: handleMoveEnd,
  });

  return null;
};

const MyLocationButton = ({ onLocationFound, isLoading }) => {
  const map = useMap();

  const handleMyLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          map.setView([latitude, longitude], 12);
          onLocationFound({ lat: latitude, lng: longitude });
        },
        (error) => {
          console.error('Geolocation error:', error);
          alert('Unable to get your location. Please enable location services.');
        },
        { timeout: 10000, enableHighAccuracy: true }
      );
    } else {
      alert('Geolocation is not supported by this browser.');
    }
  };

  return (
    <Button
      onClick={handleMyLocation}
      disabled={isLoading}
      className="absolute bottom-4 right-4 z-[1000] bg-white hover:bg-gray-50 text-gray-800 border border-gray-300 shadow-lg"
      size="icon"
    >
      {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Crosshair className="w-4 h-4" />}
      <span className="sr-only">My Location</span>
    </Button>
  );
};

const SearchAreaButton = ({ onSearchArea, isVisible, isLoading }) => {
  if (!isVisible) return null;

  return (
    <Button
      onClick={onSearchArea}
      disabled={isLoading}
      className="absolute top-4 left-1/2 transform -translate-x-1/2 z-[1000] bg-white hover:bg-gray-50 text-gray-800 border border-gray-300 shadow-lg"
      size="sm"
    >
      {isLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Search className="w-4 h-4 mr-2" />}
      Search This Area
    </Button>
  );
};

const MapView = ({ 
  practitioners, 
  onPractitionerSelect,
  onMapPractitionersUpdate 
}) => {
  const [userLocation, setUserLocation] = useState(null);
  const [isLocationLoading, setIsLocationLoading] = useState(false);
  const [mapBounds, setMapBounds] = useState(null);
  const [isSearchAreaVisible, setIsSearchAreaVisible] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const mapRef = useRef();

  const practitionersWithCoords = practitioners.filter(p => p.latitude && p.longitude);

  const mapCenter = userLocation 
    ? [userLocation.lat, userLocation.lng]
    : practitionersWithCoords.length > 0
    ? [practitionersWithCoords[0].latitude, practitionersWithCoords[0].longitude]
    : [39.8283, -98.5795]; // Center of the US

  const handleLocationFound = (location) => {
    setUserLocation(location);
    setIsLocationLoading(false);
  };

  const handleBoundsChange = useCallback(() => {
    setIsSearchAreaVisible(true);
  }, []);

  const handleSearchArea = useCallback(() => {
    if (!mapBounds) return;
    setIsSearching(true);
    setIsSearchAreaVisible(false);

    const practitionersInBounds = practitioners.filter(p => 
      p.latitude && p.longitude &&
      p.latitude >= mapBounds.south &&
      p.latitude <= mapBounds.north &&
      p.longitude >= mapBounds.west &&
      p.longitude <= mapBounds.east
    );

    onMapPractitionersUpdate(practitionersInBounds);

    setTimeout(() => setIsSearching(false), 500);
  }, [practitioners, mapBounds, onMapPractitionersUpdate]);

  // Handle click on the "View Profile" button inside a map popup
  const handleViewProfileClick = (practitioner) => {
    if (mapRef.current) {
        mapRef.current.closePopup();
    }
    onPractitionerSelect(practitioner);
  };

  if (practitionersWithCoords.length === 0) {
    return (
      <div className="h-96 w-full bg-gray-50 flex items-center justify-center rounded-lg border">
        <div className="text-center p-8">
          <MapPin className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-700 mb-2">No practitioners with location data</h3>
          <p className="text-gray-500">Switch to list view to see all practitioners.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-96 relative bg-white rounded-lg border overflow-hidden">
      <MapContainer 
        center={mapCenter} 
        zoom={practitionersWithCoords.length > 0 ? 10 : 4} 
        scrollWheelZoom={true} 
        className="w-full h-full"
        ref={mapRef}
        style={{ height: '100%', width: '100%' }}
      >
        <MapInitializer />

        <TileLayer
          attribution='&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a> &copy; <a href="http://cartodb.com/attributions">CartoDB</a>'
          url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
        />

        <MapEventHandler 
          onBoundsChange={handleBoundsChange}
          setMapBounds={setMapBounds}
        />

        <MyLocationButton 
          onLocationFound={handleLocationFound}
          isLoading={isLocationLoading}
        />

        <SearchAreaButton 
          onSearchArea={handleSearchArea}
          isVisible={isSearchAreaVisible}
          isLoading={isSearching}
        />

        {practitionersWithCoords.map(practitioner => (
          <Marker 
            key={practitioner.id}
            position={[practitioner.latitude, practitioner.longitude]}
          >
            <Popup>
              <div className="text-center p-2">
                <h3 className="font-semibold text-gray-900 mb-1">{practitioner.full_name}</h3>
                {practitioner.address && (
                  <p className="text-sm text-gray-600 mb-2">
                    {[practitioner.address.city, practitioner.address.state_province].filter(Boolean).join(", ")}
                  </p>
                )}
                <Button 
                  size="sm" 
                  onClick={() => handleViewProfileClick(practitioner)}
                  className="bg-emerald-600 hover:bg-emerald-700"
                >
                  View Profile
                </Button>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default MapView;

components.directory/DailyQuote:
import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Leaf } from 'lucide-react';

const quotes = [
  { text: "The wound is the place where the Light enters you.", author: "Rumi" },
  { text: "Healing is not a destination, but a journey of self-discovery.", author: "Anonymous" },
  { text: "Nature itself is the best physician.", author: "Hippocrates" },
  { text: "The greatest healing therapy is friendship and love.", author: "Hubert H. Humphrey" },
  { text: "To heal is to touch with love that which we previously touched with fear.", author: "Stephen Levine" },
  { text: "Your body has the ability to heal itself. Your mind just needs to be convinced.", author: "Anonymous" },
  { text: "The art of healing comes from nature, not from the physician.", author: "Paracelsus" },
  { text: "Embrace the journey of healing, for it is a path to your true self.", author: "Anonymous" },
  { text: "Every step taken in mindfulness is a step toward healing.", author: "Thich Nhat Hanh" },
  { text: "The human spirit is stronger than anything that can happen to it.", author: "C.C. Scott" },
];

export default function DailyQuote() {
  const [dailyQuote, setDailyQuote] = useState({ text: "", author: "" });

  useEffect(() => {
    // Get the day of the year (1-366)
    const now = new Date();
    const start = new Date(now.getFullYear(), 0, 0);
    const diff = (now - start) + ((start.getTimezoneOffset() - now.getTimezoneOffset()) * 60 * 1000);
    const oneDay = 1000 * 60 * 60 * 24;
    const dayOfYear = Math.floor(diff / oneDay);

    const quoteIndex = dayOfYear % quotes.length;
    setDailyQuote(quotes[quoteIndex]);
  }, []);

  if (!dailyQuote.text) {
    return null; // Don't render if there's no quote
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.7, delay: 0.6 }}
      className="max-w-4xl mx-auto my-12 text-center"
    >
      <div className="relative p-6 bg-white/50 border border-emerald-100 rounded-2xl shadow-sm backdrop-blur-sm">
        <Leaf className="absolute top-4 left-4 h-6 w-6 text-emerald-300 opacity-50" />
        <Leaf className="absolute bottom-4 right-4 h-6 w-6 text-emerald-300 opacity-50" />
        <p className="text-xl md:text-2xl font-serif italic text-gray-700 mb-3">
          "{dailyQuote.text}"
        </p>
        <p className="text-sm font-medium text-emerald-700 tracking-wide">
          — {dailyQuote.author}
        </p>
      </div>
    </motion.div>
  );
}

