                {format(new Date(event.start_date), "h:mm a")}
              </span>
            </div>

            <div className="flex items-center gap-2 text-sm text-gray-600">
              {event.is_online ? (
                <>
                  <Globe className="w-4 h-4" />
                  <span>Online Event</span>
                </>
              ) : (
                <>
                  <MapPin className="w-4 h-4" />
                  <span className="truncate flex-1">{event.location}</span>
                  {event.distance !== null && event.distance !== undefined && (
                    <span className="text-blue-600 font-medium ml-auto">
                      {formatDistance(event.distance)}
                    </span>
                  )}
                </>
              )}
            </div>

            <div className="flex items-center justify-between text-sm">
              <div className="flex items-center gap-2 text-gray-600">
                <Users className="w-4 h-4" />
                <span>
                  {event.current_participants}/{event.max_participants} spots
                </span>
              </div>
              <div className="flex items-center gap-1 font-semibold text-emerald-600">
                <DollarSign className="w-4 h-4" />
                <span>{event.price}</span>
              </div>
            </div>
          </div>

          {/* Availability Status */}
          {isFull ? (
            <Badge className="bg-red-100 text-red-800 border-red-200 w-full justify-center mb-3">
              Event Full
            </Badge>
          ) : isAlmostFull ? (
            <Badge className="bg-orange-100 text-orange-800 border-orange-200 w-full justify-center mb-3">
              Only {spotsLeft} spots left!
            </Badge>
          ) : null}

          {/* Action Buttons */}
          <div className="flex gap-2">
            <Button 
              variant="outline" 
              size="sm" 
              onClick={() => onViewDetails(event)}
              className="flex-1"
            >
              View Details
            </Button>
            <Button 
              size="sm" 
              onClick={() => onRegister(event)}
              disabled={isFull}
              className={`flex-1 ${
                isFull 
                  ? "bg-gray-400 cursor-not-allowed" 
                  : "bg-emerald-600 hover:bg-emerald-700"
              }`}
            >
              {isFull ? "Full" : "Register"}
            </Button>
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
}

components.events/EventModal:
import React from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { 
  Calendar, MapPin, Users, DollarSign, Clock, 
  Globe, Video, CheckCircle, AlertTriangle, User
} from "lucide-react";
import { format } from "date-fns";

export default function EventModal({ event, practitioner, onClose, onRegister }) {
  if (!event) return null;

  const getEventTypeBadge = (type) => {
    const badges = {
      circle: { color: "bg-emerald-100 text-emerald-800", text: "Kambo Circle" },
      workshop: { color: "bg-blue-100 text-blue-800", text: "Workshop" },
      retreat: { color: "bg-purple-100 text-purple-800", text: "Retreat" },
      meetup: { color: "bg-orange-100 text-orange-800", text: "Meetup" },
      training: { color: "bg-red-100 text-red-800", text: "Training" }
    };
    return badges[type] || badges.circle;
  };

  const isFull = event.current_participants >= event.max_participants;
  const spotsLeft = event.max_participants - event.current_participants;
  const badge = getEventTypeBadge(event.event_type);

  const startDate = new Date(event.start_date);
  const endDate = new Date(event.end_date);
  const isMultiDay = format(startDate, 'yyyy-MM-dd') !== format(endDate, 'yyyy-MM-dd');

  return (
    <Dialog open={!!event} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="space-y-4">
            {/* Event Image */}
            {event.image_url && (
              <div className="w-full h-48 rounded-lg overflow-hidden">
                <img 
                  src={event.image_url} 
                  alt={event.title}
                  className="w-full h-full object-cover"
                />
              </div>
            )}

            {/* Header Info */}
            <div>
              <div className="flex items-start justify-between mb-2">
                <DialogTitle className="text-2xl font-bold text-gray-900 pr-4">
                  {event.title}
                </DialogTitle>
                <div className="flex gap-2 flex-shrink-0">
                  <Badge className={`${badge.color} border`}>
                    {badge.text}
                  </Badge>
                  {event.is_online && (
                    <Badge className="bg-blue-100 text-blue-800 border-blue-200 flex items-center gap-1">
                      <Video className="w-3 h-3" />
                      Online
                    </Badge>
                  )}
                </div>
              </div>

              <div className="flex items-center gap-2 text-gray-600">
                <User className="w-4 h-4" />
                <span>Hosted by {practitioner?.full_name || "Practitioner"}</span>
              </div>
            </div>
          </div>
        </DialogHeader>

        <div className="space-y-6">
          {/* Key Details */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-3">
              <div className="flex items-center gap-3">
                <Calendar className="w-5 h-5 text-emerald-600" />
                <div>
                  <p className="font-medium">
                    {format(startDate, "EEEE, MMMM d, yyyy")}
                  </p>
                  {isMultiDay && (
                    <p className="text-sm text-gray-600">
                      to {format(endDate, "EEEE, MMMM d, yyyy")}
                    </p>
                  )}
                </div>
              </div>

              <div className="flex items-center gap-3">
                <Clock className="w-5 h-5 text-emerald-600" />
                <div>
                  <p className="font-medium">
                    {format(startDate, "h:mm a")} - {format(endDate, "h:mm a")}
                  </p>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex items-center gap-3">
                {event.is_online ? (
                  <>
                    <Globe className="w-5 h-5 text-emerald-600" />
                    <div>
                      <p className="font-medium">Online Event</p>
                      <p className="text-sm text-gray-600">Link provided after registration</p>
                    </div>
                  </>
                ) : (
                  <>
                    <MapPin className="w-5 h-5 text-emerald-600" />
                    <div>
                      <p className="font-medium">{event.location}</p>
                      {event.address && (
                        <p className="text-sm text-gray-600">{event.address}</p>
                      )}
                    </div>
                  </>
                )}
              </div>

              <div className="flex items-center gap-3">
                <Users className="w-5 h-5 text-emerald-600" />
                <div>
                  <p className="font-medium">
                    {event.current_participants} / {event.max_participants} participants
                  </p>
                  {!isFull && (
                    <p className="text-sm text-gray-600">
                      {spotsLeft} spots remaining
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>

          <Separator />

          {/* Price */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <DollarSign className="w-5 h-5 text-emerald-600" />
              <span className="text-2xl font-bold text-emerald-600">
                ${event.price}
              </span>
              <span className="text-gray-600">{event.currency}</span>
            </div>

            <Button
              onClick={() => onRegister(event)}
              disabled={isFull}
              className={`px-8 ${
                isFull 
                  ? "bg-gray-400 cursor-not-allowed" 
                  : "bg-emerald-600 hover:bg-emerald-700"
              }`}
            >
              {isFull ? "Event Full" : "Register Now"}
            </Button>
          </div>

          <Separator />

          {/* Description */}
          {event.description && (
            <div>
              <h3 className="font-semibold text-lg mb-3">About This Event</h3>
              <p className="text-gray-700 leading-relaxed whitespace-pre-line">
                {event.description}
              </p>
            </div>
          )}

          {/* Requirements */}
          {event.requirements && event.requirements.length > 0 && (
            <div>
              <h3 className="font-semibold text-lg mb-3 flex items-center gap-2">
                <AlertTriangle className="w-5 h-5 text-amber-600" />
                Requirements
              </h3>
              <ul className="space-y-2">
                {event.requirements.map((req, index) => (
                  <li key={index} className="flex items-start gap-2">
                    <CheckCircle className="w-4 h-4 text-emerald-600 mt-0.5 flex-shrink-0" />
                    <span className="text-gray-700">{req}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* What to Bring */}
          {event.what_to_bring && event.what_to_bring.length > 0 && (
            <div>
              <h3 className="font-semibold text-lg mb-3">What to Bring</h3>
              <ul className="space-y-2">
                {event.what_to_bring.map((item, index) => (
                  <li key={index} className="flex items-start gap-2">
                    <CheckCircle className="w-4 h-4 text-emerald-600 mt-0.5 flex-shrink-0" />
                    <span className="text-gray-700">{item}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          {isFull && (
            <div className="bg-red-50 border border-red-200 rounded-lg p-4">
              <p className="text-red-800 font-medium">
                This event is currently full. You can still register to join the waitlist.
              </p>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

components.events/RegistrationModal:
import React, { useState, useEffect } from 'react';
import { User, Notification } from "@/entities/all";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Loader2 } from "lucide-react";
import { createPageUrl } from '@/utils';

export default function RegistrationModal({ event, onClose, onSubmitRegistration }) {
  const [user, setUser] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    participant_name: "",
    participant_email: "",
    participant_phone: "",
    previous_kambo_experience: false,
    medical_conditions: "",
    emergency_contact: ""
  });

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
        setFormData(prev => ({
          ...prev,
          participant_name: currentUser.full_name || "",
          participant_email: currentUser.email || "",
          participant_phone: currentUser.phone || ""
        }));
      } catch (e) {
        setUser(null);
      }
    };
    fetchUser();
  }, []);

  const handleRegistrationSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      const registrationData = {
        ...formData,
        event_id: event.id,
        registration_status: "confirmed", // Auto-confirm for this app version
        payment_status: "pending"
      };

      await onSubmitRegistration(registrationData);

      // Create a notification for the user
      if (user) {
        await Notification.create({
            user_id: user.id,
            title: "Event Registration Confirmed",
            message: `You are now registered for "${event.title}".`,
            type: 'event',
            related_id: event.id,
            action_url: createPageUrl("Bookings") // Or an event-specific page
        });
      }

      onClose();
    } catch (error) {
      console.error("Registration failed:", error);
      alert("Registration failed. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!event) return null;

  return (
    <Dialog open={true} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle>Register for: {event.title}</DialogTitle>
          <DialogDescription>
            Complete the form below to secure your spot.
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleRegistrationSubmit}>
          <div className="grid gap-4 py-4">
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="name" className="text-right">Name</Label>
              <Input
                id="name"
                value={formData.participant_name}
                onChange={(e) => setFormData({...formData, participant_name: e.target.value})}
                className="col-span-3"
                required
              />
            </div>
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="email" className="text-right">Email</Label>
              <Input
                id="email"
                type="email"
                value={formData.participant_email}
                onChange={(e) => setFormData({...formData, participant_email: e.target.value})}
                className="col-span-3"
                required
              />
            </div>
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="phone" className="text-right">Phone</Label>
              <Input
                id="phone"
                value={formData.participant_phone}
                onChange={(e) => setFormData({...formData, participant_phone: e.target.value})}
                className="col-span-3"
                required
              />
            </div>
            <div className="grid grid-cols-4 items-start gap-4">
              <Label htmlFor="medical" className="text-right pt-2">Medical Notes</Label>
              <Textarea
                id="medical"
                value={formData.medical_conditions}
                onChange={(e) => setFormData({...formData, medical_conditions: e.target.value})}
                placeholder="Any conditions or medications we should be aware of?"
                className="col-span-3"
              />
            </div>
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={onClose}>Cancel</Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Register
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

components.community/ForumView:
import React, { useState, useEffect } from "react";
import { Post } from "@/entities/Post";
import { Link } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Plus, Search, MessageSquare, Pin, ArrowRight } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import FavoriteButton from "../favorites/FavoriteButton";

const PostListItem = ({ post }) => {
  const categoryColors = {
    "General Discussion": "bg-blue-100 text-blue-800 border-blue-200",
    "Experience Sharing": "bg-emerald-100 text-emerald-800 border-emerald-200",
    "Q&A": "bg-amber-100 text-amber-800 border-amber-200",
    "Integration": "bg-purple-100 text-purple-800 border-purple-200",
  };

  return (
    <Card className="shadow-sm border-gray-200 hover:shadow-md hover:border-gray-300 transition-all duration-300 group relative">
        <CardContent className="p-4 flex items-start gap-4">
            <div className="flex-1">
              {post.is_pinned && (
                <div className="flex items-center gap-1.5 text-xs text-amber-600 font-medium mb-2">
                  <Pin className="w-3.5 h-3.5"/> Pinned Post
                </div>
              )}
              <Link to={createPageUrl(`Post?id=${post.id}`)} className="block group-hover:text-emerald-600 transition-colors">
                <h3 className="font-semibold text-gray-800 text-lg mb-2">{post.title}</h3>
              </Link>
              <div className="flex items-center gap-2 text-sm text-gray-600">
                <Badge variant="outline" className={`${categoryColors[post.category]} border`}>{post.category}</Badge>
                <span>by {post.author_name}</span>
                <span>•</span>
                <span>{formatDistanceToNow(new Date(post.last_reply_date || post.created_date), { addSuffix: true })}</span>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <div className="flex flex-col items-center justify-center text-center">
                <div className="text-2xl font-bold text-gray-800">{post.reply_count}</div>
                <div className="text-xs text-gray-500">replies</div>
              </div>

              {/* Favorite button */}
              <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                <FavoriteButton
                  itemId={post.id}
                  itemType="post"
                  itemTitle={post.title}
                  metadata={{
                    post_author: post.author_name,
                    category: post.category
                  }}
                  size="sm"
                />
              </div>

              <Link to={createPageUrl(`Post?id=${post.id}`)} className="opacity-0 group-hover:opacity-100 transition-opacity">
                <ArrowRight className="w-4 h-4 text-gray-400" />
              </Link>
            </div>
        </CardContent>
    </Card>
  );
};


export default function ForumView() {
  const [posts, setPosts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [hasFetched, setHasFetched] = useState(false);

  useEffect(() => {
    const fetchPosts = async () => {
      if (hasFetched) return; // Prevent multiple fetches

      setIsLoading(true);
      setHasFetched(true);

      try {
        await new Promise(resolve => setTimeout(resolve, 300)); // Add delay to prevent rate limiting
        const allPosts = await Post.list("-last_reply_date");
        // Mock data for reply counts for demo
        const postsWithReplies = allPosts.map((p, i) => ({...p, reply_count: i % 5 + (p.is_pinned ? 5 : 0) }));
        setPosts(postsWithReplies);
      } catch (error) {
        console.error("Failed to load posts:", error);
        setPosts([]);
      } finally {
        setIsLoading(false);
      }
    };
    fetchPosts();
  }, []); // Empty dependency array to run only once

  const filteredPosts = posts.filter(post => 
    post.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    post.content.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const pinnedPosts = filteredPosts.filter(p => p.is_pinned);
  const regularPosts = filteredPosts.filter(p => !p.is_pinned);

  return (
    <div>
      <div className="flex flex-col sm:flex-row gap-4 mb-6">
        <div className="relative flex-1">
          <Search className="absolute left-3.5 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
          <Input
            placeholder="Search discussions..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-11 h-11 rounded-xl bg-white border-gray-300"
          />
        </div>
        <Link to={createPageUrl("NewPost")}>
          <Button className="w-full sm:w-auto bg-emerald-600 hover:bg-emerald-700 h-11 rounded-xl">
            <Plus className="w-4 h-4 mr-2" />
            New Post
          </Button>
        </Link>
      </div>

      {isLoading ? (
        <div className="space-y-4">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-24 bg-gray-100 rounded-lg animate-pulse"></div>
          ))}
        </div>
      ) : filteredPosts.length > 0 ? (
        <div className="space-y-3">
          {pinnedPosts.map(post => <PostListItem key={post.id} post={post} />)}
          {regularPosts.map(post => <PostListItem key={post.id} post={post} />)}
        </div>
      ) : (
        <div className="text-center py-12">
          <MessageSquare className="w-12 h-12 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-800 mb-2">No discussions found</h3>
          <p className="text-gray-500">Be the first to start a conversation!</p>
        </div>
      )}
    </div>
  );
}

