      setIsLoading(false);
    };
    fetchResources();
  }, []);

  const groupedResources = groupBy(resources, 'category');
  const categoryOrder = ["Community Guidelines", "Safety Protocols", "Integration Practices", "Further Reading"];

  return (
    <div className="space-y-12">
      {isLoading ? (
        <div className="space-y-12">
          {[...Array(3)].map((_, i) => (
            <div key={i}>
              <div className="flex items-center gap-3 mb-6">
                <div className="w-12 h-12 bg-gray-200 rounded-lg animate-pulse"></div>
                <div>
                  <div className="h-6 w-48 bg-gray-200 rounded animate-pulse mb-2"></div>
                  <div className="h-4 w-24 bg-gray-200 rounded animate-pulse"></div>
                </div>
              </div>
              <div className="grid md:grid-cols-2 gap-6">
                <div className="h-64 bg-gray-100 rounded-lg animate-pulse"></div>
                <div className="h-64 bg-gray-100 rounded-lg animate-pulse"></div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <>
          {categoryOrder.map(category => (
            groupedResources[category] && (
              <div key={category} className="scroll-mt-6">
                <CategoryHeader 
                  category={category} 
                  count={groupedResources[category].length}
                />
                <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-6">
                  {groupedResources[category].map(resource => (
                    <ResourceCard key={resource.id} resource={resource} />
                  ))}
                </div>
              </div>
            )
          ))}

          {/* Empty State */}
          {resources.length === 0 && (
            <div className="text-center py-16">
              <div className="w-20 h-20 bg-gradient-to-br from-emerald-100 to-teal-100 rounded-full flex items-center justify-center mx-auto mb-6">
                <BookOpen className="w-10 h-10 text-emerald-600" />
              </div>
              <h3 className="text-xl font-semibold text-gray-800 mb-2">No Resources Yet</h3>
              <p className="text-gray-500 max-w-md mx-auto">
                Community resources will appear here as they become available. Check back soon!
              </p>
            </div>
          )}
        </>
      )}
    </div>
  );
}

components.bookings/ClientBookingsView:
import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Booking, Practitioner, Message, User, Payment, Review, Conversation } from "@/entities/all";
import { createPageUrl } from "@/utils";
import { format } from 'date-fns';
import { Calendar, Check, X, Hourglass, CalendarCheck2, AlertTriangle, MessageSquare, Loader2, RefreshCw, DollarSign, Star, CheckCircle } from 'lucide-react';
import { NotificationService } from '../notifications/NotificationService';
import BookingReviewModal from './BookingReviewModal';

const ConfirmationDialog = ({ open, onOpenChange, onConfirm, title, description, isDestructive, isProcessing, children }) => (
  <Dialog open={open} onOpenChange={onOpenChange}>
    <DialogContent>
      <DialogHeader>
        <DialogTitle className="flex items-center gap-2">
          {isDestructive && <AlertTriangle className="text-red-500" />}
          {title}
        </DialogTitle>
        <DialogDescription>{description}</DialogDescription>
      </DialogHeader>
      {children}
      <DialogFooter className="gap-2 pt-4">
        <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isProcessing}>
          Back
        </Button>
        <Button 
          onClick={onConfirm}
          className={isDestructive ? 'bg-red-600 hover:bg-red-700' : 'bg-emerald-600 hover:bg-emerald-700'}
          disabled={isProcessing}
        >
          {isProcessing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Check className="w-4 h-4 mr-2" />}
          Confirm
        </Button>
      </DialogFooter>
    </DialogContent>
  </Dialog>
);

const StatusInfo = ({ status }) => {
  const config = {
    pending: {
      icon: <Hourglass className="w-4 h-4 text-yellow-600" />,
      text: "Pending practitioner confirmation.",
      badge: "bg-yellow-100 text-yellow-800 border-yellow-200",
    },
    confirmed: {
      icon: <Check className="w-4 h-4 text-green-600" />,
      text: "Confirmed! The practitioner will be in touch.",
      badge: "bg-green-100 text-green-800 border-green-200",
    },
    declined: {
      icon: <X className="w-4 h-4 text-red-600" />,
      text: "This booking was declined by the practitioner.",
      badge: "bg-red-100 text-red-800 border-red-200",
    },
    cancelled: {
      icon: <X className="w-4 h-4 text-gray-500" />,
      text: "You have cancelled this booking request.",
      badge: "bg-gray-100 text-gray-700 border-gray-200",
    },
    completed: {
      icon: <CalendarCheck2 className="w-4 h-4 text-blue-600" />,
      text: "This session has been completed.",
      badge: "bg-blue-100 text-blue-800 border-blue-200",
    },
  };

  const current = config[status] || config.pending;

  return (
    <>
        <Badge className={current.badge}>{status}</Badge>
        <div className="flex items-center gap-2 text-sm text-gray-600 mt-3">
            {current.icon}
            <p>{current.text}</p>
        </div>
    </>
  );
};

const RescheduleButton = ({ booking }) => {
    const navigate = useNavigate();
    const [conversationId, setConversationId] = useState(null);

    useEffect(() => {
        const findConversation = async () => {
            if (!booking.id) return;
            try {
                const convos = await Conversation.filter({ related_booking_id: booking.id });
                if (convos.length > 0) {
                    setConversationId(convos[0].id);
                }
            } catch (error) {
                console.error("Failed to fetch conversation for booking:", error);
            }
        };
        findConversation();
    }, [booking.id]);

    const handleReschedule = () => {
        if (conversationId) {
            navigate(createPageUrl(`Messages?conversation_id=${conversationId}`));
        } else {
            // Fallback for older bookings without a conversation link or if fetching fails
            navigate(createPageUrl('Messages'));
        }
    };

    return (
        <Button variant="outline" size="sm" onClick={handleReschedule}>
            <MessageSquare className="w-4 h-4 mr-2" />
            Request Reschedule
        </Button>
    );
};

const ClientBookingsView = ({ bookings, onUpdate }) => {
  const [confirmState, setConfirmState] = useState({ open: false, booking: null, action: null });
  const [isProcessing, setIsProcessing] = useState(false);
  const [reviewState, setReviewState] = useState({ open: false, booking: null });
  const [reviewedBookingIds, setReviewedBookingIds] = useState(new Set());
  const [reviewsLoaded, setReviewsLoaded] = useState(false);

  // Memoize bookings length to prevent unnecessary re-renders
  const bookingsLength = bookings?.length || 0;

  useEffect(() => {
    // Only fetch reviews once when component mounts or when bookings length changes
    const checkReviewedBookings = async () => {
      // Don't fetch if we already loaded reviews or if there are no bookings
      if (reviewsLoaded || bookingsLength === 0) return;

      try {
        const user = await User.me();
        if (user) {
          const userReviews = await Review.filter({ reviewer_id: user.id });
          const reviewedIds = new Set(userReviews.map(r => r.booking_id));
          setReviewedBookingIds(reviewedIds);
          setReviewsLoaded(true); // Mark as loaded
        }
      } catch (error) {
        console.warn("Could not load review history:", error);
        setReviewsLoaded(true); // Mark as loaded even on error to prevent retries
      }
    };

    checkReviewedBookings();
  }, [bookingsLength, reviewsLoaded]); // Use bookingsLength instead of accessing bookings directly

  const cancellationFee = confirmState.booking?.price ? (confirmState.booking.price * 0.2).toFixed(2) : '0.00';

  const handleAction = (booking, action) => {
    setConfirmState({ open: true, booking, action });
  };

  const handleReview = (booking) => {
    // Ensure booking is completed before allowing review
    if (booking.status !== 'completed') {
      console.warn("Can only review completed bookings");
      return;
    }

    // Check if already reviewed
    if (reviewedBookingIds.has(booking.id)) {
      console.warn("This booking has already been reviewed");
      return;
    }

    setReviewState({ open: true, booking: booking });
  };

  const handleReviewSubmit = async () => {
    // Reload bookings and review status after review submission
    onUpdate();

    // Update local state to reflect new review without making additional API calls
    if (reviewState.booking) {
      setReviewedBookingIds(prev => new Set([...prev, reviewState.booking.id]));
    }
    setReviewState({ open: false, booking: null }); // Close the modal
  };

  const handleConfirm = async () => {
    const { booking, action } = confirmState;
    if (!booking || !action) return;

    setIsProcessing(true);

    try {
      if (action === 'withdraw') { // For pending requests, no fee
        await Booking.update(booking.id, { status: 'cancelled' });

        // Create notification for user
        const currentUser = await User.me();
        await NotificationService.createBookingNotification(
          currentUser.id, 
          booking, 
          'cancelled'
        );

      } else if (action === 'cancel' && booking.status === 'confirmed') { // For confirmed sessions, process fee
        const currentUser = await User.me();

        // 1. Process cancellation fee payment
        if (booking.price > 0 && parseFloat(cancellationFee) > 0) {
          await Payment.create({
            booking_id: booking.id,
            user_id: currentUser.id,
            practitioner_id: booking.practitioner_id,
            amount: parseFloat(cancellationFee),
            payment_type: 'cancellation_fee',
            payment_status: 'completed',
            currency: 'USD',
          });
        }

        // 2. Update booking to cancelled
        await Booking.update(booking.id, { status: 'cancelled' });

        // 3. Create notification for user
        await NotificationService.createBookingNotification(
          currentUser.id, 
          booking, 
          'cancelled'
        );

        // 4. Send in-app system message to practitioner
        const practitioners = await Practitioner.filter({ id: booking.practitioner_id });
        if (practitioners.length > 0) {
          const practitionerUser = await User.filter({ email: practitioners[0].email });
          if (practitionerUser.length > 0) {
            await Message.create({
              booking_id: booking.id,
              sender_id: currentUser.id,
              receiver_id: practitionerUser[0].id,
              sender_name: "KamboConnect System",
              content: `Booking Cancelled: Your session with ${booking.client_name} for ${format(new Date(booking.requested_date), 'PPP')} was cancelled. A 20% cancellation fee of $${cancellationFee} has been processed.`,
              message_type: 'system',
              is_read: false
            });
          }
        }
      }
      onUpdate(); // Reload data in parent
    } catch (error) {
      console.error(`Failed to ${action} booking:`, error);
      // You could show an error toast here
    } finally {
      setIsProcessing(false);
      setConfirmState({ open: false, booking: null, action: null });
    }
  };

  if (!bookings || bookings.length === 0) {
    return (
      <Card className="text-center py-12">
        <CardHeader>
          <Calendar className="w-12 h-12 mx-auto text-gray-300" />
          <CardTitle className="mt-4">You have no booking requests</CardTitle>
          <CardDescription>
            Find a practitioner in the directory to request a session.
          </CardDescription>
        </CardHeader>
      </Card>
    );
  }

  const upcoming = bookings.filter(b => b.status === 'pending' || b.status === 'confirmed');
  const past = bookings.filter(b => b.status === 'declined' || b.status === 'completed' || b.status === 'cancelled');

  return (
    <div className="space-y-8">
      <ConfirmationDialog
        open={confirmState.open}
        onOpenChange={(isOpen) => !isProcessing && setConfirmState({ ...confirmState, open: isOpen })}
        onConfirm={handleConfirm}
        isProcessing={isProcessing}
        title={confirmState.action === 'withdraw' ? 'Withdraw Booking Request?' : 'Cancel Confirmed Session?'}
        description={
            confirmState.action === 'withdraw' 
            ? `Are you sure you want to withdraw your request with ${confirmState.booking?.practitioner_name}? This can be re-booked later.`
            : `Are you sure you want to cancel this session? Please review the cancellation policy below.`
        }
        isDestructive={true}
      >
        {confirmState.action === 'cancel' && confirmState.booking?.status === 'confirmed' && (
             <div className="mt-4 p-4 bg-amber-50 border border-amber-200 rounded-lg">
                <h4 className="font-semibold text-amber-900 flex items-center gap-2"><DollarSign className="w-5 h-5"/>Cancellation Fee</h4>
                <p className="text-sm text-amber-800 mt-2">
                    Cancelling a confirmed session incurs a 20% fee to compensate the practitioner. This does not include standard credit card processing fees.
                </p>
                <div className="mt-3 font-medium text-amber-900">
                    Session Price: ${confirmState.booking?.price?.toFixed(2) || 'N/A'}<br/>
                    Cancellation Fee (20%): ${cancellationFee}
                </div>
                 <p className="text-xs text-amber-700 mt-2">By confirming, you agree to be charged this amount.</p>
            </div>
        )}
      </ConfirmationDialog>

      {reviewState.open && (
        <BookingReviewModal
          booking={reviewState.booking}
          onClose={() => setReviewState({ open: false, booking: null })}
          onSubmit={handleReviewSubmit}
        />
      )}

      <section>
        <h2 className="text-2xl font-bold mb-4">Upcoming Bookings</h2>
        {upcoming.length > 0 ? (
          <div className="grid md:grid-cols-2 gap-6">
            {upcoming.map(booking => (
              <BookingCard key={booking.id} booking={booking} onAction={handleAction} onReview={handleReview} hasBeenReviewed={reviewedBookingIds.has(booking.id)} />
            ))}
          </div>
        ) : (
          <p className="text-gray-500">No upcoming sessions found.</p>
        )}
      </section>

      <section>
        <h2 className="text-2xl font-bold mb-4">Booking History</h2>
        {past.length > 0 ? (
          <div className="grid md:grid-cols-2 gap-6">
            {past.map(booking => (
              <BookingCard key={booking.id} booking={booking} onAction={handleAction} onReview={handleReview} hasBeenReviewed={reviewedBookingIds.has(booking.id)} />
            ))}
          </div>
        ) : (
          <p className="text-gray-500">No past bookings found.</p>
        )}
      </section>
    </div>
  );
};

const BookingCard = ({ booking, onAction, onReview, hasBeenReviewed }) => {
    const canReview = booking.status === 'completed' && !hasBeenReviewed;

    return (
        <Card key={booking.id} className="flex flex-col border-gray-200 shadow-sm">
            <CardHeader>
                <div className="flex justify-between items-start">
                    <div>
                        <CardTitle className="text-lg">
                            Session with {booking.practitioner_name}
                        </CardTitle>
                        <CardDescription>{booking.service_type}</CardDescription>
                    </div>
                    <Link to={createPageUrl(`PractitionerProfile?id=${booking.practitioner_id}`)}>
                       <Button variant="outline" size="sm">View Profile</Button>
                    </Link>
                </div>
            </CardHeader>
            <CardContent className="flex-grow space-y-4">
                <div className="flex items-center gap-2 text-sm text-gray-700">
                    <Calendar className="w-4 h-4 text-gray-500" />
                    <span>Requested for: {format(new Date(booking.requested_date), 'PPP')}</span>
                </div>
                <div>
                    <StatusInfo status={booking.status} />
                </div>
            </CardContent>
            <div className="p-4 border-t bg-gray-50 flex flex-wrap gap-2">
                {booking.status === 'pending' && (
                    <Button variant="destructive" size="sm" onClick={() => onAction(booking, 'withdraw')}>
                        <X className="w-4 h-4 mr-2" />
                        Withdraw Request
                    </Button>
                )}
                {booking.status === 'confirmed' && (
                    <>
                        <Button variant="destructive" size="sm" onClick={() => onAction(booking, 'cancel')}>
                            <X className="w-4 h-4 mr-2" />
                            Cancel Session
                        </Button>
                        <RescheduleButton booking={booking} />
                    </>
                )}
                {booking.status === 'completed' && (
                    canReview ? (
                        <Button size="sm" className="bg-emerald-600 hover:bg-emerald-700" onClick={() => onReview(booking)}>
                            <Star className="w-4 h-4 mr-2" />
                            Leave a Review
                        </Button>
                    ) : hasBeenReviewed ? (
                        <Button size="sm" disabled variant="outline">
                            <CheckCircle className="w-4 h-4 mr-2" />
                            Review Submitted
                        </Button>
                    ) : null
                )}
                {(booking.status === 'declined' || booking.status === 'cancelled') && (
                    <Link to={createPageUrl(`Directory`)}>
                        <Button size="sm">
                            <RefreshCw className="w-4 h-4 mr-2" />
                            Find Another Practitioner
                        </Button>
                    </Link>
                )}
            </div>
        </Card>
    );
};

export default ClientBookingsView;

components.bookings/PractitionerBookingsView:
import React from 'react';
import { Card, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { format } from 'date-fns';
import { Check, X, Mail, Phone, MoreHorizontal, Briefcase } from "lucide-react";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Booking } from '@/entities/Booking';

const StatusBadge = ({ status }) => {
    const statusStyles = {
      pending: "bg-yellow-100 text-yellow-800 border-yellow-200",
      confirmed: "bg-green-100 text-green-800 border-green-200",
      declined: "bg-red-100 text-red-800 border-red-200",
      completed: "bg-blue-100 text-blue-800 border-blue-200",
      cancelled: "bg-gray-100 text-gray-700 border-gray-200",
    };
    return <Badge className={statusStyles[status] || statusStyles.pending}>{status}</Badge>;
};

const PractitionerBookingsView = ({ bookings, onUpdate }) => {

  const updateBookingStatus = async (bookingId, status) => {
    await Booking.update(bookingId, { status });
    onUpdate();
  };

  const BookingRow = ({ booking }) => (
    <TableRow>
      <TableCell>
        <div className="font-medium">{booking.client_name}</div>
        <div className="text-sm text-muted-foreground">{booking.client_email}</div>
      </TableCell>
      <TableCell>{format(new Date(booking.requested_date), "PP")}</TableCell>
      <TableCell>{booking.service_type}</TableCell>
      <TableCell><StatusBadge status={booking.status} /></TableCell>
      <TableCell>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon"><MoreHorizontal className="w-4 h-4"/></Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent>
             <DropdownMenuItem onClick={() => updateBookingStatus(booking.id, 'confirmed')}>
                <Check className="w-4 h-4 mr-2"/>Confirm
             </DropdownMenuItem>
             <DropdownMenuItem onClick={() => updateBookingStatus(booking.id, 'declined')}>
                <X className="w-4 h-4 mr-2"/>Decline
             </DropdownMenuItem>
             <DropdownMenuItem onClick={() => updateBookingStatus(booking.id, 'completed')}>
                <Check className="w-4 h-4 mr-2"/>Mark as Completed
             </DropdownMenuItem>
             <DropdownMenuItem asChild>
                <a href={`mailto:${booking.client_email}`} className="w-full">
                    <Mail className="w-4 h-4 mr-2"/>Email Client
                </a>
             </DropdownMenuItem>
             {booking.client_phone && (
                <DropdownMenuItem asChild>
                    <a href={`tel:${booking.client_phone}`} className="w-full">
                       <Phone className="w-4 h-4 mr-2"/>Call Client
                    </a>
                </DropdownMenuItem>
             )}
          </DropdownMenuContent>
        </DropdownMenu>
      </TableCell>
    </TableRow>
  );

  if (!bookings || bookings.length === 0) {
    return (
      <Card className="text-center py-12">
        <CardHeader>
          <Briefcase className="w-12 h-12 mx-auto text-gray-300" />
          <CardTitle className="mt-4">You have no client bookings</CardTitle>
          <CardDescription>
            When clients request to book with you, their requests will appear here.
          </CardDescription>
        </CardHeader>
      </Card>
    );
  }

  const filteredBookings = (status) => {
    if (status === 'archived') {
      return bookings.filter(b => b.status === 'declined' || b.status === 'cancelled' || b.status === 'completed');
    }
    return bookings.filter(b => b.status === status);
  };

  return (
    <Tabs defaultValue="pending">
      <TabsList>
        <TabsTrigger value="pending">Pending ({filteredBookings('pending').length})</TabsTrigger>
        <TabsTrigger value="confirmed">Confirmed ({filteredBookings('confirmed').length})</TabsTrigger>
        <TabsTrigger value="archived">Archived ({filteredBookings('archived').length})</TabsTrigger>
      </TabsList>

      {['pending', 'confirmed', 'archived'].map(status => (
        <TabsContent key={status} value={status} className="mt-4">
            <Card>
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Client</TableHead>
                            <TableHead>Requested Date</TableHead>
                            <TableHead>Service</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead>Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredBookings(status).map(b => <BookingRow key={b.id} booking={b}/>)}
                    </TableBody>
                </Table>
                {filteredBookings(status).length === 0 && <p className="p-6 text-center text-gray-500">No {status} bookings.</p>}
            </Card>
        </TabsContent>
      ))}
    </Tabs>
  );
};

export default PractitionerBookingsView;

components.bookings/BookingReviewModal:
import React, { useState, useEffect } from "react";
import { Review, User, Notification } from "@/entities/all";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Separator } from "@/components/ui/separator";
import { Star, CheckCircle, XCircle, Loader2, Calendar } from "lucide-react";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { format } from 'date-fns';

const StarRating = ({ rating, onRatingChange, label, description, required = false }) => (
  <div className="space-y-2">
    <div className="flex items-center justify-between">
      <Label className="text-sm font-medium">
        {label} {required && <span className="text-red-500">*</span>}
      </Label>
      <span className="text-sm text-gray-500">{rating > 0 ? `${rating}/5` : 'Not rated'}</span>
    </div>
    {description && <p className="text-xs text-gray-500">{description}</p>}
    <div className="flex gap-1">
      {[1, 2, 3, 4, 5].map((star) => (
        <button
          key={star}
          type="button"
          onClick={() => onRatingChange(star)}
          className="focus:outline-none transition-all hover:scale-110"
        >
          <Star
            className={`w-6 h-6 transition-colors ${
              star <= rating
                ? "text-yellow-400 fill-yellow-400"
                : "text-gray-300 hover:text-yellow-300"
            }`}
          />
        </button>
      ))}
    </div>
  </div>
);

export default function BookingReviewModal({ booking, onClose, onSubmit }) {
  const [user, setUser] = useState(null);
  const [reviewData, setReviewData] = useState({
    overall_rating: 0,
    safety_rating: 0,
    communication_rating: 0,
    environment_rating: 0,
    professionalism_rating: 0,
    review_text: "",
    would_recommend: null,
    session_date: booking?.requested_date ? format(new Date(booking.requested_date), 'yyyy-MM-dd') : ""
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
      } catch (e) {
        setError("You must be logged in to leave a review");
      }
    };
    fetchUser();
  }, []);

  const validateForm = () => {
    if (reviewData.overall_rating === 0) {
      return "Please provide an overall rating";
    }
    if (reviewData.would_recommend === null) {
      return "Please indicate if you would recommend this practitioner";
    }
    if (!reviewData.review_text.trim()) {
      return "Please write a review describing your experience";
    }
    if (!reviewData.session_date) {
      return "Please confirm the session date";
    }
    return null;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!user || !booking) return;

    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    setIsSubmitting(true);
    setError("");

    try {
      const newReview = await Review.create({
        practitioner_id: booking.practitioner_id,
        booking_id: booking.id,
        reviewer_name: user.full_name,
        reviewer_id: user.id,
        session_date: reviewData.session_date,
        session_type: booking.service_type,
        overall_rating: reviewData.overall_rating,
        safety_rating: reviewData.safety_rating || null,
        communication_rating: reviewData.communication_rating || null,
        environment_rating: reviewData.environment_rating || null,
        professionalism_rating: reviewData.professionalism_rating || null,
        review_text: reviewData.review_text.trim(),
        would_recommend: reviewData.would_recommend,
        verified_client: true, // Always true when submitted via completed booking
      });

      // Notify the practitioner about the new review
      await Notification.create({
        user_id: booking.practitioner_id,
        title: `New Review from ${user.full_name}`,
        message: `You received a ${newReview.overall_rating}-star review for a recent session.`,
        type: 'review',
        priority: 'normal',
        related_id: newReview.id,
        action_url: `/PractitionerProfile?id=${booking.practitioner_id}` // Link to their profile
      });

      onSubmit(); // Trigger refresh in parent component
      onClose(); // Close the modal
    } catch (error) {
      console.error("Failed to submit review:", error);
      setError("There was an error submitting your review. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!booking || !user) return null;

  return (
    <Dialog open={true} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-2xl flex items-center gap-2">
            <Star className="w-6 h-6 text-yellow-500" />
            Review Your Session with {booking.practitioner_name}
          </DialogTitle>
          <DialogDescription>
            Your feedback helps our community make informed decisions and helps practitioners improve their services.
          </DialogDescription>
        </DialogHeader>

        {error && (
          <Alert variant="destructive" className="mb-4">
            <XCircle className="h-4 w-4" />
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        )}

        <form onSubmit={handleSubmit} className="space-y-6 pt-4">
          {/* Session Date Confirmation */}
          <div className="bg-gray-50 p-4 rounded-lg">
            <Label htmlFor="session_date" className="text-sm font-medium flex items-center gap-2">
              <Calendar className="w-4 h-4" />
              Confirm Session Date <span className="text-red-500">*</span>
            </Label>
            <p className="text-xs text-gray-500 mb-2">Please confirm the actual date of your Kambo session</p>
            <Input
              id="session_date"
              type="date"
              value={reviewData.session_date}
              onChange={(e) => setReviewData(prev => ({...prev, session_date: e.target.value}))}
              required
              className="mt-2"
            />
          </div>

          <Separator />

          {/* Rating Section */}
          <div className="space-y-6">
            <h3 className="text-lg font-semibold text-gray-900">Rate Your Experience</h3>

            <StarRating
              label="Overall Experience"
              description="Your general satisfaction with the session"
              rating={reviewData.overall_rating}
              onRatingChange={(rating) => setReviewData(prev => ({...prev, overall_rating: rating}))}
              required={true}
            />

            <div className="grid md:grid-cols-2 gap-6">
              <StarRating
                label="Safety & Protocols"
                description="How safe you felt during the session"
                rating={reviewData.safety_rating}
                onRatingChange={(rating) => setReviewData(prev => ({...prev, safety_rating: rating}))}
              />

              <StarRating
                label="Communication"
                description="Clarity of instructions and guidance"
                rating={reviewData.communication_rating}
                onRatingChange={(rating) => setReviewData(prev => ({...prev, communication_rating: rating}))}
              />

              <StarRating
                label="Environment"
                description="Comfort and cleanliness of the space"
                rating={reviewData.environment_rating}
                onRatingChange={(rating) => setReviewData(prev => ({...prev, environment_rating: rating}))}
              />

              <StarRating
                label="Professionalism"
                description="Practitioner's conduct and expertise"
                rating={reviewData.professionalism_rating}
                onRatingChange={(rating) => setReviewData(prev => ({...prev, professionalism_rating: rating}))}
              />
            </div>
          </div>

          <Separator />

          {/* Recommendation Section */}
          <div>
            <Label className="text-base font-semibold mb-3 block">
              Would you recommend this practitioner? <span className="text-red-500">*</span>
            </Label>
            <div className="flex gap-4">
              <button 
                type="button" 
                onClick={() => setReviewData(prev => ({...prev, would_recommend: true}))}
                className={`flex items-center gap-2 px-6 py-3 rounded-lg border-2 transition-all ${
                  reviewData.would_recommend === true 
                    ? "bg-green-50 border-green-300 text-green-800 shadow-sm" 
                    : "bg-white border-gray-300 text-gray-700 hover:bg-gray-50"
                }`}
              >
                <CheckCircle className="w-5 h-5" /> 
                Yes, I would recommend
              </button>

              <button 
                type="button" 
                onClick={() => setReviewData(prev => ({...prev, would_recommend: false}))}
                className={`flex items-center gap-2 px-6 py-3 rounded-lg border-2 transition-all ${
                  reviewData.would_recommend === false 
                    ? "bg-red-50 border-red-300 text-red-800 shadow-sm" 
                    : "bg-white border-gray-300 text-gray-700 hover:bg-gray-50"
                }`}
              >
                <XCircle className="w-5 h-5" /> 
                No, I would not recommend
              </button>
            </div>
          </div>

          <Separator />

          {/* Written Review */}
          <div>
            <Label htmlFor="review_text" className="text-base font-semibold">
              Your Review <span className="text-red-500">*</span>
            </Label>
            <p className="text-sm text-gray-500 mb-3">
              Share details about your experience to help others in the community
            </p>
            <Textarea
              id="review_text"
              value={reviewData.review_text}
              onChange={(e) => setReviewData(prev => ({...prev, review_text: e.target.value}))}
              placeholder="Describe your experience with this practitioner. What went well? What could be improved? How did you feel before, during, and after the session?"
              rows={5}
              required
            />
            <p className="text-xs text-gray-400 mt-1">
              {reviewData.review_text.length}/500 characters
            </p>
          </div>

          {/* Submit Buttons */}
          <div className="flex justify-end gap-3 pt-6 border-t">
            <Button 
              type="button" 
              variant="outline" 
              onClick={onClose} 
              disabled={isSubmitting}
            >
              Cancel
            </Button>
            <Button 
              type="submit" 
              disabled={isSubmitting} 
              className="bg-emerald-600 hover:bg-emerald-700"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin mr-2"/> 
                  Submitting...
                </>
              ) : (
                <>
                  <CheckCircle className="w-4 h-4 mr-2"/>
                  Submit Review
                </>
              )}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

components.practitioner/ProfileManagement:
import React, { useState } from "react";
import { Practitioner } from "@/entities/Practitioner";
import { UploadFile } from "@/integrations/Core";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { 
  Upload, Save, User, 
  Camera, Trash2, Plus, Info, CheckCircle, UserCircle 
} from "lucide-react";

export default function ProfileManagement({ practitioner, user, onUpdate }) {
  const [profileData, setProfileData] = useState({
    full_name: practitioner.full_name || "",
    email: practitioner.email || "",
    phone: practitioner.phone || "",
    address: practitioner.address || { street: "", city: "", state_province: "", postal_code: "", country: "" },
    bio: practitioner.bio || "",
    years_experience: practitioner.years_experience || 0,
    pricing_range: practitioner.pricing_range || "$",
    website_url: practitioner.website_url || "",
    specializations: practitioner.specializations || [],
    languages: practitioner.languages || ["English"],
    safety_protocols: practitioner.safety_protocols || "",
    training_background: practitioner.training_background || "",
    why_practitioner: practitioner.why_practitioner || "",
    profile_image_url: practitioner.profile_image_url || "",
    image_urls: practitioner.image_urls || []
  });
  const [isUploading, setIsUploading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [newSpecialization, setNewSpecialization] = useState("");
  const [newLanguage, setNewLanguage] = useState("");

  const handleProfileImageUpload = async (event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    console.log("Uploading profile image:", file.name);
    setIsUploading(true);
    try {
      const { file_url } = await UploadFile({ file });
      console.log("Upload successful, URL:", file_url);

      // Update local state
      setProfileData(prev => ({ ...prev, profile_image_url: file_url }));

      // Save to database immediately
      await Practitioner.update(practitioner.id, { profile_image_url: file_url });
      console.log("Profile image saved to database");

      // Refresh parent component
      onUpdate();
    } catch (error) {
      console.error("Failed to upload profile image:", error);
      alert("Failed to upload image. Please try again.");
    } finally {
      setIsUploading(false);
      // Clear the file input
      event.target.value = '';
    }
  };

  const handleGalleryImageUpload = async (event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    console.log("Uploading gallery image:", file.name);
    setIsUploading(true);
    try {
      const { file_url } = await UploadFile({ file });
      console.log("Upload successful, URL:", file_url);

      // Update local state
      const newImageUrls = [...profileData.image_urls, file_url];
      setProfileData(prev => ({ ...prev, image_urls: newImageUrls }));

      // Save to database immediately
      await Practitioner.update(practitioner.id, { image_urls: newImageUrls });
      console.log("Gallery image saved to database");

      // Refresh parent component
      onUpdate();
    } catch (error) {
      console.error("Failed to upload gallery image:", error);
      alert("Failed to upload image. Please try again.");
    } finally {
      setIsUploading(false);
      // Clear the file input
      event.target.value = '';
    }
  };

  const handleRemoveImage = async (index) => {
    try {
      const updatedUrls = profileData.image_urls.filter((_, i) => i !== index);

      // Update local state
      setProfileData(prev => ({ ...prev, image_urls: updatedUrls }));

      // Save to database immediately
      await Practitioner.update(practitioner.id, { image_urls: updatedUrls });
      console.log("Gallery image removed from database");

      // Refresh parent component
      onUpdate();
    } catch (error) {
      console.error("Failed to remove image:", error);
      alert("Failed to remove image. Please try again.");
      // Revert state if save fails
      setProfileData(prev => ({ ...prev, image_urls: practitioner.image_urls || [] }));
    }
  };

  const addSpecialization = () => {
    if (newSpecialization.trim() && !profileData.specializations.includes(newSpecialization.trim())) {
      setProfileData(prev => ({
        ...prev,
        specializations: [...prev.specializations, newSpecialization.trim()]
      }));
      setNewSpecialization("");
    }
  };

  const removeSpecialization = (index) => {
    setProfileData(prev => ({
      ...prev,
      specializations: prev.specializations.filter((_, i) => i !== index)
    }));
  };

  const addLanguage = () => {
    if (newLanguage.trim() && !profileData.languages.includes(newLanguage.trim())) {
      setProfileData(prev => ({
        ...prev,
        languages: [...prev.languages, newLanguage.trim()]
      }));
      setNewLanguage("");
    }
  };

  const removeLanguage = (index) => {
    if (profileData.languages.length > 1) {
      setProfileData(prev => ({
        ...prev,
        languages: prev.languages.filter((_, i) => i !== index)
      }));
    }
  };

  const handleAddressChange = (e) => {
    const { name, value } = e.target;
    setProfileData(prev => ({
      ...prev,
      address: {
        ...prev.address,
        [name]: value
      }
    }));
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await Practitioner.update(practitioner.id, profileData);
      onUpdate();
    } catch (error) {
      console.error("Failed to save profile:", error);
      alert("Failed to save profile. Please try again.");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <Alert>
        <Info className="h-4 w-4" />
        <AlertDescription>
          Photos are saved instantly when uploaded. Other profile changes require clicking "Save Changes" at the bottom.
        </AlertDescription>
      </Alert>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Profile Image Section */}
        <div className="lg:col-span-1">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Camera className="w-5 h-5" />
                Profile Photo
              </CardTitle>
            </CardHeader>
            <CardContent className="text-center space-y-4">
              <div className="w-32 h-32 rounded-full bg-gray-100 overflow-hidden mx-auto">
                {profileData.profile_image_url ? (
                  <img 
                    src={profileData.profile_image_url} 
                    alt="Profile"
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-gray-100">
                    <UserCircle className="w-24 h-24 text-gray-400" />
                  </div>
                )}
              </div>
              <div>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleProfileImageUpload}
                  className="hidden"
                  id="profile-upload"
                />
                <label htmlFor="profile-upload">
                  <Button disabled={isUploading} className="cursor-pointer" asChild>
                    <span>
                      <Upload className="w-4 h-4 mr-2" />
                      {isUploading ? "Uploading..." : "Change Photo"}
                    </span>
                  </Button>
                </label>
              </div>
              <div className="flex items-center justify-center gap-2">
                <CheckCircle className="w-4 h-4 text-green-600" />
                <span className="text-sm text-green-600">Verified Practitioner</span>
              </div>
            </CardContent>
          </Card>

          {/* Gallery Images */}
          <Card className="mt-6">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Camera className="w-5 h-5" />
                Gallery Images
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                {profileData.image_urls.map((url, index) => (
                  <div key={index} className="relative">
                    <img 
                      src={url} 
                      alt={`Gallery ${index + 1}`}
                      className="w-full h-20 object-cover rounded-lg"
                    />
                    <Button
                      size="icon"
                      variant="destructive"
                      className="absolute top-1 right-1 w-6 h-6"
                      onClick={() => handleRemoveImage(index)}
                    >
                      <Trash2 className="w-3 h-3" />
                    </Button>
                  </div>
                ))}
              </div>
              <div>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleGalleryImageUpload}
                  className="hidden"
                  id="gallery-upload"
                />
                <label htmlFor="gallery-upload">
                  <Button variant="outline" disabled={isUploading} className="w-full cursor-pointer" asChild>
                    <span>
                      <Plus className="w-4 h-4 mr-2" />
                      {isUploading ? "Uploading..." : "Add Photo"}
                    </span>
                  </Button>
                </label>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Profile Details */}
        <div className="lg:col-span-2 space-y-6">
          {/* Basic Information */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="w-5 h-5" />
                Basic Information
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="name">Full Name</Label>
                  <Input
                    id="name"
                    value={profileData.full_name}
                    onChange={(e) => setProfileData(prev => ({...prev, full_name: e.target.value}))}
                  />
                </div>
                <div>
                  <Label htmlFor="email">Email Address</Label>
                  <Input
                    id="email"
                    value={profileData.email}
                    disabled
                    className="bg-gray-50"
                  />
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="phone">Phone Number</Label>
                  <Input
                    id="phone"
                    value={profileData.phone}
                    onChange={(e) => setProfileData(prev => ({...prev, phone: e.target.value}))}
                  />
                </div>
                <div>
                  <Label htmlFor="country">Country</Label>
                  <Input
                    id="country"
                    name="country"
                    value={profileData.address.country || ""}
                    onChange={handleAddressChange}
                    placeholder="e.g., USA"
                  />
                </div>
              </div>

              <div>
                  <Label>Full Address</Label>
                  <div className="space-y-2">
                      <Input name="street" value={profileData.address.street || ""} onChange={handleAddressChange} placeholder="Street Address" />
                      <div className="grid md:grid-cols-2 gap-4">
                           <Input name="city" value={profileData.address.city || ""} onChange={handleAddressChange} placeholder="City" />
                           <Input name="state_province" value={profileData.address.state_province || ""} onChange={handleAddressChange} placeholder="State / Province" />
                      </div>
                      <Input name="postal_code" value={profileData.address.postal_code || ""} onChange={handleAddressChange} placeholder="Postal / ZIP Code" />
                  </div>
              </div>

              <div>
                <Label htmlFor="website">Website</Label>
                <Input
                  id="website"
                  value={profileData.website_url}
                  onChange={(e) => setProfileData(prev => ({...prev, website_url: e.target.value}))}
                  placeholder="https://yourwebsite.com"
                />
              </div>
            </CardContent>
          </Card>

          {/* Professional Details */}
          <Card>
            <CardHeader>
              <CardTitle>Professional Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <Label htmlFor="bio">Professional Bio</Label>
                <Textarea
                  id="bio"
                  value={profileData.bio}
                  onChange={(e) => setProfileData(prev => ({...prev, bio: e.target.value}))}
                  rows={4}
                  placeholder="Tell clients about your approach and experience..."
                />
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="experience">Years of Experience</Label>
                  <Input
                    id="experience"
                    type="number"
                    value={profileData.years_experience}
                    onChange={(e) => setProfileData(prev => ({...prev, years_experience: parseInt(e.target.value) || 0}))}
                  />
                </div>
                <div>
                  <Label htmlFor="pricing">Pricing Range</Label>
                  <Select 
                    value={profileData.pricing_range} 
                    onValueChange={(value) => setProfileData(prev => ({...prev, pricing_range: value}))}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="$">$ (Under $100)</SelectItem>
                      <SelectItem value="$$">$$ ($100-200)</SelectItem>
                      <SelectItem value="$$$">$$$ ($200-350)</SelectItem>
                      <SelectItem value="$$$$">$$$$ ($350+)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Specializations */}
              <div>
                <Label>Specializations</Label>
                <div className="flex flex-wrap gap-2 mb-2">
                  {profileData.specializations.map((spec, index) => (
                    <Badge key={index} variant="secondary" className="flex items-center gap-1">
                      {spec}
                      <Button
                        size="sm"
                        variant="ghost"
                        className="h-auto p-0 w-4 h-4"
                        onClick={() => removeSpecialization(index)}
                      >
                        <Trash2 className="w-3 h-3" />
                      </Button>
                    </Badge>
                  ))}
                </div>
                <div className="flex gap-2">
                  <Input
                    value={newSpecialization}
                    onChange={(e) => setNewSpecialization(e.target.value)}
                    placeholder="Add specialization"
                    onKeyPress={(e) => e.key === 'Enter' && addSpecialization()}
                  />
                  <Button onClick={addSpecialization}>Add</Button>
                </div>
              </div>

              {/* Languages */}
              <div>
                <Label>Languages</Label>
                <div className="flex flex-wrap gap-2 mb-2">
                  {profileData.languages.map((lang, index) => (
                    <Badge key={index} variant="outline" className="flex items-center gap-1">
                      {lang}
                      {profileData.languages.length > 1 && (
                        <Button
                          size="sm"
                          variant="ghost"
                          className="h-auto p-0 w-4 h-4"
                          onClick={() => removeLanguage(index)}
                        >
                          <Trash2 className="w-3 h-3" />
                        </Button>
                      )}
                    </Badge>
                  ))}
                </div>
                <div className="flex gap-2">
                  <Input
                    value={newLanguage}
                    onChange={(e) => setNewLanguage(e.target.value)}
                    placeholder="Add language"
                    onKeyPress={(e) => e.key === 'Enter' && addLanguage()}
                  />
                  <Button onClick={addLanguage}>Add</Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Extended Details */}
          <Card>
            <CardHeader>
              <CardTitle>Extended Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <Label htmlFor="training">Training Background</Label>
                <Textarea
                  id="training"
                  value={profileData.training_background}
                  onChange={(e) => setProfileData(prev => ({...prev, training_background: e.target.value}))}
                  rows={3}
                  placeholder="Describe your training, certifications, and learning path..."
                />
              </div>

              <div>
                <Label htmlFor="why">Why You Practice</Label>
                <Textarea
                  id="why"
                  value={profileData.why_practitioner}
                  onChange={(e) => setProfileData(prev => ({...prev, why_practitioner: e.target.value}))}
                  rows={3}
                  placeholder="Share your personal journey and motivation..."
                />
              </div>

              <div>
                <Label htmlFor="safety">Safety Protocols</Label>
                <Textarea
                  id="safety"
                  value={profileData.safety_protocols}
                  onChange={(e) => setProfileData(prev => ({...prev, safety_protocols: e.target.value}))}
                  rows={3}
                  placeholder="Describe your safety measures and protocols..."
                />
              </div>
            </CardContent>
          </Card>

          {/* Save Button */}
          <div className="flex justify-end">
            <Button 
              onClick={handleSave}
              disabled={isSaving}
              className="bg-emerald-600 hover:bg-emerald-700"
            >
              <Save className="w-4 h-4 mr-2" />
              {isSaving ? "Saving..." : "Save Changes"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

components.practitioner/BookingCalendar:
import React, { useState } from 'react';
import { Booking, Message, Conversation } from "@/entities/all";
import { SendEmail } from "@/integrations/Core";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  format,
  addMonths,
  subMonths,
  startOfMonth,
  endOfMonth,
  eachDayOfInterval,
  isSameDay,
  isSameMonth
} from "date-fns";
import {
  Calendar, ChevronLeft, ChevronRight, Check, X,
  Mail, Phone, User, MessageSquare
} from "lucide-react";

export default function BookingCalendar({ bookings, practitioner, onUpdate }) {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [isUpdating, setIsUpdating] = useState(false);

  const updateBookingStatus = async (bookingId, status) => {
    setIsUpdating(true);
    try {
      await Booking.update(bookingId, { status });
      const booking = bookings.find(b => b.id === bookingId);

      if (booking) {
        // If confirmed, ensure a conversation exists
        if (status === 'confirmed') {
          const existingConversations = await Conversation.filter({ related_booking_id: bookingId });
          if (existingConversations.length === 0) {
            await Conversation.create({
              participant_1_id: practitioner.id,
              participant_2_id: booking.client_id,
              participant_1_name: practitioner.full_name,
              participant_2_name: booking.client_name,
              related_booking_id: bookingId,
              last_message: "Booking confirmed. You can now chat with your practitioner.",
              last_message_date: new Date().toISOString()
            });
          }
        }

        // Send automated email notification
        await sendStatusEmail(booking, status);

        // Create system message
        const conversation = (await Conversation.filter({ related_booking_id: bookingId }))[0];
        if (conversation) {
            await Message.create({
              conversation_id: conversation.id,
              booking_id: bookingId,
              sender_id: 'system',
              receiver_id: booking.client_id || 'system',
              sender_name: 'System',
              content: `Booking status updated to: ${status}`,
              message_type: 'system'
            });
        }
      }

      onUpdate();
    } catch (error) {
      console.error("Failed to update booking:", error);
    } finally {
      setIsUpdating(false);
    }
  };

  const sendStatusEmail = async (booking, status) => {
    const emailSubject = `Booking ${status.charAt(0).toUpperCase() + status.slice(1)} - ${practitioner.full_name}`;
    const emailContent = getEmailContent(booking, status);

    try {
      await SendEmail({
        to: booking.client_email,
        subject: emailSubject,
        body: emailContent
      });
    } catch (error) {
      console.error("Failed to send email:", error);
    }
  };

  const getEmailContent = (booking, status) => {
    const baseMessage = `Dear ${booking.client_name},\n\n`;

    switch (status) {
      case 'confirmed':
        return `${baseMessage}Great news! Your Kambo session request has been confirmed.\n\nSession Details:\n- Date: ${format(new Date(booking.requested_date), 'PPP')}\n- Service: ${booking.service_type}\n- Practitioner: ${practitioner.full_name}\n\nI will be in touch soon to arrange the final details and location.\n\nLooking forward to our session together!\n\nBest regards,\n${practitioner.full_name}`;

      case 'declined':
        return `${baseMessage}Thank you for your interest in booking a session with me.\n\nUnfortunately, I'm unable to accommodate your request for ${format(new Date(booking.requested_date), 'PPP')}. This could be due to scheduling conflicts or other commitments.\n\nI encourage you to reach out with alternative dates, or feel free to browse other practitioners in our directory.\n\nWishing you well on your healing journey,\n${practitioner.full_name}`;

      case 'completed':
        return `${baseMessage}Thank you for participating in our Kambo session. I hope it was a meaningful and healing experience for you.\n\nPlease take time to rest and integrate in the coming days. Remember to stay hydrated and be gentle with yourself.\n\nIf you'd like to share feedback or have any questions about your experience, please don't hesitate to reach out.\n\nWith gratitude,\n${practitioner.full_name}`;

      default:
        return `${baseMessage}Your booking status has been updated to: ${status}.\n\nBest regards,\n${practitioner.full_name}`;
    }
  };

  const getBookingsForDate = (date) => {
    return bookings.filter(booking => {
      try {
        return isSameDay(new Date(booking.requested_date), date);
      } catch (error) {
        return false;
      }
    });
  };

  const getStatusColor = (status) => {
    const colors = {
      pending: "bg-yellow-100 text-yellow-800 border-yellow-200",
      confirmed: "bg-green-100 text-green-800 border-green-200",
      declined: "bg-red-100 text-red-800 border-red-200",
      completed: "bg-blue-100 text-blue-800 border-blue-200",
    };
    return colors[status] || colors.pending;
  };

  const StatusBadge = ({ status }) => (
    <Badge className={getStatusColor(status)}>{status}</Badge>
  );

  return (
    <div className="space-y-6">
      {/* Calendar View */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <Calendar className="w-5 h-5" />
              Booking Calendar - {format(currentMonth, 'MMMM yyyy')}
            </CardTitle>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={() => setCurrentMonth(prev => subMonths(prev, 1))}
              >
                <ChevronLeft className="w-4 h-4" />
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setCurrentMonth(prev => addMonths(prev, 1))}
              >
                <ChevronRight className="w-4 h-4" />
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          {/* Calendar Grid */}
          <div className="grid grid-cols-7 gap-1">
            {/* Day Headers */}
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
              <div key={day} className="p-3 text-center font-medium text-gray-600 text-sm">
                {day}
              </div>
            ))}

            {/* Calendar Days */}
            {eachDayOfInterval({
              start: (() => {
                const monthStart = startOfMonth(currentMonth);
                const startDate = new Date(monthStart);
                startDate.setDate(startDate.getDate() - monthStart.getDay());
                return startDate;
              })(),
              end: (() => {
                const monthEnd = endOfMonth(currentMonth);
                const endDate = new Date(monthEnd);
                endDate.setDate(endDate.getDate() + (6 - endDate.getDay()));
                return endDate;
              })()
            }).map(day => {
              const dayBookings = getBookingsForDate(day);
              const isCurrentMonth = isSameMonth(day, currentMonth);
              const isToday = isSameDay(day, new Date());

              return (
                <div
                  key={day.toISOString()}
                  className={`min-h-[100px] p-2 border border-gray-100 rounded-lg ${
                    isCurrentMonth ? 'bg-white' : 'bg-gray-50'
                  } ${isToday ? 'ring-2 ring-emerald-500' : ''}`}
                >
                  <div className={`text-sm font-medium mb-1 ${
                    isCurrentMonth ? 'text-gray-900' : 'text-gray-400'
                  } ${isToday ? 'text-emerald-600 font-bold' : ''}`}>
                    {format(day, 'd')}
                  </div>

                  <div className="space-y-1">
                    {dayBookings.map(booking => (
                      <div
                        key={booking.id}
                        className={`text-xs p-1 rounded text-white cursor-pointer truncate ${
                          booking.status === 'confirmed' ? 'bg-green-500 hover:bg-green-600' :
                          booking.status === 'pending' ? 'bg-yellow-500 hover:bg-yellow-600' :
                          booking.status === 'declined' ? 'bg-red-500 hover:bg-red-600' :
                          'bg-blue-500 hover:bg-blue-600'
                        }`}
                        title={`${booking.client_name} - ${booking.service_type} - ${booking.status}`}
                        onClick={() => setSelectedBooking(booking)}
                      >
                        {booking.client_name}
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* Booking Details Modal */}
      {selectedBooking && (
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>Booking Details</CardTitle>
              <Button
                variant="ghost"
                onClick={() => setSelectedBooking(null)}
              >
                Close
              </Button>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <h4 className="font-semibold text-gray-900 mb-2 flex items-center gap-2">
                  <User className="w-4 h-4" />
                  Client Information
                </h4>
                <div className="space-y-1 text-sm">
                  <p><strong>Name:</strong> {selectedBooking.client_name}</p>
                  <p><strong>Email:</strong> {selectedBooking.client_email}</p>
                  {selectedBooking.client_phone && (
                    <p><strong>Phone:</strong> {selectedBooking.client_phone}</p>
                  )}
                </div>
              </div>

              <div>
                <h4 className="font-semibold text-gray-900 mb-2 flex items-center gap-2">
                  <Calendar className="w-4 h-4" />
                  Session Details
                </h4>
                <div className="space-y-1 text-sm">
                  <p><strong>Date:</strong> {format(new Date(selectedBooking.requested_date), 'PPP')}</p>
                  <p><strong>Service:</strong> {selectedBooking.service_type}</p>
                  <p><strong>Status:</strong> <StatusBadge status={selectedBooking.status} /></p>
                </div>
              </div>
            </div>

            {selectedBooking.message && (
              <div>
                <h4 className="font-semibold text-gray-900 mb-2 flex items-center gap-2">
                  <MessageSquare className="w-4 h-4" />
                  Client Message
                </h4>
                <p className="text-sm text-gray-700 bg-gray-50 p-3 rounded-lg">
                  {selectedBooking.message}
                </p>
              </div>
            )}

            {/* Action Buttons */}
            <div className="flex flex-wrap gap-2 pt-4 border-t">
              {selectedBooking.status === 'pending' && (
                <>
                  <Button
                    onClick={() => updateBookingStatus(selectedBooking.id, 'confirmed')}
                    disabled={isUpdating}
                    className="bg-green-600 hover:bg-green-700"
                  >
                    <Check className="w-4 h-4 mr-2" />
                    Confirm
                  </Button>
                  <Button
                    variant="destructive"
                    onClick={() => updateBookingStatus(selectedBooking.id, 'declined')}
                    disabled={isUpdating}
                  >
                    <X className="w-4 h-4 mr-2" />
                    Decline
                  </Button>
                </>
              )}

              {selectedBooking.status === 'confirmed' && (
                <Button
                  onClick={() => updateBookingStatus(selectedBooking.id, 'completed')}
                  disabled={isUpdating}
                  className="bg-blue-600 hover:bg-blue-700"
                >
                  <Check className="w-4 h-4 mr-2" />
                  Mark Completed
                </Button>
              )}

              <Button
                variant="outline"
                onClick={() => window.open(`mailto:${selectedBooking.client_email}`, '_blank')}
              >
                <Mail className="w-4 h-4 mr-2" />
                Email Client
              </Button>

              {selectedBooking.client_phone && (
                <Button
                  variant="outline"
                  onClick={() => window.open(`tel:${selectedBooking.client_phone}`, '_blank')}
                >
                  <Phone className="w-4 h-4 mr-2" />
                  Call Client
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {['pending', 'confirmed', 'completed', 'declined'].map(status => {
          const count = bookings.filter(b => b.status === status).length;
          return (
            <Card key={status}>
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-gray-900">{count}</div>
                <div className="text-sm text-gray-600 capitalize">{status}</div>
              </CardContent>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

components.practitioner/MessagingCenter:
import React, { useState } from 'react';
import { Message, Conversation } from "@/entities/all";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { MessageSquare, Send, User as UserIcon } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { NotificationService } from '../notifications/NotificationService';

export default function MessagingCenter({ messages, practitioner, bookings, onUpdate }) {
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [newMessage, setNewMessage] = useState("");
  const [isSending, setIsSending] = useState(false);

  // Group messages by booking
  const messagesByBooking = messages.reduce((acc, message) => {
    if (!acc[message.booking_id]) {
      acc[message.booking_id] = [];
    }
    acc[message.booking_id].push(message);
    return acc;
  }, {});

  const sendMessage = async () => {
    if (!newMessage.trim() || !selectedBooking) return;

    setIsSending(true);
    try {
      // Find or create conversation for this booking
      let conversations = await Conversation.filter({ related_booking_id: selectedBooking.id });
      let conversation;

      if (conversations.length === 0) {
        // Create conversation if it doesn't exist
        conversation = await Conversation.create({
          participant_1_id: practitioner.id,
          // If the client_id is not available or for self-messaging, default to practitioner's ID for participant_2
          participant_2_id: selectedBooking.client_id || practitioner.id, 
          participant_1_name: practitioner.full_name,
          participant_2_name: selectedBooking.client_name,
          related_booking_id: selectedBooking.id,
          last_message: newMessage.trim(),
          last_message_date: new Date().toISOString()
        });
      } else {
        conversation = conversations[0];
      }

      // 1. Create the message
      const createdMessage = await Message.create({
        conversation_id: conversation.id,
        booking_id: selectedBooking.id,
        sender_id: practitioner.id,
        // If the client_id is not available or for self-messaging, default to practitioner's ID for receiver
        receiver_id: selectedBooking.client_id || practitioner.id, 
        sender_name: practitioner.full_name,
        content: newMessage.trim(),
        // Auto-mark as read if the sender is also the effective receiver (self-messaging)
        is_read: selectedBooking.client_id === practitioner.id 
      });

      // 2. Update the conversation
      await Conversation.update(conversation.id, {
        last_message: newMessage.trim(),
        last_message_date: new Date().toISOString()
      });

      // 3. Create notification (only if not self-messaging)
      if (selectedBooking.client_id && selectedBooking.client_id !== practitioner.id) {
        await NotificationService.createMessageNotification(selectedBooking.client_id, {
            sender_name: practitioner.full_name,
            content: newMessage.trim(),
            conversation_id: conversation.id
        });
      }

      setNewMessage("");
      onUpdate(); // This should trigger a refresh of messages
    } catch (error) {
      console.error("Failed to send message:", error);
      alert("Failed to send message. Please try again.");
    } finally {
      setIsSending(false);
    }
  };

  const markAsRead = async (messageId) => {
    try {
      await Message.update(messageId, { is_read: true });
      onUpdate();
    } catch (error) {
      console.error("Failed to mark message as read:", error);
    }
  };

  const getBookingMessages = (bookingId) => {
    return messagesByBooking[bookingId] || [];
  };

  const getUnreadCount = (bookingId) => {
    // Count unread messages that were sent TO the practitioner (i.e., practitioner is receiver or sender is not practitioner)
    return getBookingMessages(bookingId).filter(m => !m.is_read && m.sender_id !== practitioner.id).length;
  };

  return (
    <div className="grid lg:grid-cols-3 gap-6 h-[600px]">
      {/* Conversation List */}
      <div className="lg:col-span-1">
        <Card className="h-full">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MessageSquare className="w-5 h-5" />
              Conversations ({bookings.length})
            </CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <div className="space-y-1 max-h-[500px] overflow-y-auto">
              {bookings.map(booking => {
                const unreadCount = getUnreadCount(booking.id);
                const lastMessage = getBookingMessages(booking.id)
                  .sort((a, b) => new Date(b.created_date) - new Date(a.created_date))[0];

                return (
                  <div
                    key={booking.id}
                    className={`p-4 border-b cursor-pointer hover:bg-gray-50 transition-colors ${
                      selectedBooking?.id === booking.id ? 'bg-emerald-50 border-emerald-200' : ''
                    }`}
                    onClick={() => setSelectedBooking(booking)}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <div className="flex items-center gap-2">
                          <UserIcon className="w-4 h-4 text-gray-400" />
                          <span className="font-medium text-sm">{booking.client_name}</span>
                          {unreadCount > 0 && (
                            <Badge className="bg-red-500 text-white text-xs">{unreadCount}</Badge>
                          )}
                        </div>
                        <p className="text-xs text-gray-600 mt-1">
                          {booking.service_type} - {new Date(booking.requested_date).toLocaleDateString()}
                        </p>
                        {lastMessage && (
                          <p className="text-xs text-gray-500 mt-1 truncate">
                            {lastMessage.content.substring(0, 50)}...
                          </p>
                        )}
                      </div>
                      {lastMessage && (
                        <span className="text-xs text-gray-400">
                          {formatDistanceToNow(new Date(lastMessage.created_date), { addSuffix: true })}
                        </span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Message Thread */}
      <div className="lg:col-span-2">
        <Card className="h-full flex flex-col">
          {selectedBooking ? (
            <>
              <CardHeader>
                <CardTitle className="text-lg">
                  Chat with {selectedBooking.client_name}
                </CardTitle>
                <p className="text-sm text-gray-600">
                  {selectedBooking.service_type} - {new Date(selectedBooking.requested_date).toLocaleDateString()}
                </p>
              </CardHeader>

              {/* Messages */}
              <CardContent className="flex-1 flex flex-col">
                <div className="flex-1 space-y-4 max-h-[350px] overflow-y-auto mb-4">
                  {getBookingMessages(selectedBooking.id)
                    .sort((a, b) => new Date(a.created_date) - new Date(b.created_date))
                    .map(message => (
                    <div 
                      key={message.id}
                      className={`flex ${
                        message.sender_id === practitioner.id ? 'justify-end' : 'justify-start'
                      }`}
                    >
                      <div 
                        className={`max-w-[70%] rounded-lg p-3 ${
                          message.sender_id === practitioner.id
                            ? 'bg-emerald-600 text-white'
                            : message.message_type === 'automated'
                            ? 'bg-gray-100 text-gray-600 border-l-4 border-blue-400'
                            : 'bg-gray-200 text-gray-900'
                        }`}
                        // Mark as read only if the message is from the other party and is unread
                        onClick={() => !message.is_read && message.sender_id !== practitioner.id && markAsRead(message.id)}
                      >
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-xs font-medium">
                            {message.sender_name}
                          </span>
                          <span className={`text-xs ${
                            message.sender_id === practitioner.id ? 'text-emerald-200' : 'text-gray-500'
                          }`}>
                            {formatDistanceToNow(new Date(message.created_date), { addSuffix: true })}
                          </span>
                        </div>
                        <p className="text-sm">{message.content}</p>
                        {/* Only show unread indicator for messages sent by others to the practitioner */}
                        {!message.is_read && message.sender_id !== practitioner.id && (
                          <div className="w-2 h-2 bg-blue-500 rounded-full mt-2 ml-auto"></div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>

                <Separator className="my-4" />

                {/* Message Input */}
                <div className="flex gap-2">
                  <Textarea
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    placeholder="Type your message..."
                    rows={2}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        sendMessage();
                      }
                    }}
                  />
                  <Button 
                    onClick={sendMessage} 
                    disabled={isSending || !newMessage.trim()}
                    className="bg-emerald-600 hover:bg-emerald-700"
                  >
                    <Send className="w-4 h-4" />
                  </Button>
                </div>
              </CardContent>
            </>
          ) : (
            <CardContent className="flex-1 flex items-center justify-center">
              <div className="text-center">
                <MessageSquare className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-gray-800 mb-2">Select a Conversation</h3>
                <p className="text-gray-500">Choose a booking to start messaging with your client</p>
              </div>
            </CardContent>
          )}
        </Card>
      </div>
    </div>
  );
}

components.practitioner/EventManagement:
import React, { useState } from 'react';
import { Event, Favorite, Notification } from "@/entities/all";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { 
  Plus, Calendar, MapPin, Users, DollarSign, Edit, Trash2, 
  Clock, Globe, Video 
} from "lucide-react";
import { format } from "date-fns";
import { createPageUrl } from '@/utils';

export default function EventManagement({ events, practitioner, onUpdate }) {
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [editingEvent, setEditingEvent] = useState(null);
  const [eventData, setEventData] = useState({
    title: "",
    description: "",
    event_type: "circle",
    start_date: "",
    end_date: "",
    location: "",
    price: 100,
    max_participants: 8,
    is_online: false,
    requirements: [],
    what_to_bring: []
  });

  const resetForm = () => {
    setEventData({
      title: "",
      description: "",
      event_type: "circle",
      start_date: "",
      end_date: "",
      location: "",
      price: 100,
      max_participants: 8,
      is_online: false,
      requirements: [],
      what_to_bring: []
    });
    setEditingEvent(null);
    setShowCreateForm(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const eventPayload = {
        ...eventData,
        practitioner_id: practitioner.id,
        start_date: new Date(eventData.start_date).toISOString(),
        end_date: new Date(eventData.end_date).toISOString()
      };

      if (editingEvent) {
        await Event.update(editingEvent.id, eventPayload);
      } else {
        const newEvent = await Event.create(eventPayload);

        // Notify users who have favorited this practitioner
        const favorites = await Favorite.filter({ 
            item_id: practitioner.id, 
            item_type: 'practitioner' 
        });

        for (const fav of favorites) {
            await Notification.create({
                user_id: fav.user_id,
                title: `New Event from ${practitioner.full_name}`,
                message: `Check out the new event: "${newEvent.title}"`,
                type: 'event',
                related_id: newEvent.id,
                action_url: createPageUrl(`Events`),
                sender_image_url: practitioner.profile_image_url || null
            });
        }
      }

      resetForm();
      onUpdate();
    } catch (error) {
      console.error("Failed to save event:", error);
    }
  };

  const handleEdit = (event) => {
    setEventData({
      title: event.title,
      description: event.description || "",
      event_type: event.event_type,
      start_date: new Date(event.start_date).toISOString().slice(0, 16),
      end_date: new Date(event.end_date).toISOString().slice(0, 16),
      location: event.location,
      price: event.price,
      max_participants: event.max_participants,
      is_online: event.is_online || false,
      requirements: event.requirements || [],
      what_to_bring: event.what_to_bring || []
    });
    setEditingEvent(event);
    setShowCreateForm(true);
  };

  const handleDelete = async (eventId) => {
    if (window.confirm("Are you sure you want to delete this event?")) {
      try {
        await Event.delete(eventId);
        onUpdate();
      } catch (error) {
        console.error("Failed to delete event:", error);
      }
    }
  };

  const getEventTypeBadge = (type) => {
    const badges = {
      circle: { color: "bg-emerald-100 text-emerald-800", text: "Kambo Circle" },
      workshop: { color: "bg-blue-100 text-blue-800", text: "Workshop" },
      retreat: { color: "bg-purple-100 text-purple-800", text: "Retreat" },
      meetup: { color: "bg-orange-100 text-orange-800", text: "Meetup" },
      training: { color: "bg-red-100 text-red-800", text: "Training" }
    };
    return badges[type] || badges.circle;
  };

  const addListItem = (field, value) => {
    if (value.trim()) {
      setEventData(prev => ({
        ...prev,
        [field]: [...prev[field], value.trim()]
      }));
    }
  };

  const removeListItem = (field, index) => {
    setEventData(prev => ({
      ...prev,
      [field]: prev[field].filter((_, i) => i !== index)
    }));
  };

  // Mock payment integration - in real app, integrate with Stripe
  const handlePaymentSetup = async (eventId) => {
    // This would integrate with a real payment processor
    console.log("Setting up payment for event:", eventId);
    // For now, just show a success message
    alert("Payment integration would be set up here (Stripe, etc.)");
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold text-gray-900">My Events ({events.length})</h2>
        <Button 
          onClick={() => setShowCreateForm(true)}
          className="bg-emerald-600 hover:bg-emerald-700"
        >
          <Plus className="w-4 h-4 mr-2" />
          Create Event
        </Button>
      </div>

      {/* Create/Edit Form */}
      {showCreateForm && (
        <Card>
          <CardHeader>
            <CardTitle>
              {editingEvent ? 'Edit Event' : 'Create New Event'}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="title">Event Title</Label>
                  <Input
                    id="title"
                    value={eventData.title}
                    onChange={(e) => setEventData(prev => ({...prev, title: e.target.value}))}
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="type">Event Type</Label>
                  <Select 
                    value={eventData.event_type} 
                    onValueChange={(value) => setEventData(prev => ({...prev, event_type: value}))}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="circle">Kambo Circle</SelectItem>
                      <SelectItem value="workshop">Workshop</SelectItem>
                      <SelectItem value="retreat">Retreat</SelectItem>
                      <SelectItem value="meetup">Meetup</SelectItem>
                      <SelectItem value="training">Training</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div>
                <Label htmlFor="description">Description</Label>
                <Textarea
                  id="description"
                  value={eventData.description}
                  onChange={(e) => setEventData(prev => ({...prev, description: e.target.value}))}
                  rows={3}
                />
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="start_date">Start Date & Time</Label>
                  <Input
                    id="start_date"
                    type="datetime-local"
                    value={eventData.start_date}
                    onChange={(e) => setEventData(prev => ({...prev, start_date: e.target.value}))}
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="end_date">End Date & Time</Label>
                  <Input
                    id="end_date"
                    type="datetime-local"
                    value={eventData.end_date}
                    onChange={(e) => setEventData(prev => ({...prev, end_date: e.target.value}))}
                    required
                  />
                </div>
              </div>

              <div className="grid md:grid-cols-3 gap-4">
                <div>
                  <Label htmlFor="location">Location</Label>
                  <Input
                    id="location"
                    value={eventData.location}
                    onChange={(e) => setEventData(prev => ({...prev, location: e.target.value}))}
                    placeholder={eventData.is_online ? "Online" : "City, State"}
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="price">Price ($)</Label>
                  <Input
                    id="price"
                    type="number"
                    value={eventData.price}
                    onChange={(e) => setEventData(prev => ({...prev, price: parseFloat(e.target.value) || 0}))}
                    required
                  />
                </div>
                <div>
                  <Label htmlFor="max_participants">Max Participants</Label>
                  <Input
                    id="max_participants"
                    type="number"
                    value={eventData.max_participants}
                    onChange={(e) => setEventData(prev => ({...prev, max_participants: parseInt(e.target.value) || 8}))}
                    required
                  />
                </div>
              </div>

              <div className="flex items-center gap-2">
                <input
                  type="checkbox"
                  id="is_online"
                  checked={eventData.is_online}
                  onChange={(e) => setEventData(prev => ({...prev, is_online: e.target.checked}))}
                />
                <Label htmlFor="is_online">This is an online event</Label>
              </div>

              <div className="flex gap-3">
                <Button type="submit" className="bg-emerald-600 hover:bg-emerald-700">
                  {editingEvent ? 'Update Event' : 'Create Event'}
                </Button>
                <Button type="button" variant="outline" onClick={resetForm}>
                  Cancel
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      )}

      {/* Events List */}
      <div className="grid lg:grid-cols-2 gap-6">
        {events.map(event => {
          const badge = getEventTypeBadge(event.event_type);
          const isUpcoming = new Date(event.start_date) > new Date();
          const spotsLeft = event.max_participants - (event.current_participants || 0);

          return (
            <Card key={event.id} className="relative">
              <CardHeader>
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                      <Badge className={`${badge.color} border`}>
                        {badge.text}
                      </Badge>
                      {event.is_online && (
                        <Badge className="bg-blue-100 text-blue-800 border-blue-200 flex items-center gap-1">
                          <Video className="w-3 h-3" />
                          Online
                        </Badge>
                      )}
                      {!isUpcoming && (
                        <Badge className="bg-gray-100 text-gray-800">Past Event</Badge>
                      )}
                    </div>
                    <CardTitle className="text-lg">{event.title}</CardTitle>
                  </div>
                  <div className="flex gap-2">
                    <Button 
                      variant="ghost" 
                      size="icon"
                      onClick={() => handleEdit(event)}
                    >
                      <Edit className="w-4 h-4" />
                    </Button>
                    <Button 
                      variant="ghost" 
                      size="icon"
                      onClick={() => handleDelete(event.id)}
                      className="text-red-600 hover:text-red-700"
                    >
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </CardHeader>

              <CardContent className="space-y-3">
                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4 text-emerald-600" />
                    <span>{format(new Date(event.start_date), "MMM d, yyyy")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Clock className="w-4 h-4 text-emerald-600" />
                    <span>{format(new Date(event.start_date), "h:mm a")}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    {event.is_online ? (
                      <Globe className="w-4 h-4 text-emerald-600" />
                    ) : (
                      <MapPin className="w-4 h-4 text-emerald-600" />
                    )}
                    <span className="truncate">{event.location}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <DollarSign className="w-4 h-4 text-emerald-600" />
                    <span>${event.price}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between pt-3 border-t">
                  <div className="flex items-center gap-2 text-sm">
                    <Users className="w-4 h-4 text-gray-600" />
                    <span>{event.current_participants || 0}/{event.max_participants} spots</span>
                    {spotsLeft <= 2 && spotsLeft > 0 && (
                      <Badge className="bg-orange-100 text-orange-800">
                        {spotsLeft} left!
                      </Badge>
                    )}
                  </div>

                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handlePaymentSetup(event.id)}
                  >
                    <DollarSign className="w-4 h-4 mr-2" />
                    Payment Setup
                  </Button>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {events.length === 0 && !showCreateForm && (
        <Card>
          <CardContent className="text-center py-12">
            <Calendar className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-800 mb-2">No Events Yet</h3>
            <p className="text-gray-500 mb-4">Create your first event to start building your community</p>
            <Button 
              onClick={() => setShowCreateForm(true)}
              className="bg-emerald-600 hover:bg-emerald-700"
            >
              <Plus className="w-4 h-4 mr-2" />
              Create Your First Event
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

components.practitioner/AvailabilitySettings:
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PractitionerAvailability } from "@/entities/PractitionerAvailability";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Clock, Save, Plus, Trash2, Ban, AlertTriangle } from "lucide-react";

import BlockedDatesManager from "./BlockedDatesManager";
import ExceptionManager from "./ExceptionManager";

export default function AvailabilitySettings({ practitioner, onUpdate }) {
  const [availability, setAvailability] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const daysOfWeek = useMemo(() => [
    'monday', 'tuesday', 'wednesday', 'thursday', 
    'friday', 'saturday', 'sunday'
  ], []);

  const loadAvailability = useCallback(async () => {
    setIsLoading(true);
    try {
      const practitionerAvailability = await PractitionerAvailability.filter({
        practitioner_id: practitioner.id
      });

      // Initialize with default availability if none exists
      if (practitionerAvailability.length === 0) {
        const defaultAvailability = daysOfWeek.map(day => ({
          practitioner_id: practitioner.id,
          day_of_week: day,
          start_time: "09:00",
          end_time: "17:00",
          is_available: false,
          notes: ""
        }));
        setAvailability(defaultAvailability);
      } else {
        setAvailability(practitionerAvailability);
      }
    } catch (error) {
      console.error("Failed to load availability:", error);
    } finally {
      setIsLoading(false);
    }
  }, [practitioner.id, daysOfWeek]);

  useEffect(() => {
    loadAvailability();
  }, [loadAvailability]);

  const updateAvailability = (dayIndex, field, value) => {
    setAvailability(prev => prev.map((day, index) => 
      index === dayIndex ? { ...day, [field]: value } : day
    ));
  };

  const addTimeSlot = (day) => {
    const newSlotData = {
      practitioner_id: practitioner.id,
      day_of_week: day,
      start_time: "09:00",
      end_time: "17:00",
      is_available: true,
      notes: ""
    };
    setAvailability(prev => [...prev, newSlotData]);
  };

  const removeTimeSlot = (dayIndex) => {
    setAvailability(prev => prev.filter((_, index) => index !== dayIndex));
  };

  const saveAvailability = async () => {
    setIsSaving(true);
    try {
      // Delete existing availability
      const existingAvailability = await PractitionerAvailability.filter({
        practitioner_id: practitioner.id
      });

      for (const existing of existingAvailability) {
        await PractitionerAvailability.delete(existing.id);
      }

      // Create new availability entries
      for (const timeSlot of availability) {
        if (timeSlot.is_available) {
          await PractitionerAvailability.create({
            practitioner_id: practitioner.id,
            day_of_week: timeSlot.day_of_week,
            start_time: timeSlot.start_time,
            end_time: timeSlot.end_time,
            is_available: timeSlot.is_available,
            notes: timeSlot.notes || ""
          });
        }
      }

      onUpdate();
    } catch (error) {
      console.error("Failed to save availability:", error);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="p-6">
          <div className="space-y-4">
            {[...Array(7)].map((_, i) => (
              <div key={i} className="h-16 bg-gray-200 rounded animate-pulse"></div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  const groupedByDay = availability.reduce((acc, slot) => {
    if (!acc[slot.day_of_week]) {
      acc[slot.day_of_week] = [];
    }
    acc[slot.day_of_week].push(slot);
    return acc;
  }, {});

  return (
    <div className="space-y-6">
      <Tabs defaultValue="weekly" className="w-full">
        <TabsList className="grid w-full grid-cols-3 bg-gray-200 p-1 rounded-xl">
          <TabsTrigger value="weekly" className="rounded-lg">
            <Clock className="w-4 h-4 mr-2" />
            Weekly Hours
          </TabsTrigger>
          <TabsTrigger value="blocked" className="rounded-lg">
            <Ban className="w-4 h-4 mr-2" />
            Blocked Dates
          </TabsTrigger>
          <TabsTrigger value="exceptions" className="rounded-lg">
            <AlertTriangle className="w-4 h-4 mr-2" />
            Exceptions
          </TabsTrigger>
        </TabsList>

        <TabsContent value="weekly" className="py-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Clock className="w-5 h-5" />
                Weekly Availability
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {daysOfWeek.map((day, dayIndex) => {
                const daySlots = groupedByDay[day] || [
                  {
                    day_of_week: day,
                    start_time: "09:00",
                    end_time: "17:00",
                    is_available: false,
                    notes: ""
                  }
                ];

                return (
                  <div key={day} className="border rounded-lg p-4">
                    <div className="flex items-center justify-between mb-3">
                      <h4 className="font-semibold text-gray-900 capitalize">
                        {day}
                      </h4>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => addTimeSlot(day)}
                      >
                        <Plus className="w-4 h-4 mr-1" />
                        Add Slot
                      </Button>
                    </div>

                    <div className="space-y-3">
                      {daySlots.map((slot, slotIndex) => (
                        <div key={slotIndex} className="grid grid-cols-12 gap-3 items-center">
                          <div className="col-span-2">
                            <div className="flex items-center">
                              <input
                                type="checkbox"
                                checked={slot.is_available}
                                onChange={(e) => updateAvailability(
                                  availability.findIndex(a => a === slot),
                                  'is_available',
                                  e.target.checked
                                )}
                                className="mr-2"
                              />
                              <span className="text-sm font-medium">Available</span>
                            </div>
                          </div>

                          <div className="col-span-3">
                            <Label className="text-xs">Start Time</Label>
                            <Input
                              type="time"
                              value={slot.start_time}
                              onChange={(e) => updateAvailability(
                                availability.findIndex(a => a === slot),
                                'start_time',
                                e.target.value
                              )}
                              disabled={!slot.is_available}
                            />
                          </div>

                          <div className="col-span-3">
                            <Label className="text-xs">End Time</Label>
                            <Input
                              type="time"
                              value={slot.end_time}
                              onChange={(e) => updateAvailability(
                                availability.findIndex(a => a === slot),
                                'end_time',
                                e.target.value
                              )}
                              disabled={!slot.is_available}
                            />
                          </div>

                          <div className="col-span-3">
                            <Label className="text-xs">Notes</Label>
                            <Input
                              value={slot.notes || ""}
                              onChange={(e) => updateAvailability(
                                availability.findIndex(a => a === slot),
                                'notes',
                                e.target.value
                              )}
                              placeholder="Optional notes"
                              disabled={!slot.is_available}
                            />
                          </div>

                          <div className="col-span-1">
                            {daySlots.length > 0 && (
                              <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => removeTimeSlot(availability.findIndex(a => a === slot))}
                                className="text-red-600 hover:text-red-700"
                              >
                                <Trash2 className="w-4 h-4" />
                              </Button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}

              <div className="flex justify-end pt-4 border-t">
                <Button 
                  onClick={saveAvailability}
                  disabled={isSaving}
                  className="bg-emerald-600 hover:bg-emerald-700"
                >
                  <Save className="w-4 h-4 mr-2" />
                  {isSaving ? "Saving..." : "Save Availability"}
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Quick Stats */}
          <div className="grid grid-cols-3 gap-4">
            <Card>
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-emerald-600">
                  {availability.filter(a => a.is_available).length}
                </div>
                <div className="text-sm text-gray-600">Available Slots</div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-gray-900">
                  {new Set(availability.filter(a => a.is_available).map(a => a.day_of_week)).size}
                </div>
                <div className="text-sm text-gray-600">Available Days</div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4 text-center">
                <div className="text-2xl font-bold text-blue-600">
                  {availability.filter(a => a.is_available).reduce((total, slot) => {
                    const start = new Date(`2000-01-01T${slot.start_time}`);
                    const end = new Date(`2000-01-01T${slot.end_time}`);
                    return total + ((end - start) / (1000 * 60 * 60));
                  }, 0).toFixed(1)}h
                </div>
                <div className="text-sm text-gray-600">Weekly Hours</div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="blocked" className="py-6">
          <BlockedDatesManager practitioner={practitioner} onUpdate={onUpdate} />
        </TabsContent>

        <TabsContent value="exceptions" className="py-6">
          <ExceptionManager practitioner={practitioner} onUpdate={onUpdate} />
        </TabsContent>
      </Tabs>
    </div>
  );
}

components.practitioner/PractitionerApplication:
import React, { useState, useEffect } from "react";
import { Practitioner, User, Notification } from "@/entities/all";
import { UploadPrivateFile, SendEmail } from "@/integrations/Core";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Save, User as UserIcon, Info, CheckCircle, Loader2, FileText, AlertTriangle } from "lucide-react";

export default function PractitionerApplicationForm({ onSuccess }) {
  const [user, setUser] = useState(null);
  const [isLoadingUser, setIsLoadingUser] = useState(true);
  const [formData, setFormData] = useState({
    full_name: "",
    email: "",
    phone: "",
    address: { street: "", city: "", state_province: "", postal_code: "", country: "" },
    bio: "",
    years_experience: 0,
    pricing_range: "$$",
    website_url: "",
    specializations: [],
    languages: ["English"],
    safety_protocols: "",
    training_background: "",
    why_practitioner: "",
    cpr_certification_url: "",
    cpr_expiration_date: "",
    kambo_certification_url: "",
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [validationErrors, setValidationErrors] = useState({});
  const [isUploading, setIsUploading] = useState({ cpr: false, kambo: false });

  const [networkStatus, setNetworkStatus] = useState('online');
  const [retryAttempt, setRetryAttempt] = useState(0);

  useEffect(() => {
    const fetchUser = async () => {
      setIsLoadingUser(true);
      try {
        const currentUser = await User.me();
        setUser(currentUser);
        setFormData(prev => ({
          ...prev,
          full_name: currentUser.full_name || "",
          email: currentUser.email || ""
        }));
      } catch (e) {
        setUser(null);
      } finally {
        setIsLoadingUser(false);
      }
    };
    fetchUser();
  }, []);

  const validateForm = () => {
    const errors = {};

    if (!formData.full_name.trim()) errors.full_name = "Full name is required";
    if (!formData.email.trim()) errors.email = "Email is required";
    if (!formData.training_background.trim()) errors.training_background = "Training background is required";
    if (!formData.safety_protocols.trim()) errors.safety_protocols = "Safety protocols are required";
    if (!formData.why_practitioner.trim()) errors.why_practitioner = "Please explain why you practice Kambo";
    if (!formData.cpr_certification_url) errors.cpr_certification_url = "CPR certification upload is required";
    if (!formData.kambo_certification_url) errors.kambo_certification_url = "Kambo certification upload is required";
    if (!formData.cpr_expiration_date) errors.cpr_expiration_date = "CPR expiration date is required";

    // Address validation
    if (!formData.address.street.trim()) errors.address_street = "Street address is required";
    if (!formData.address.city.trim()) errors.address_city = "City is required";
    if (!formData.address.country.trim()) errors.address_country = "Country is required";

    setValidationErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleFileUpload = async (file, type) => {
    if (!file) return;
    setIsUploading(prev => ({ ...prev, [type]: true }));
    setError("");

    try {
      const { file_uri } = await UploadPrivateFile({ file });
      setFormData(prev => ({ ...prev, [`${type}_certification_url`]: file_uri }));

      // Clear validation error if file was uploaded successfully
      setValidationErrors(prev => ({ ...prev, [`${type}_certification_url`]: null }));
    } catch (err) {
      console.error(`Failed to upload ${type} file:`, err);
      setError(`Failed to upload ${type} document. Please try again.`);
    } finally {
      setIsUploading(prev => ({ ...prev, [type]: false }));
    }
  };

  const handleAddressChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, address: { ...prev.address, [name]: value } }));

    // Clear validation error
    setValidationErrors(prev => ({ ...prev, [`address_${name}`]: null }));
  };

  const handleInputChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Clear validation error
    setValidationErrors(prev => ({ ...prev, [field]: null }));
  };

  const geocodeAddress = async (address) => {
    // Simple geocoding fallback - in production you'd use a proper service
    try {
      // For now, just return null coordinates - the app should work without them
      return { lat: null, lng: null };
    } catch (err) {
      console.warn("Geocoding failed:", err);
      return { lat: null, lng: null };
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setNetworkStatus('online');

    console.log("Form submission started");

    if (!validateForm()) {
      setError("Please fill in all required fields marked with *");
      console.log("Validation failed:", validationErrors);
      return;
    }

    setIsSubmitting(true);
    const maxRetries = 3;
    let attempt = 0;

    const attemptSubmission = async () => {
      try {
        attempt++;
        setRetryAttempt(attempt);
        console.log(`Submission attempt ${attempt}/${maxRetries}`);

        // Check network connectivity first
        if (!navigator.onLine) {
          setNetworkStatus('offline');
          throw new Error('You appear to be offline. Please check your internet connection.');
        }

        const fullAddress = `${formData.address.street}, ${formData.address.city}, ${formData.address.state_province || ''}, ${formData.address.country}`.replace(/,\s*,/g, ',').trim();
        const location = await geocodeAddress(fullAddress);

        const applicationData = {
          ...formData,
          is_verified: false,
          verification_level: 'pending',
          latitude: location?.lat || null,
          longitude: location?.lng || null,
        };

        console.log("Creating practitioner record...");
        const newPractitioner = await Practitioner.create(applicationData);
        console.log("✅ Practitioner created successfully:", newPractitioner.id);

        // Try notifications and email, but don't fail if they don't work
        try {
          const admins = await User.filter({ role: 'admin' });
          for (const admin of admins) {
            await Notification.create({
              user_id: admin.id,
              title: "New Practitioner Application",
              message: `${formData.full_name} has submitted an application for review.`,
              type: "system",
              priority: "high",
              action_url: `/Verification`
            });
          }
        } catch (notifError) {
          console.warn("⚠️ Notifications failed (non-critical):", notifError.message);
        }

        try {
          await SendEmail({
            to: formData.email,
            subject: "We've Received Your KamboConnect Application",
            body: `<h1>Thank You, ${formData.full_name}!</h1><p>We have successfully received your practitioner application. Our team will review it within the next 5-7 business days. We'll notify you via email once your application has been processed.</p><p>The KamboConnect Team</p>`
          });
          console.log("✅ Confirmation email sent");
        } catch (emailError) {
          console.warn("⚠️ Email failed (non-critical):", emailError.message);
        }

        console.log("🎉 Application submitted successfully!");
        onSuccess();
        return true; // Indicate success
      } catch (err) {
        console.error(`❌ Attempt ${attempt} failed:`, err.message);

        // Determine if this is a network error that should be retried
        const isNetworkError = err.message.includes('Network Error') || 
                              err.message.includes('ERR_NETWORK') ||
                              err.message.includes('ERR_INTERNET_DISCONNECTED') ||
                              err.message.includes('Failed to fetch') ||
                              err.message.includes('offline') ||
                              err.name === 'NetworkError';

        if (isNetworkError) {
          setNetworkStatus('unstable');

          if (attempt < maxRetries) {
            console.log(`⏳ Retrying in ${attempt * 2} seconds...`);
            setTimeout(() => attemptSubmission(), attempt * 2000); // Exponential backoff
            return false; // Indicate failure but might retry
          } else {
            setError(`Network connectivity issues prevented submission after ${maxRetries} attempts. Please check your internet connection and try again.`);
            return false; // Indicate final failure
          }
        } else {
          // Non-network error - don't retry
          setError(`Submission failed: ${err.message}. Please check your information and try again.`);
          return false; // Indicate final failure
        }
      }
    };

    await attemptSubmission();
    // These will be executed once all attempts (including retries) are complete or a final error occurs
    setIsSubmitting(false);
    setRetryAttempt(0);
  };

  if (isLoadingUser) {
    return (
      <div className="flex justify-center items-center h-64">
        <Loader2 className="w-8 h-8 animate-spin" />
      </div>
    );
  }

  return (
    <Card className="shadow-lg">
      <CardHeader>
        <CardTitle className="text-3xl font-bold text-center">Become a Kambo Practitioner</CardTitle>
        <CardDescription className="text-center text-gray-600">Join our community of trusted practitioners. Complete the form below to begin.</CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="space-y-4 p-6 border rounded-lg">
            <h3 className="text-xl font-semibold flex items-center gap-2"><UserIcon/>Personal Information</h3>

            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="full_name">Full Name *</Label>
                <Input 
                  id="full_name" 
                  value={formData.full_name} 
                  onChange={(e) => handleInputChange('full_name', e.target.value)} 
                  required 
                  className={validationErrors.full_name ? "border-red-500" : ""}
                />
                {validationErrors.full_name && <p className="text-red-500 text-sm mt-1">{validationErrors.full_name}</p>}
              </div>
              <div>
                <Label htmlFor="email">Email Address *</Label>
                <Input
                  id="email"
                  type="email"
                  value={formData.email}
                  onChange={(e) => handleInputChange('email', e.target.value)}
                  required
                  disabled={!!user}
                  placeholder="your.email@example.com"
                  className={`${!!user ? "bg-gray-100 cursor-not-allowed" : ""} ${validationErrors.email ? "border-red-500" : ""}`}
                />
                {user && <p className="text-xs text-gray-500 mt-1">Email is pre-filled from your logged-in account.</p>}
                {validationErrors.email && <p className="text-red-500 text-sm mt-1">{validationErrors.email}</p>}
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="phone">Phone Number</Label>
                <Input id="phone" value={formData.phone} onChange={(e) => handleInputChange('phone', e.target.value)} />
              </div>
              <div>
                <Label htmlFor="website_url">Website or Social Media URL</Label>
                <Input id="website_url" value={formData.website_url} onChange={(e) => handleInputChange('website_url', e.target.value)} placeholder="https://"/>
              </div>
            </div>

            <div>
              <Label>Primary Location Address *</Label>
              <div className="space-y-2 p-3 bg-gray-50 rounded-md border">
                <Input 
                  name="street" 
                  value={formData.address.street} 
                  onChange={handleAddressChange} 
                  placeholder="Street Address" 
                  required
                  className={validationErrors.address_street ? "border-red-500" : ""}
                />
                {validationErrors.address_street && <p className="text-red-500 text-sm">{validationErrors.address_street}</p>}

                <div className="grid md:grid-cols-3 gap-2">
                  <div>
                    <Input 
                      name="city" 
                      value={formData.address.city} 
                      onChange={handleAddressChange} 
                      placeholder="City" 
                      required
                      className={validationErrors.address_city ? "border-red-500" : ""}
                    />
                    {validationErrors.address_city && <p className="text-red-500 text-sm">{validationErrors.address_city}</p>}
                  </div>
                  <Input name="state_province" value={formData.address.state_province} onChange={handleAddressChange} placeholder="State / Province"/>
                  <Input name="postal_code" value={formData.address.postal_code} onChange={handleAddressChange} placeholder="Postal / ZIP Code"/>
                </div>

                <Input 
                  name="country" 
                  value={formData.address.country} 
                  onChange={handleAddressChange} 
                  placeholder="Country" 
                  required
                  className={validationErrors.address_country ? "border-red-500" : ""}
                />
                {validationErrors.address_country && <p className="text-red-500 text-sm">{validationErrors.address_country}</p>}
              </div>
              <p className="text-xs text-gray-500 mt-1">Your exact address will not be public. This is used for location-based searches.</p>
            </div>
          </div>

          <div className="space-y-4 p-6 border rounded-lg">
            <h3 className="text-xl font-semibold flex items-center gap-2"><Info/>Professional Background</h3>

            <div>
              <Label htmlFor="training_background">Training & Lineage *</Label>
              <Textarea 
                id="training_background" 
                value={formData.training_background} 
                onChange={(e) => handleInputChange('training_background', e.target.value)} 
                rows={4} 
                placeholder="Describe where you trained, who you learned from, and your lineage..." 
                required 
                className={validationErrors.training_background ? "border-red-500" : ""}
              />
              {validationErrors.training_background && <p className="text-red-500 text-sm mt-1">{validationErrors.training_background}</p>}
            </div>

            <div>
              <Label htmlFor="why_practitioner">Your "Why" *</Label>
              <Textarea 
                id="why_practitioner" 
                value={formData.why_practitioner} 
                onChange={(e) => handleInputChange('why_practitioner', e.target.value)} 
                rows={4} 
                placeholder="What called you to serve Kambo? Share your story." 
                required 
                className={validationErrors.why_practitioner ? "border-red-500" : ""}
              />
              {validationErrors.why_practitioner && <p className="text-red-500 text-sm mt-1">{validationErrors.why_practitioner}</p>}
            </div>

            <div>
              <Label htmlFor="safety_protocols">Safety Protocols & Screening Process *</Label>
              <Textarea 
                id="safety_protocols" 
                value={formData.safety_protocols} 
                onChange={(e) => handleInputChange('safety_protocols', e.target.value)} 
                rows={4} 
                placeholder="Detail your process for screening clients for contraindications, and the safety measures you take during a ceremony." 
                required 
                className={validationErrors.safety_protocols ? "border-red-500" : ""}
              />
              {validationErrors.safety_protocols && <p className="text-red-500 text-sm mt-1">{validationErrors.safety_protocols}</p>}
            </div>

            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="years_experience">Years of Experience *</Label>
                <Input 
                  id="years_experience" 
                  type="number" 
                  value={formData.years_experience} 
                  onChange={(e) => handleInputChange('years_experience', parseInt(e.target.value) || 0)} 
                  required 
                />
              </div>
              <div>
                <Label htmlFor="pricing_range">Typical Pricing Range *</Label>
                <Select value={formData.pricing_range} onValueChange={(value) => handleInputChange('pricing_range', value)}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="$">$ (Under $100)</SelectItem>
                    <SelectItem value="$$">$$ ($100-200)</SelectItem>
                    <SelectItem value="$$$">$$$ ($200-350)</SelectItem>
                    <SelectItem value="$$$$">$$$$ ($350+)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>

          <div className="space-y-4 p-6 border rounded-lg">
            <h3 className="text-xl font-semibold flex items-center gap-2"><FileText/>Document Upload</h3>
            <p className="text-sm text-gray-600">Your documents are stored securely and are only visible to platform administrators for verification purposes.</p>

            <div className="grid md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <Label htmlFor="cpr_certification_url">CPR/First-Aid Certification *</Label>
                <div className="flex items-center gap-2">
                  <Input 
                    id="cpr_upload" 
                    type="file" 
                    accept=".pdf,.jpg,.jpeg,.png" 
                    onChange={(e) => handleFileUpload(e.target.files[0], 'cpr')} 
                    className={`flex-1 ${validationErrors.cpr_certification_url ? "border-red-500" : ""}`}
                  />
                  {isUploading.cpr && <Loader2 className="w-4 h-4 animate-spin"/>}
                </div>
                {formData.cpr_certification_url && <p className="text-sm text-green-600 flex items-center gap-1"><CheckCircle className="w-4 h-4"/> Document Uploaded</p>}
                {validationErrors.cpr_certification_url && <p className="text-red-500 text-sm">{validationErrors.cpr_certification_url}</p>}

                <Label htmlFor="cpr_expiration_date" className="mt-2 block">CPR Expiration Date *</Label>
                <Input 
                  id="cpr_expiration_date" 
                  type="date" 
                  value={formData.cpr_expiration_date} 
                  onChange={(e) => handleInputChange('cpr_expiration_date', e.target.value)} 
                  required 
                  className={validationErrors.cpr_expiration_date ? "border-red-500" : ""}
                />
                {validationErrors.cpr_expiration_date && <p className="text-red-500 text-sm">{validationErrors.cpr_expiration_date}</p>}
              </div>

              <div className="space-y-2">
                <Label htmlFor="kambo_certification_url">Kambo Training Certification *</Label>
                <div className="flex items-center gap-2">
                  <Input 
                    id="kambo_upload" 
                    type="file" 
                    accept=".pdf,.jpg,.jpeg,.png" 
                    onChange={(e) => handleFileUpload(e.target.files[0], 'kambo')} 
                    className={`flex-1 ${validationErrors.kambo_certification_url ? "border-red-500" : ""}`}
                  />
                  {isUploading.kambo && <Loader2 className="w-4 h-4 animate-spin"/>}
                </div>
                {formData.kambo_certification_url && <p className="text-sm text-green-600 flex items-center gap-1"><CheckCircle className="w-4 h-4"/> Document Uploaded</p>}
                {validationErrors.kambo_certification_url && <p className="text-red-500 text-sm">{validationErrors.kambo_certification_url}</p>}
              </div>
            </div>
          </div>

          {error && (
            <Alert variant="destructive">
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription>
                {error}
                {networkStatus === 'offline' && (
                  <div className="mt-2">
                    <p className="text-sm">📶 Network Status: Offline</p>
                    <p className="text-xs">Please check your internet connection and try again.</p>
                  </div>
                )}
                {networkStatus === 'unstable' && retryAttempt > 0 && retryAttempt <= 3 && (
                  <div className="mt-2">
                    <p className="text-sm">📶 Network Status: Unstable</p>
                    <p className="text-xs">Connection issues detected. The form is automatically retrying.</p>
                  </div>
                )}
              </AlertDescription>
            </Alert>
          )}

          <div className="flex justify-end pt-6 border-t">
            <Button 
              type="submit" 
              size="lg" 
              disabled={isSubmitting || Object.values(isUploading).some(v => v)} 
              className="bg-emerald-600 hover:bg-emerald-700"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin"/>
                  {retryAttempt > 0 ? `Retrying... (Attempt ${retryAttempt}/3)` : 'Submitting Application...'}
                </>
              ) : (
                <>
                  <Save className="w-4 h-4 mr-2"/>
                  Submit Application
                </>
              )}
            </Button>
          </div>
        </form>
      </CardContent>
    </Card>
  );
}

components.practitioner/BlockedDatesManager:
import React, { useState, useEffect, useCallback } from 'react';
import { PractitionerBlockedDate } from "@/entities/PractitionerBlockedDate";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Calendar } from "@/components/ui/calendar";
import { Badge } from "@/components/ui/badge";
import { 
  Calendar as CalendarIcon, Plus, Trash2, Clock, 
  AlertCircle, Ban, Edit, Save, X 
} from "lucide-react";
import { format, startOfDay, isBefore } from "date-fns";
import { Alert, AlertDescription } from "@/components/ui/alert";

export default function BlockedDatesManager({ practitioner, onUpdate }) {
  const [blockedDates, setBlockedDates] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [newBlock, setNewBlock] = useState({
    date: null,
    block_type: 'full_day',
    start_time: '09:00',
    end_time: '17:00',
    reason: '',
    recurring: false
  });

  const loadBlockedDates = useCallback(async () => {
    setIsLoading(true);
    try {
      const blocks = await PractitionerBlockedDate.filter({
        practitioner_id: practitioner.id
      }, '-date');
      setBlockedDates(blocks);
    } catch (error) {
      console.error("Failed to load blocked dates:", error);
    } finally {
      setIsLoading(false);
    }
  }, [practitioner.id]);

  useEffect(() => {
    loadBlockedDates();
  }, [loadBlockedDates]);

  const handleAddBlock = async () => {
    if (!newBlock.date) return;

    try {
      const blockData = {
        practitioner_id: practitioner.id,
        date: format(newBlock.date, 'yyyy-MM-dd'),
        block_type: newBlock.block_type,
        reason: newBlock.reason,
        recurring: newBlock.recurring
      };

      if (newBlock.block_type === 'partial_day') {
        blockData.start_time = newBlock.start_time;
        blockData.end_time = newBlock.end_time;
      }

      await PractitionerBlockedDate.create(blockData);

      setNewBlock({
        date: null,
        block_type: 'full_day',
        start_time: '09:00',
        end_time: '17:00',
        reason: '',
        recurring: false
      });
      setIsAdding(false);
      loadBlockedDates();
      onUpdate();
    } catch (error) {
      console.error("Failed to create blocked date:", error);
    }
  };

  const handleUpdateBlock = async (blockId, updatedData) => {
    try {
      await PractitionerBlockedDate.update(blockId, updatedData);
      setEditingId(null);
      loadBlockedDates();
      onUpdate();
    } catch (error) {
      console.error("Failed to update blocked date:", error);
    }
  };

  const handleDeleteBlock = async (blockId) => {
    if (confirm('Are you sure you want to remove this blocked date?')) {
      try {
        await PractitionerBlockedDate.delete(blockId);
        loadBlockedDates();
        onUpdate();
      } catch (error) {
        console.error("Failed to delete blocked date:", error);
      }
    }
  };

  const getBlockTypeColor = (blockType) => {
    const colors = {
      full_day: "bg-red-100 text-red-800 border-red-200",
      partial_day: "bg-orange-100 text-orange-800 border-orange-200", 
      exception: "bg-blue-100 text-blue-800 border-blue-200"
    };
    return colors[blockType] || colors.full_day;
  };

  const BlockedDateItem = ({ block }) => {
    const [isEditing, setIsEditing] = useState(false);
    const [editData, setEditData] = useState(block);

    const handleSave = () => {
      handleUpdateBlock(block.id, editData);
      setIsEditing(false);
    };

    if (isEditing) {
      return (
        <Card className="mb-4">
          <CardContent className="p-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label>Date</Label>
                <Input 
                  type="date"
                  value={editData.date}
                  onChange={(e) => setEditData({...editData, date: e.target.value})}
                />
              </div>
              <div>
                <Label>Block Type</Label>
                <Select value={editData.block_type} onValueChange={(value) => setEditData({...editData, block_type: value})}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="full_day">Full Day</SelectItem>
                    <SelectItem value="partial_day">Partial Day</SelectItem>
                    <SelectItem value="exception">Exception</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              {editData.block_type === 'partial_day' && (
                <>
                  <div>
                    <Label>Start Time</Label>
                    <Input 
                      type="time"
                      value={editData.start_time}
                      onChange={(e) => setEditData({...editData, start_time: e.target.value})}
                    />
                  </div>
                  <div>
                    <Label>End Time</Label>
                    <Input 
                      type="time"
                      value={editData.end_time}
                      onChange={(e) => setEditData({...editData, end_time: e.target.value})}
                    />
                  </div>
                </>
              )}
              <div className="md:col-span-2">
                <Label>Reason</Label>
                <Input 
                  value={editData.reason}
                  onChange={(e) => setEditData({...editData, reason: e.target.value})}
                  placeholder="Optional reason..."
                />
              </div>
            </div>
            <div className="flex gap-2 mt-4">
              <Button onClick={handleSave} size="sm">
                <Save className="w-4 h-4 mr-2" />
                Save
              </Button>
              <Button variant="outline" onClick={() => setIsEditing(false)} size="sm">
                <X className="w-4 h-4 mr-2" />
                Cancel
              </Button>
            </div>
          </CardContent>
        </Card>
      );
    }

    return (
      <Card className="mb-4 hover:shadow-md transition-shadow">
        <CardContent className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h4 className="font-semibold">{format(new Date(block.date), 'EEEE, MMMM d, yyyy')}</h4>
                <Badge className={getBlockTypeColor(block.block_type)}>
                  {block.block_type === 'full_day' ? 'Full Day' : 
                   block.block_type === 'partial_day' ? 'Partial Day' : 'Exception'}
                </Badge>
                {block.recurring && (
                  <Badge variant="outline" className="bg-purple-50 text-purple-700 border-purple-200">
                    Recurring
                  </Badge>
                )}
              </div>

              {block.block_type === 'partial_day' && (
                <div className="text-sm text-gray-600 flex items-center gap-1 mb-1">
                  <Clock className="w-4 h-4" />
                  {block.start_time} - {block.end_time}
                </div>
              )}

              {block.reason && (
                <p className="text-sm text-gray-600 italic">{block.reason}</p>
              )}
            </div>

            <div className="flex gap-2">
              <Button variant="ghost" size="sm" onClick={() => setIsEditing(true)}>
                <Edit className="w-4 h-4" />
              </Button>
              <Button 
                variant="ghost" 
                size="sm" 
                onClick={() => handleDeleteBlock(block.id)}
                className="text-red-600 hover:text-red-700"
              >
                <Trash2 className="w-4 h-4" />
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    );
  };

  if (isLoading) {
    return (
      <Card>
        <CardContent className="p-6">
          <div className="space-y-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-16 bg-gray-200 rounded animate-pulse"></div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <Ban className="w-5 h-5" />
              Blocked Dates & Exceptions
            </CardTitle>
            <Button onClick={() => setIsAdding(true)} disabled={isAdding}>
              <Plus className="w-4 h-4 mr-2" />
              Block Date
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {/* Add New Block Form */}
          {isAdding && (
            <Card className="mb-6 border-emerald-200 bg-emerald-50">
              <CardContent className="p-4">
                <h4 className="font-semibold mb-4">Block New Date</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <Label>Select Date</Label>
                    <Calendar
                      mode="single"
                      selected={newBlock.date}
                      onSelect={(date) => setNewBlock({...newBlock, date})}
                      disabled={(date) => isBefore(date, startOfDay(new Date()))}
                      className="rounded-lg border mt-2"
                    />
                  </div>

                  <div className="space-y-4">
                    <div>
                      <Label>Block Type</Label>
                      <Select value={newBlock.block_type} onValueChange={(value) => setNewBlock({...newBlock, block_type: value})}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="full_day">Full Day - Completely unavailable</SelectItem>
                          <SelectItem value="partial_day">Partial Day - Block specific hours</SelectItem>
                          <SelectItem value="exception">Exception - Override normal availability</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    {newBlock.block_type === 'partial_day' && (
                      <>
                        <div>
                          <Label>Start Time</Label>
                          <Input 
                            type="time"
                            value={newBlock.start_time}
                            onChange={(e) => setNewBlock({...newBlock, start_time: e.target.value})}
                          />
                        </div>
                        <div>
                          <Label>End Time</Label>
                          <Input 
                            type="time"
                            value={newBlock.end_time}
                            onChange={(e) => setNewBlock({...newBlock, end_time: e.target.value})}
                          />
                        </div>
                      </>
                    )}

                    <div>
                      <Label>Reason (Optional)</Label>
                      <Input 
                        value={newBlock.reason}
                        onChange={(e) => setNewBlock({...newBlock, reason: e.target.value})}
                        placeholder="Vacation, personal time, etc."
                      />
