components.profile/ProfilePictureUpload:
import React, { useState } from "react";
import { User } from "@/entities/User";
import { UploadFile } from "@/integrations/Core";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Camera, X, Check, Loader2 } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Alert, AlertDescription } from "@/components/ui/alert";

export default function ProfilePictureUpload({ user, onUpdate }) {
  const [isUploading, setIsUploading] = useState(false);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [error, setError] = useState(null);

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (!file) return;

    // Reset previous errors
    setError(null);

    // Validate file size (5MB limit)
    if (file.size > 5 * 1024 * 1024) {
      setError("File size must be less than 5MB");
      return;
    }

    // Validate file type
    if (!file.type.startsWith('image/')) {
      setError("Please select an image file (JPEG, PNG, GIF, etc.)");
      return;
    }

    setSelectedFile(file);

    // Create preview URL
    const reader = new FileReader();
    reader.onload = (e) => setPreviewUrl(e.target.result);
    reader.readAsDataURL(file);

    setShowUploadModal(true);
  };

  const handleUpload = async () => {
    if (!selectedFile) return;

    setIsUploading(true);
    setError(null);

    try {
      // Upload the file
      const uploadResult = await UploadFile({ file: selectedFile });

      // Update user profile with new image URL
      await User.updateMyUserData({ 
        profile_image_url: uploadResult.file_url 
      });

      // Notify parent component to refresh user data
      if (onUpdate) {
        onUpdate();
      }

      // Close modal and reset state
      setShowUploadModal(false);
      setSelectedFile(null);
      setPreviewUrl(null);

    } catch (error) {
      console.error("Failed to upload profile picture:", error);
      setError("Failed to upload image. Please try again.");
    } finally {
      setIsUploading(false);
    }
  };

  const handleCancel = () => {
    setShowUploadModal(false);
    setSelectedFile(null);
    setPreviewUrl(null);
    setError(null);
  };

  const handleRemovePhoto = async () => {
    setIsUploading(true);
    setError(null);

    try {
      await User.updateMyUserData({ 
        profile_image_url: null 
      });

      if (onUpdate) {
        onUpdate();
      }
    } catch (error) {
      console.error("Failed to remove profile picture:", error);
      setError("Failed to remove image. Please try again.");
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <>
      <div className="relative group">
        <Avatar className="w-24 h-24 border-4 border-white shadow-md">
          <AvatarImage src={user?.profile_image_url} alt={user?.full_name} />
          <AvatarFallback className="text-3xl bg-gradient-to-br from-emerald-100 to-teal-100 text-emerald-700">
            {user?.full_name?.charAt(0)?.toUpperCase() || 'U'}
          </AvatarFallback>
        </Avatar>

        {/* Hover overlay for upload */}
        <label className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer rounded-full flex items-center justify-center">
          <Camera className="w-6 h-6 text-white" />
          <input
            type="file"
            accept="image/*"
            onChange={handleFileSelect}
            className="hidden"
            disabled={isUploading}
          />
        </label>

        {/* Loading spinner overlay */}
        {isUploading && (
          <div className="absolute inset-0 bg-black/50 rounded-full flex items-center justify-center">
            <Loader2 className="w-6 h-6 text-white animate-spin" />
          </div>
        )}
      </div>

      {/* Error display */}
      {error && (
        <Alert className="mt-4 border-red-200 bg-red-50">
          <X className="h-4 w-4 text-red-600" />
          <AlertDescription className="text-red-800">
            {error}
          </AlertDescription>
        </Alert>
      )}

      {/* Upload Confirmation Modal */}
      <Dialog open={showUploadModal} onOpenChange={setShowUploadModal}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Update Profile Picture</DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            {previewUrl && (
              <div className="flex justify-center">
                <Avatar className="w-32 h-32 border-4 border-gray-200">
                  <AvatarImage src={previewUrl} alt="Preview" />
                </Avatar>
              </div>
            )}

            <p className="text-sm text-gray-600 text-center">
              Are you happy with this new profile picture?
            </p>

            {error && (
              <Alert className="border-red-200 bg-red-50">
                <X className="h-4 w-4 text-red-600" />
                <AlertDescription className="text-red-800">
                  {error}
                </AlertDescription>
              </Alert>
            )}

            <div className="flex gap-2">
              <Button
                variant="outline"
                onClick={handleCancel}
                disabled={isUploading}
                className="flex-1"
              >
                <X className="w-4 h-4 mr-2" />
                Cancel
              </Button>
              <Button
                onClick={handleUpload}
                disabled={isUploading}
                className="flex-1 bg-emerald-600 hover:bg-emerald-700"
              >
                {isUploading ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Uploading...
                  </>
                ) : (
                  <>
                    <Check className="w-4 h-4 mr-2" />
                    Update Picture
                  </>
                )}
              </Button>
            </div>

            {/* Option to remove existing photo */}
            {user?.profile_image_url && !isUploading && (
              <>
                <div className="relative">
                  <div className="absolute inset-0 flex items-center">
                    <span className="w-full border-t border-gray-300" />
                  </div>
                  <div className="relative flex justify-center text-xs">
                    <span className="bg-white px-2 text-gray-500">or</span>
                  </div>
                </div>
                <Button
                  variant="ghost"
                  onClick={handleRemovePhoto}
                  className="w-full text-red-600 hover:text-red-700 hover:bg-red-50"
                >
                  Remove Current Photo
                </Button>
              </>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

components.profile/DemoNotificationGenerator:
import React, { useState } from 'react';
import { Button } from "@/components/ui/button";
import { User, Notification, Conversation } from '@/entities/all';
import { BellPlus, Loader2, Check } from 'lucide-react';
import { createPageUrl } from '@/utils';

export default function DemoNotificationGenerator() {
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const generateNotifications = async () => {
    setIsLoading(true);
    setIsSuccess(false);
    try {
      const user = await User.me();
      if (!user) {
        console.error("User not found. Please log in to generate notifications.");
        return;
      }

      // Find or create a dummy conversation to link to
      let conversations = await Conversation.filter({ participant_1_id: user.id, participant_2_name: "Demo Bot" });
      let demoConversation;

      if (conversations.length > 0) {
        demoConversation = conversations[0];
      } else {
        demoConversation = await Conversation.create({
          participant_1_id: user.id,
          participant_2_id: 'system_demo_bot',
          participant_1_name: user.full_name,
          participant_2_name: "Demo Bot",
          last_message: "This is a demo conversation.",
          last_message_date: new Date().toISOString()
        });
      }

      const notificationsToCreate = [
        {
          user_id: user.id,
          title: "Booking Confirmed!",
          message: "Your session with Jane Doe for next Tuesday has been confirmed.",
          type: "booking",
          priority: "high",
          action_url: createPageUrl('Bookings')
        },
        {
          user_id: user.id,
          title: "New Message from Demo Bot",
          message: "This is a sample message to test notifications. Click to view.",
          type: "message",
          priority: "normal",
          related_id: demoConversation.id,
          action_url: `${createPageUrl('Messages')}?conversation_id=${demoConversation.id}`
        },
        {
          user_id: user.id,
          title: "Event Reminder: Kambo Workshop",
          message: "Your workshop starts in 24 hours. Don't forget to prepare!",
          type: "event",
          priority: "urgent",
          action_url: createPageUrl('Events')
        },
        {
          user_id: user.id,
          title: "New Review on your Profile",
          message: "A client has left a new 5-star review. Great job!",
          type: "review",
          priority: "normal",
          action_url: createPageUrl('Profile') // Assuming a practitioner might see reviews on their main profile
        }
      ];

      // Use Promise.all to create all notifications concurrently
      await Promise.all(notificationsToCreate.map(n => Notification.create(n)));

      setIsSuccess(true);
      setTimeout(() => {
        setIsSuccess(false);
        // Maybe trigger a refresh of notifications in the UI
        window.dispatchEvent(new CustomEvent('notificationsUpdated'));
      }, 3000);

    } catch (error) {
      console.error("Failed to generate notifications:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-between p-4 border rounded-lg bg-gray-50">
      <div>
        <h4 className="font-semibold text-gray-800">Generate Sample Notifications</h4>
        <p className="text-sm text-gray-500">Click to add 4 sample notifications to your account for demonstration.</p>
      </div>
      <Button onClick={generateNotifications} disabled={isLoading || isSuccess} className="w-32">
        {isLoading ? (
          <Loader2 className="w-4 h-4 mr-2 animate-spin" />
        ) : isSuccess ? (
          <Check className="w-4 h-4 mr-2" />
        ) : (
          <BellPlus className="w-4 h-4 mr-2" />
        )}
        {isLoading ? "Generating..." : isSuccess ? "Done!" : "Generate"}
      </Button>
    </div>
  );
}

components.profile/ReportButton:
import React, { useState } from "react";
import { Report, User } from "@/entities/all";
import { Button } from "@/components/ui/button";
import { Flag } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

export default function ReportButton({ 
  itemType, 
  itemId, 
  itemTitle,
  size = "sm",
  variant = "outline" 
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [reason, setReason] = useState("");
  const [description, setDescription] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const reasons = [
    { value: "spam", label: "Spam or promotional content" },
    { value: "harassment", label: "Harassment or bullying" },
    { value: "inappropriate_content", label: "Inappropriate or offensive content" },
    { value: "safety_concern", label: "Safety concern" },
    { value: "fraud", label: "Fraud or scam" },
    { value: "other", label: "Other" }
  ];

  const handleSubmit = async () => {
    if (!reason) return;

    setIsSubmitting(true);
    try {
      const currentUser = await User.me();

      await Report.create({
        reported_item_type: itemType,
        reported_item_id: itemId,
        reporter_id: currentUser.id,
        reporter_email: currentUser.email,
        reason,
        description: description.trim(),
        priority: reason === 'safety_concern' ? 'urgent' : 'medium'
      });

      setIsOpen(false);
      setReason("");
      setDescription("");

      // Show success message
      alert("Report submitted successfully. Our team will review it shortly.");
    } catch (error) {
      console.error("Failed to submit report:", error);
      alert("Failed to submit report. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <>
      <Button
        variant={variant}
        size={size}
        onClick={() => setIsOpen(true)}
        className="text-red-600 hover:text-red-700 hover:bg-red-50"
      >
        <Flag className="w-3 h-3 mr-1" />
        Report
      </Button>

      <Dialog open={isOpen} onOpenChange={setIsOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Report Content</DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            <div>
              <p className="text-sm text-gray-600 mb-3">
                You're reporting: <strong>{itemTitle}</strong>
              </p>

              <Label>What's the issue?</Label>
              <RadioGroup value={reason} onValueChange={setReason} className="mt-2">
                {reasons.map(r => (
                  <div key={r.value} className="flex items-center space-x-2">
                    <RadioGroupItem value={r.value} id={r.value} />
                    <Label htmlFor={r.value} className="text-sm cursor-pointer">
                      {r.label}
                    </Label>
                  </div>
                ))}
              </RadioGroup>
            </div>

            <div>
              <Label>Additional details (optional)</Label>
              <Textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Please provide any additional context..."
                className="mt-1"
              />
            </div>

            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setIsOpen(false)}>
                Cancel
              </Button>
              <Button 
                onClick={handleSubmit}
                disabled={!reason || isSubmitting}
              >
                {isSubmitting ? "Submitting..." : "Submit Report"}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

components.booking/DirectBookingModal:
import React, { useState, useEffect, useCallback } from "react";
import {
  Booking,
  Payment,
  Conversation,
  PractitionerAvailability,
  PractitionerBlockedDate,
  PractitionerException,
  User,
  Notification
} from "@/entities/all";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Separator } from "@/components/ui/separator";
import {
  Loader2,
  CheckCircle,
  Calendar as CalendarIcon,
  Clock,
  ArrowRight,
  Shield,
  XCircle
} from "lucide-react";
import { format, parse, startOfDay, isSameDay } from "date-fns";

// Helper function to generate time slots
const generateTimeSlots = (start, end, interval) => {
  const slots = [];
  let currentTime = parse(start, 'HH:mm', new Date());
  const endTime = parse(end, 'HH:mm', new Date());

  while (currentTime < endTime) {
    slots.push(format(currentTime, 'HH:mm'));
    currentTime.setMinutes(currentTime.getMinutes() + interval);
  }
  return slots;
};


export default function DirectBookingModal({ practitioner, onClose, onBookingComplete }) {
  const [user, setUser] = useState(null);
  const [selectedDate, setSelectedDate] = useState(null);
  const [selectedTime, setSelectedTime] = useState(null);
  const [availableSlots, setAvailableSlots] = useState([]);
  const [isLoadingSlots, setIsLoadingSlots] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState("");
  const [bookingStep, setBookingStep] = useState('date_selection'); // 'date_selection', 'confirmation', 'success'

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
      } catch (e) {
        setUser(null);
      }
    };
    fetchUser();
  }, []);

  const getAvailableSlots = useCallback(async (date) => {
    if (!date) return;
    setIsLoadingSlots(true);
    setAvailableSlots([]);
    setSelectedTime(null);
    setError('');

    const dayOfWeek = format(date, 'eeee').toLowerCase();

    try {
      const [weeklyAvail, blockedDates, exceptions] = await Promise.all([
        PractitionerAvailability.filter({ practitioner_id: practitioner.id, day_of_week: dayOfWeek }),
        PractitionerBlockedDate.filter({ practitioner_id: practitioner.id }),
        PractitionerException.filter({ practitioner_id: practitioner.id, date: format(date, 'yyyy-MM-dd') }),
      ]);

      let finalSlots = [];

      // 1. Start with weekly availability
      let baseSlots = weeklyAvail.filter(a => a.is_available).flatMap(a => generateTimeSlots(a.start_time, a.end_time, 60));

      // 2. Apply exceptions for the day
      const overrideException = exceptions.find(e => e.exception_type === 'override');
      const additionalExceptions = exceptions.filter(e => e.exception_type === 'additional');
      const removeExceptions = exceptions.filter(e => e.exception_type === 'remove');

      if (overrideException) {
        baseSlots = generateTimeSlots(overrideException.start_time, overrideException.end_time, 60);
      }

      additionalExceptions.forEach(e => {
        baseSlots.push(...generateTimeSlots(e.start_time, e.end_time, 60));
      });

      if (removeExceptions.length > 0) {
        const removeRanges = removeExceptions.map(e => ({ start: parse(e.start_time, 'HH:mm', date), end: parse(e.end_time, 'HH:mm', date) }));
        baseSlots = baseSlots.filter(slot => {
          const slotTime = parse(slot, 'HH:mm', date);
          return !removeRanges.some(range => slotTime >= range.start && slotTime < range.end);
        });
      }

      // 3. Filter out blocked dates/times
      const todayBlockedDates = blockedDates.filter(b => isSameDay(new Date(b.date), date));
      if (todayBlockedDates.some(b => b.block_type === 'full_day')) {
        finalSlots = [];
      } else {
        const partialBlocks = todayBlockedDates.filter(b => b.block_type === 'partial_day');
        const blockedRanges = partialBlocks.map(b => ({ start: parse(b.start_time, 'HH:mm', date), end: parse(b.end_time, 'HH:mm', date) }));

        finalSlots = baseSlots.filter(slot => {
          const slotTime = parse(slot, 'HH:mm', date);
          return !blockedRanges.some(range => slotTime >= range.start && slotTime < range.end);
        });
      }

      // Remove duplicates and sort
      finalSlots = [...new Set(finalSlots)].sort();

      setAvailableSlots(finalSlots);

    } catch (err) {
      console.error("Error fetching availability:", err);
      setError("Could not load available times. Please try again.");
    } finally {
      setIsLoadingSlots(false);
    }
  }, [practitioner.id]);

  const handleDateChange = (date) => {
    setSelectedDate(date);
    getAvailableSlots(date);
  };

  const handleConfirmBooking = async () => {
    if (!user || !selectedDate || !selectedTime) {
      setError("Please select a date and time to continue.");
      return;
    }

    setIsProcessing(true);
    setError("");

    try {
      const bookingDateTime = parse(selectedTime, 'HH:mm', selectedDate);
      const sessionPrice = practitioner.pricing_range === '$' ? 150 : practitioner.pricing_range === '$$' ? 200 : 250;

      // --- MOCK PAYMENT GATEWAY ---
      // In a real app, this would redirect to Stripe Checkout or use Stripe Elements.
      // Here, we simulate a successful payment by creating a Payment record.
      const paymentRecord = await Payment.create({
        booking_id: null, // will be updated after booking is created
        user_id: user.id,
        practitioner_id: practitioner.id,
        amount: sessionPrice,
        payment_type: 'booking',
        payment_status: 'completed',
        payment_method: 'mock_credit_card',
      });
      // --- END MOCK PAYMENT ---

      const bookingRecord = await Booking.create({
        practitioner_id: practitioner.id,
        practitioner_name: practitioner.full_name,
        client_id: user.id,
        client_name: user.full_name,
        client_email: user.email,
        service_type: "Private Session",
        requested_date: format(bookingDateTime, "yyyy-MM-dd'T'HH:mm:ss'Z'"),
        status: "confirmed", // Direct booking is auto-confirmed
        price: sessionPrice,
        payment_status: "paid",
        message: `Direct booking made via practitioner profile for ${format(bookingDateTime, 'PPP @ p')}`
      });

      // Link payment to booking
      await Payment.update(paymentRecord.id, { booking_id: bookingRecord.id });

      // Ensure a conversation exists for this booking
      const existingConvo = await Conversation.filter({ related_booking_id: bookingRecord.id });
      if (existingConvo.length === 0) {
        await Conversation.create({
          participant_1_id: user.id,
          participant_2_id: practitioner.id,
          participant_1_name: user.full_name,
          participant_2_name: practitioner.full_name,
          related_booking_id: bookingRecord.id,
          last_message: "Session booked! You can now chat with your practitioner.",
          last_message_date: new Date().toISOString(),
        });
      }

      // Notify practitioner
      await Notification.create({
          user_id: practitioner.id,
          title: "New Direct Booking!",
          message: `${user.full_name} has booked a session with you for ${format(bookingDateTime, 'PPP @ p')}.`,
          type: 'booking',
          related_id: bookingRecord.id,
          priority: 'high',
          action_url: '/PractitionerDashboard'
      });

      setBookingStep('success');
      onBookingComplete();

    } catch (err) {
      console.error("Direct booking failed:", err);
      setError("An unexpected error occurred while confirming your booking. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Dialog open={true} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-2xl">Book a Session with {practitioner.full_name}</DialogTitle>
          <DialogDescription>
            {bookingStep === 'date_selection' && "Select an available date and time for your session."}
            {bookingStep === 'confirmation' && "Please confirm your booking and proceed with payment."}
            {bookingStep === 'success' && "Your session is confirmed!"}
          </DialogDescription>
        </DialogHeader>

        {error && (
            <Alert variant="destructive"><XCircle className="h-4 w-4" /> <AlertDescription>{error}</AlertDescription></Alert>
        )}

        {bookingStep === 'date_selection' && (
          <div className="grid md:grid-cols-2 gap-8 pt-4">
            <div>
              <h3 className="font-semibold mb-2 flex items-center gap-2"><CalendarIcon className="w-5 h-5 text-emerald-600"/> Select a Date</h3>
              <Calendar
                mode="single"
                selected={selectedDate}
                onSelect={handleDateChange}
                disabled={(date) => date < startOfDay(new Date())}
                className="rounded-md border"
              />
            </div>
            <div>
              <h3 className="font-semibold mb-2 flex items-center gap-2"><Clock className="w-5 h-5 text-emerald-600"/> Select a Time</h3>
              {isLoadingSlots ? (
                <div className="flex items-center justify-center h-48"><Loader2 className="w-8 h-8 animate-spin text-gray-400" /></div>
              ) : selectedDate && availableSlots.length > 0 ? (
                <RadioGroup value={selectedTime} onValueChange={setSelectedTime} className="space-y-2">
                  <div className="grid grid-cols-3 gap-2">
                    {availableSlots.map(slot => (
                      <div key={slot}>
                        <RadioGroupItem value={slot} id={slot} className="peer sr-only" />
                        <Label
                          htmlFor={slot}
                          className="flex items-center justify-center rounded-md border-2 border-gray-200 bg-white p-3 text-sm font-medium hover:bg-gray-50 peer-data-[state=checked]:border-emerald-500 peer-data-[state=checked]:bg-emerald-50 peer-data-[state=checked]:text-emerald-900 cursor-pointer"
                        >
                          {format(parse(slot, 'HH:mm', new Date()), 'p')}
                        </Label>
                      </div>
                    ))}
                  </div>
                </RadioGroup>
              ) : selectedDate ? (
                <p className="text-gray-500 text-center h-48 flex items-center justify-center">No available slots for this date.</p>
              ) : (
                <p className="text-gray-500 text-center h-48 flex items-center justify-center">Please select a date to see available times.</p>
              )}
            </div>
          </div>
        )}

        {bookingStep === 'confirmation' && (
             <div className="pt-4 space-y-4">
                <h3 className="text-lg font-semibold">Booking Summary</h3>
                <div className="bg-gray-50 p-4 rounded-lg space-y-2">
                    <p><strong>Practitioner:</strong> {practitioner.full_name}</p>
                    <p><strong>Date:</strong> {format(selectedDate, 'PPP')}</p>
                    <p><strong>Time:</strong> {format(parse(selectedTime, 'HH:mm', new Date()), 'p')}</p>
                    <Separator/>
                    <p className="font-bold text-lg"><strong>Total:</strong> ${practitioner.pricing_range === '$' ? 150 : practitioner.pricing_range === '$$' ? 200 : 250}</p>
                </div>
                 <Alert>
                    <Shield className="h-4 w-4" />
                    <AlertDescription>
                        This is a mock payment step. In a real application, you would enter your credit card details here. Clicking "Confirm & Pay" will simulate a successful payment and book your session.
                    </AlertDescription>
                </Alert>
            </div>
        )}

        {bookingStep === 'success' && (
            <div className="text-center py-8">
                <CheckCircle className="w-16 h-16 text-green-500 mx-auto mb-4"/>
                <h2 className="text-2xl font-bold mb-2">Booking Confirmed!</h2>
                <p className="text-gray-600 mb-6">
                    Your session with {practitioner.full_name} is booked. You can view your booking details and message your practitioner from the "My Bookings" page.
                </p>
                <Button onClick={onClose}>Done</Button>
            </div>
        )}

        {bookingStep !== 'success' && (
            <div className="flex justify-end pt-6 border-t mt-6">
                {bookingStep === 'date_selection' && (
                    <Button onClick={() => setBookingStep('confirmation')} disabled={!selectedDate || !selectedTime}>
                        Proceed to Confirmation <ArrowRight className="w-4 h-4 ml-2"/>
                    </Button>
                )}
                 {bookingStep === 'confirmation' && (
                    <div className="flex gap-2">
                        <Button variant="outline" onClick={() => setBookingStep('date_selection')} disabled={isProcessing}>Back</Button>
                        <Button onClick={handleConfirmBooking} disabled={isProcessing} className="bg-emerald-600 hover:bg-emerald-700">
                            {isProcessing ? <Loader2 className="w-4 h-4 mr-2 animate-spin"/> : <CheckCircle className="w-4 h-4 mr-2"/>}
                            {isProcessing ? 'Processing...' : 'Confirm & Pay'}
                        </Button>
                    </div>
                )}
            </div>
        )}

      </DialogContent>
    </Dialog>
  );
}

components.messages/MessageBubble:
import React from 'react';
import { format, isToday, isYesterday } from 'date-fns';
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Check, CheckCheck, FileText, Info } from 'lucide-react';
import { cn } from '@/lib/utils';

const formatDate = (date) => {
    const d = new Date(date);
    if (isToday(d)) return format(d, 'p');
    if (isYesterday(d)) return `Yesterday at ${format(d, 'p')}`;
    return format(d, 'MMM d, yyyy');
};

const SystemMessage = ({ content }) => (
    <div className="flex items-center justify-center my-4">
        <div className="text-xs text-gray-500 bg-gray-100 rounded-full px-3 py-1 flex items-center gap-2">
            <Info className="w-3 h-3" />
            <span>{content}</span>
        </div>
    </div>
);

const FileMessage = ({ fileUrl, content }) => (
    <a 
        href={fileUrl} 
        target="_blank" 
        rel="noopener noreferrer"
        className="flex items-center gap-2 bg-emerald-50 text-emerald-800 p-2 rounded-lg hover:bg-emerald-100 transition-colors"
    >
        <FileText className="w-5 h-5 flex-shrink-0" />
        <span className="text-sm font-medium underline truncate">{content}</span>
    </a>
);

export default function MessageBubble({ message, isSender, senderName, showAvatar }) {
    if (message.message_type === 'system') {
        return <SystemMessage content={message.content} />;
    }

    const senderInitial = senderName ? senderName.charAt(0).toUpperCase() : '?';

    return (
        <div className={cn("flex items-start gap-3 w-full", isSender ? 'justify-end' : 'justify-start')}>
            {!isSender && (
                <div className="w-8 h-8 flex-shrink-0">
                    {showAvatar && (
                        <Avatar className="w-8 h-8">
                            <AvatarFallback>{senderInitial}</AvatarFallback>
                        </Avatar>
                    )}
                </div>
            )}
            <div className={cn("flex flex-col max-w-sm md:max-w-md", isSender ? 'items-end' : 'items-start')}>
                <div
                    className={cn(
                        "rounded-lg p-3",
                        isSender ? 'bg-emerald-600 text-white rounded-br-none' : 'bg-gray-200 text-gray-900 rounded-bl-none'
                    )}
                >
                    {!isSender && showAvatar && <p className="text-xs font-bold mb-1">{senderName}</p>}

                    {message.message_type === 'file' ? (
                        <FileMessage fileUrl={message.file_url} content={message.content} />
                    ) : (
                        <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                    )}
                </div>
                <div className="text-xs text-gray-500 mt-1 px-1 flex items-center gap-1">
                    <span>{formatDate(message.created_date)}</span>
                    {isSender && (
                        message.is_read ? <CheckCheck className="w-4 h-4 text-blue-500" /> : <Check className="w-4 h-4" />
                    )}
                </div>
            </div>
        </div>
    );
}

components.messages/MessageInput:
import React, { useState, useRef } from 'react';
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Send, Loader2, Paperclip } from "lucide-react";
import { UploadFile } from "@/integrations/Core";

export default function MessageInput({ onSendMessage, isSending }) {
    const [newMessage, setNewMessage] = useState("");
    const fileInputRef = useRef(null);

    const handleSend = () => {
        if (!newMessage.trim()) return;
        onSendMessage({ type: 'text', content: newMessage.trim() });
        setNewMessage("");
    };

    const handleFileChange = async (event) => {
        const file = event.target.files[0];
        if (!file) return;

        try {
            const { file_url } = await UploadFile({ file });
            onSendMessage({ type: 'file', content: file.name, url: file_url });
        } catch (error) {
            console.error("File upload failed:", error);
            // Optionally, show an error toast to the user
        } finally {
            // Reset file input
            if(fileInputRef.current) fileInputRef.current.value = "";
        }
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div className="flex items-start gap-2 p-4 border-t bg-white">
            <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                className="hidden"
            />
            <Button
                variant="ghost"
                size="icon"
                className="text-gray-500 h-10 w-10 flex-shrink-0"
                onClick={() => fileInputRef.current?.click()}
                disabled={isSending}
            >
                <Paperclip className="w-5 h-5" />
            </Button>
            <Textarea
                value={newMessage}
                onChange={(e) => setNewMessage(e.target.value)}
                placeholder="Type your message..."
                rows={1}
                onKeyPress={handleKeyPress}
                className="resize-none pr-4 min-h-[40px] max-h-32"
                style={{ overflowY: 'auto' }}
            />
            <Button
                onClick={handleSend}
                disabled={isSending || !newMessage.trim()}
                className="bg-emerald-600 hover:bg-emerald-700 self-end h-10"
            >
                {isSending ? (
                    <Loader2 className="w-5 h-5 animate-spin" />
                ) : (
                    <Send className="w-5 h-5" />
                )}
            </Button>
        </div>
    );
}

