  );
}

components.notifications/NotificationCenter:
import React, { useState, useEffect, useCallback } from "react";
import { User, Notification } from "@/entities/all";
import { Bell, MessageSquare, CalendarCheck, Star, Users, Info, Loader2, X } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { formatDistanceToNow } from "date-fns";
import { useNavigate } from "react-router-dom";

const NOTIFICATION_CHECK_INTERVAL = 120000; // Check every 2 minutes (reduced frequency)

export default function NotificationCenter() {
  const [notifications, setNotifications] = useState([]);
  const [user, setUser] = useState(null);
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isFailing, setIsFailing] = useState(false);
  const [lastFetchTime, setLastFetchTime] = useState(0);
  const navigate = useNavigate();

  const fetchNotifications = useCallback(async (currentUser, force = false) => {
    if (!currentUser || isFailing) return;

    // Prevent rapid successive calls - enforce minimum 30 second delay
    const now = Date.now();
    if (!force && now - lastFetchTime < 30000) {
      return;
    }

    setIsLoading(true);
    setLastFetchTime(now);

    try {
      await new Promise(resolve => setTimeout(resolve, 200)); // Add delay before API call
      const fetchedNotifications = await Notification.filter(
        { user_id: currentUser.id },
        "-created_date",
        20
      );
      setNotifications(fetchedNotifications);
      setIsFailing(false); // Reset failure state on success
    } catch (err) {
      console.warn("Could not fetch notifications. Pausing automatic checks.", err.message);
      setIsFailing(true);
      setNotifications([]);
      // Retry after 10 minutes on failure
      setTimeout(() => setIsFailing(false), 600000);
    } finally {
      setIsLoading(false);
    }
  }, [isFailing, lastFetchTime]);

  const dismissNotification = useCallback(async (notificationId) => {
    setNotifications(prev => prev.filter(n => n.id !== notificationId));
    try {
      await Notification.delete(notificationId);
    } catch (error) {
      console.warn("Failed to dismiss notification silently.", error.message);
    }
  }, []);

  const handleNotificationClick = useCallback(async (notification) => {
    if (!notification.is_read) {
      setNotifications(prev => prev.map(n => n.id === notification.id ? { ...n, is_read: true } : n));
      try {
        await Notification.update(notification.id, { is_read: true });
      } catch (error) {
        console.warn("Failed to mark notification as read silently.", error.message);
      }
    }
    if (notification.action_url && notification.action_url.trim() !== "#") {
      setIsOpen(false);
      navigate(notification.action_url);
    }
  }, [navigate]);

  useEffect(() => {
    const init = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
        if (currentUser) {
          await fetchNotifications(currentUser, true); // Force initial fetch
          // Set up periodic refresh with longer interval
          const intervalId = setInterval(() => {
            if (!isFailing) {
              fetchNotifications(currentUser);
            }
          }, NOTIFICATION_CHECK_INTERVAL);
          return () => clearInterval(intervalId);
        }
      } catch (e) {
        setUser(null);
      }
    };
    init();
  }, []); // Remove fetchNotifications from dependencies to prevent re-initialization

  const getNotificationIcon = (type) => {
    const icons = {
      booking: <CalendarCheck className="w-5 h-5 text-emerald-500" />,
      message: <MessageSquare className="w-5 h-5 text-blue-500" />,
      event: <CalendarCheck className="w-5 h-5 text-purple-500" />,
      review: <Star className="w-5 h-5 text-yellow-500" />,
      community: <Users className="w-5 h-5 text-orange-500" />,
      system: <Info className="w-5 h-5 text-gray-500" />,
    };
    return icons[type] || <Bell className="w-5 h-5 text-gray-500" />;
  };

  const getNotificationBorder = (type) => {
      const borders = {
          booking: 'border-l-emerald-500',
          message: 'border-l-blue-500',
          event: 'border-l-purple-500',
          review: 'border-l-yellow-500',
          community: 'border-l-orange-500',
          system: 'border-l-gray-500',
      };
      return borders[type] || 'border-l-gray-500';
  };

  const getNotificationBg = (type, isRead) => {
      if (isRead) return 'bg-white hover:bg-gray-50';
      const backgrounds = {
          booking: 'bg-emerald-50 hover:bg-emerald-100',
          message: 'bg-blue-50 hover:bg-blue-100',
          event: 'bg-purple-50 hover:bg-purple-100',
          review: 'bg-yellow-50 hover:bg-yellow-100',
          community: 'bg-orange-50 hover:bg-orange-100',
          system: 'bg-gray-50 hover:bg-gray-100',
      };
      return backgrounds[type] || 'bg-gray-50 hover:bg-gray-100';
  };

  if (!user) return null;

  const unreadCount = notifications.filter(n => !n.is_read).length;

  return (
    <Popover open={isOpen} onOpenChange={setIsOpen}>
      <PopoverTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="w-5 h-5" />
          {unreadCount > 0 && (
            <Badge className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 bg-red-500 text-white text-xs animate-pulse">
              {unreadCount > 9 ? '9+' : unreadCount}
            </Badge>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-80 p-0" align="end">
        <div className="flex items-center justify-between p-4 border-b bg-white">
          <h3 className="text-lg font-semibold text-gray-900">Notifications</h3>
          {unreadCount > 0 && (
            <Badge variant="secondary" className="bg-emerald-100 text-emerald-800 border-emerald-200">
              {unreadCount} new
            </Badge>
          )}
        </div>

        <div className="max-h-96 overflow-y-auto">
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="w-8 h-8 text-emerald-600 animate-spin" />
            </div>
          ) : notifications.length === 0 ? (
            <div className="text-center py-8 text-gray-500">
              <Bell className="w-12 h-12 mx-auto mb-4 text-gray-300" />
              <p className="font-medium">No notifications</p>
              <p className="text-xs">New updates will appear here.</p>
            </div>
          ) : (
            notifications.map(notification => (
              <div
                key={notification.id}
                className={`flex gap-3 p-3 border-b border-l-4 transition-colors cursor-pointer ${getNotificationBorder(notification.type)} ${getNotificationBg(notification.type, notification.is_read)}`}
                onClick={() => handleNotificationClick(notification)}
              >
                <div className="flex-shrink-0 pt-1">
                  {getNotificationIcon(notification.type)}
                </div>
                <div className="flex-1">
                  <p className="text-sm text-gray-800">{notification.message}</p>
                  <p className="text-xs text-gray-500 mt-1">
                    {formatDistanceToNow(new Date(notification.created_date), { addSuffix: true })}
                  </p>
                </div>
                <Button variant="ghost" size="icon" className="h-8 w-8 self-center" onClick={(e) => { e.stopPropagation(); dismissNotification(notification.id); }}>
                  <X className="w-4 h-4 text-gray-400" />
                </Button>
              </div>
            ))
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}

components.notifications/NotificationService:
import { Notification } from '@/entities/Notification';
import { SendEmail } from '@/integrations/Core';
import { createPageUrl } from '@/utils';

export class NotificationService {
  // Create booking-related notifications
  static async createBookingNotification(userId, bookingData, type) {
    const notifications = {
      confirmed: {
        title: 'Booking Confirmed!',
        message: `Your session with ${bookingData.practitioner_name} has been confirmed for ${new Date(bookingData.requested_date).toLocaleDateString()}.`,
        priority: 'high'
      },
      declined: {
        title: 'Booking Update',
        message: `Unfortunately, ${bookingData.practitioner_name} cannot accommodate your requested session date.`,
        priority: 'normal'
      },
      cancelled: {
        title: 'Booking Cancelled',
        message: `Your session with ${bookingData.practitioner_name} has been cancelled.`,
        priority: 'normal'
      },
      completed: {
        title: 'Session Complete',
        message: `Your session with ${bookingData.practitioner_name} is complete. How was your experience?`,
        priority: 'normal'
      }
    };

    const config = notifications[type];
    if (!config) return;

    return await Notification.create({
      user_id: userId,
      title: config.title,
      message: config.message,
      type: 'booking',
      priority: config.priority,
      related_id: bookingData.id,
      action_url: createPageUrl('Bookings'),
      metadata: {
        practitioner_name: bookingData.practitioner_name,
        booking_status: type
      }
    });
  }

  // Create message notifications
  static async createMessageNotification(receiverId, messageData) {
    return await Notification.create({
      user_id: receiverId,
      title: `New message from ${messageData.sender_name}`,
      message: messageData.content.substring(0, 100) + (messageData.content.length > 100 ? '...' : ''),
      type: 'message',
      priority: 'normal',
      related_id: messageData.conversation_id,
      action_url: `${createPageUrl('Messages')}?conversation_id=${messageData.conversation_id}`,
      metadata: {
        sender_name: messageData.sender_name
      }
    });
  }

  // Create event notifications
  static async createEventNotification(userId, eventData, type) {
    const notifications = {
      registration_confirmed: {
        title: 'Event Registration Confirmed',
        message: `You're registered for "${eventData.title}" on ${new Date(eventData.start_date).toLocaleDateString()}.`,
        priority: 'high'
      },
      reminder_24h: {
        title: 'Event Tomorrow',
        message: `Don't forget: "${eventData.title}" is tomorrow at ${new Date(eventData.start_date).toLocaleTimeString()}.`,
        priority: 'high'
      },
      reminder_1h: {
        title: 'Event Starting Soon',
        message: `"${eventData.title}" begins in 1 hour. Please prepare accordingly.`,
        priority: 'urgent'
      },
      cancelled: {
        title: 'Event Cancelled',
        message: `Unfortunately, "${eventData.title}" has been cancelled. You'll receive a full refund.`,
        priority: 'high'
      }
    };

    const config = notifications[type];
    if (!config) return;

    return await Notification.create({
      user_id: userId,
      title: config.title,
      message: config.message,
      type: 'event',
      priority: config.priority,
      related_id: eventData.id,
      action_url: createPageUrl('Events'),
      metadata: {
        event_title: eventData.title
      }
    });
  }

  // Create community notifications
  static async createCommunityNotification(title, message, priority = 'normal', actionUrl = null) {
    // This would typically be sent to all users or a specific subset
    // For now, we'll create a method that can be called for specific users
    return {
      title,
      message,
      type: 'community',
      priority,
      action_url: actionUrl
    };
  }

  // Create system notifications
  static async createSystemNotification(userId, title, message, priority = 'normal') {
    return await Notification.create({
      user_id: userId,
      title,
      message,
      type: 'system',
      priority,
    });
  }

  // Send email notifications for high-priority items
  static async sendEmailNotification(userEmail, subject, message) {
    try {
      await SendEmail({
        to: userEmail,
        subject: `KamboConnect: ${subject}`,
        body: message
      });
    } catch (error) {
      console.error('Failed to send email notification:', error);
    }
  }
}

components.favorites/FavoriteButton:
import React, { useState, useEffect } from 'react';
import { Heart } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { Favorite } from '@/entities/Favorite';
import { User } from '@/entities/User';
import { cn } from '@/lib/utils';
import { motion } from 'framer-motion';

export default function FavoriteButton({ 
  itemId, 
  itemType, 
  itemTitle,
  metadata = {},
  className = "",
  size = "default"
}) {
  const [isFavorited, setIsFavorited] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [user, setUser] = useState(null);
  const [hasFetched, setHasFetched] = useState(false);

  useEffect(() => {
    const loadUserAndFavoriteStatus = async () => {
      if (hasFetched) return; // Prevent multiple fetches

      try {
        const currentUser = await User.me();
        setUser(currentUser);
        setHasFetched(true);

        if (currentUser) {
          await new Promise(resolve => setTimeout(resolve, 150)); // Add delay to prevent rate limiting
          const existingFavorite = await Favorite.filter({
            user_id: currentUser.id,
            item_id: itemId,
            item_type: itemType
          });
          setIsFavorited(existingFavorite.length > 0);
        }
      } catch (error) {
        // User not logged in or other error
        console.warn("Could not load favorite status:", error.message);
        setUser(null);
        setHasFetched(true);
      }
    };

    loadUserAndFavoriteStatus();
  }, [itemId, itemType, hasFetched]);

  const toggleFavorite = async (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (!user) {
      // Optionally redirect to login or show message
      await User.login();
      return;
    }

    setIsLoading(true);
    try {
      if (isFavorited) {
        // Remove favorite - optimistically update UI first
        setIsFavorited(false);

        // Add delay before API call to prevent rate limiting
        await new Promise(resolve => setTimeout(resolve, 100));
        const existingFavorites = await Favorite.filter({
          user_id: user.id,
          item_id: itemId,
          item_type: itemType
        });

        if (existingFavorites.length > 0) {
          await Favorite.delete(existingFavorites[0].id);
        }
      } else {
        // Add favorite - optimistically update UI first
        setIsFavorited(true);

        // Add delay before API call to prevent rate limiting
        await new Promise(resolve => setTimeout(resolve, 100));
        await Favorite.create({
          user_id: user.id,
          item_id: itemId,
          item_type: itemType,
          item_title: itemTitle,
          metadata
        });
      }
    } catch (error) {
      console.error('Failed to toggle favorite:', error);
      // Revert optimistic update on error
      setIsFavorited(!isFavorited);
    } finally {
      setIsLoading(false);
    }
  };

  const sizeClasses = {
    sm: "h-8 w-8",
    default: "h-10 w-10",
    lg: "h-12 w-12"
  };

  const iconSizes = {
    sm: "w-4 h-4",
    default: "w-5 h-5", 
    lg: "w-6 h-6"
  };

  return (
    <Button
      variant="ghost"
      size="icon"
      onClick={toggleFavorite}
      disabled={isLoading}
      className={cn(
        "relative hover:bg-red-50 hover:text-red-600 transition-all",
        sizeClasses[size],
        className
      )}
    >
      <motion.div
        animate={{ 
          scale: isFavorited ? [1, 1.2, 1] : 1,
        }}
        transition={{ duration: 0.3 }}
      >
        <Heart 
          className={cn(
            iconSizes[size],
            "transition-all duration-200",
            isFavorited 
              ? "fill-red-500 text-red-500" 
              : "text-gray-400 hover:text-red-500"
          )} 
        />
      </motion.div>
      {isFavorited && (
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: [0, 1.5, 1] }}
          transition={{ duration: 0.5 }}
          className="absolute inset-0 pointer-events-none"
        >
          <Heart className={cn(iconSizes[size], "text-red-500 fill-red-500 m-auto mt-2")} />
        </motion.div>
      )}
    </Button>
  );
}

components.utils/locationUtils:
/**
 * Calculate distance between two points using Haversine formula
 * Returns distance in miles
 */
export const calculateDistance = (lat1, lon1, lat2, lon2) => {
  if (!lat1 || !lon1 || !lat2 || !lon2) return null;

  const R = 3959; // Earth's radius in miles
  const dLat = toRadians(lat2 - lat1);
  const dLon = toRadians(lon2 - lon1);

  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRadians(lat1)) * Math.cos(toRadians(lat2)) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  const distance = R * c;

  return Math.round(distance * 10) / 10; // Round to 1 decimal place
};

const toRadians = (degrees) => {
  return degrees * (Math.PI / 180);
};

/**
 * Get user's current location using browser geolocation
 */
export const getCurrentLocation = () => {
  return new Promise((resolve, reject) => {
    if (!navigator.geolocation) {
      reject(new Error('Geolocation is not supported by this browser'));
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        resolve({
          latitude: position.coords.latitude,
          longitude: position.coords.longitude,
          accuracy: position.coords.accuracy
        });
      },
      (error) => {
        let errorMessage;
        switch (error.code) {
          case error.PERMISSION_DENIED:
            errorMessage = 'Location access denied by user';
            break;
          case error.POSITION_UNAVAILABLE:
            errorMessage = 'Location information unavailable';
            break;
          case error.TIMEOUT:
            errorMessage = 'Location request timed out';
            break;
          default:
            errorMessage = 'An unknown error occurred while retrieving location';
        }
        reject(new Error(errorMessage));
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 300000 // Cache for 5 minutes
      }
    );
  });
};

/**
 * Format distance for display
 */
export const formatDistance = (distance) => {
  if (distance === null || distance === undefined) return 'Distance unknown';
  if (distance < 1) return `${(distance * 5280).toFixed(0)} ft`;
  return `${distance} mi`;
};

/**
 * Sort array of items by distance from user location
 */
export const sortByDistance = (items, userLocation, getItemLocation) => {
  if (!userLocation) return items;

  return items
    .map(item => {
      const itemLocation = getItemLocation(item);
      const distance = itemLocation ? 
        calculateDistance(
          userLocation.latitude, 
          userLocation.longitude, 
          itemLocation.latitude, 
          itemLocation.longitude
        ) : null;

      return { ...item, distance };
    })
    .sort((a, b) => {
      // Items with no distance go to the end
      if (a.distance === null && b.distance === null) return 0;
      if (a.distance === null) return 1;
      if (b.distance === null) return -1;
      return a.distance - b.distance;
    });
};

