                          <MoreHorizontal className="w-4 h-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent>
                        <DropdownMenuItem onClick={() => { /* View profile */ }}>
                          <Eye className="w-4 h-4 mr-2" />
                          View Profile
