                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => { setSelectedUser(user); setSelectedAction('suspend'); }}>
                          <Shield className="w-4 h-4 mr-2" />
                          Suspend User
                        </DropdownMenuItem>
