              {type === 'post' && (
                <Badge variant="outline" className="ml-2">{content.category}</Badge>
              )}
            </div>
            <div 
              className="prose prose-sm max-w-none"
              dangerouslySetInnerHTML={{ 
                __html: isExpanded ? content.content : truncateText(content.content) 
              }}
            />
            {content.content.length > 150 && (
              <Button 
                variant="link" 
                size="sm" 
                onClick={() => setIsExpanded(!isExpanded)}
                className="p-0 h-auto text-xs"
              >
                {isExpanded ? 'Show less' : 'Show more'}
              </Button>
            )}
          </div>
          <div className="flex flex-col gap-2 ml-4">
            <Button 
              variant="outline" 
              size="sm"
              onClick={() => onAction(content.id, 'flag')}
            >
              <Flag className="w-3 h-3 mr-1" />
              Flag
            </Button>
            <Button 
              variant="outline" 
              size="sm"
              onClick={() => onAction(content.id, 'hide')}
            >
              <EyeOff className="w-3 h-3 mr-1" />
              Hide
            </Button>
            <Button 
              variant="destructive" 
              size="sm"
              onClick={() => onAction(content.id, 'delete')}
            >
              <Trash2 className="w-3 h-3 mr-1" />
              Delete
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

export default function ContentModeration() {
  const [posts, setPosts] = useState([]);
  const [replies, setReplies] = useState([]);
  const [flaggedContent, setFlaggedContent] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(true);

  const loadContent = async () => {
    try {
      const [allPosts, allReplies, reports] = await Promise.all([
        Post.list('-created_date', 50),
        Reply.list('-created_date', 50), 
        Report.filter({ reported_item_type: 'post' })
      ]);

      setPosts(allPosts);
      setReplies(allReplies);
      setFlaggedContent(reports);
    } catch (error) {
      console.error("Failed to load content:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadContent();
  }, []);

  const handleContentAction = async (contentId, action) => {
    try {
      switch (action) {
        case 'flag':
          await Report.create({
            reported_item_type: 'post',
            reported_item_id: contentId,
            reporter_id: 'admin',
            reason: 'Admin flagged for review',
            status: 'pending'
          });
          break;
        case 'hide':
          // In a real app, you'd update a 'is_hidden' field
          console.log(`Hiding content ${contentId}`);
          break;
        case 'delete':
          const confirmDelete = window.confirm('Are you sure you want to delete this content? This action cannot be undone.');
          if (confirmDelete) {
            await Post.delete(contentId);
            loadContent(); // Refresh
          }
          break;
      }
    } catch (error) {
      console.error(`Failed to ${action} content:`, error);
    }
  };

  const filteredPosts = posts.filter(post => 
    !searchTerm || 
    post.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    post.content?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    post.author_name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredReplies = replies.filter(reply => 
    !searchTerm || 
    reply.content?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    reply.author_name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <MessageSquare className="w-5 h-5 text-blue-600" />
            Content Moderation
          </CardTitle>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
            <Input
              placeholder="Search content..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10"
            />
          </div>
        </CardHeader>
      </Card>

      <Tabs defaultValue="posts">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="posts">
            Posts ({filteredPosts.length})
          </TabsTrigger>
          <TabsTrigger value="replies">
            Replies ({filteredReplies.length})
          </TabsTrigger>
          <TabsTrigger value="flagged">
            Flagged ({flaggedContent.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="posts" className="space-y-4">
          {filteredPosts.map(post => (
            <ContentItem 
              key={post.id}
              content={post}
              type="post"
              onAction={handleContentAction}
            />
          ))}
        </TabsContent>

        <TabsContent value="replies" className="space-y-4">
          {filteredReplies.map(reply => (
            <ContentItem 
              key={reply.id}
              content={reply}
              type="reply"
              onAction={handleContentAction}
            />
          ))}
        </TabsContent>

        <TabsContent value="flagged" className="space-y-4">
          {flaggedContent.length > 0 ? (
            flaggedContent.map(report => (
              <Card key={report.id} className="border-orange-200">
                <CardContent className="p-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <h4 className="font-medium">Flagged Content Report</h4>
                      <p className="text-sm text-gray-600 mt-1">{report.reason}</p>
                      <p className="text-xs text-gray-500 mt-2">
                        Reported {format(new Date(report.created_date), 'MMM d, yyyy')}
                      </p>
                    </div>
                    <Badge variant="outline" className="text-orange-600">
                      Needs Review
                    </Badge>
                  </div>
                </CardContent>
              </Card>
            ))
          ) : (
            <Card>
              <CardContent className="p-8 text-center text-gray-500">
                <AlertTriangle className="w-12 h-12 mx-auto mb-4" />
                <p>No flagged content.</p>
              </CardContent>
            </Card>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

components.admin/VerificationManagement:
import React, { useState, useEffect } from "react";
import { Practitioner } from "@/entities/Practitioner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { 
  ShieldCheck, 
  CheckCircle, 
  XCircle, 
  Clock,
  ExternalLink,
  Loader2
} from "lucide-react";
import { format } from "date-fns";

const ApplicationCard = ({ application, onAction, onUpgrade }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'basic': return 'bg-green-100 text-green-800';
      case 'advanced': return 'bg-blue-100 text-blue-800';
      case 'master': return 'bg-purple-100 text-purple-800';
      case 'rejected': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <Card className="mb-4">
      <CardHeader>
        <div className="flex justify-between items-start">
          <div>
            <CardTitle className="text-lg">{application.full_name}</CardTitle>
            <p className="text-sm text-gray-600">{application.email}</p>
            <p className="text-sm text-gray-500">
              Applied {format(new Date(application.created_date), 'MMM d, yyyy')}
            </p>
          </div>
          <Badge className={getStatusColor(application.verification_level)}>
            {application.verification_level}
          </Badge>
        </div>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm">
            <div>
              <span className="font-medium">Experience:</span> {application.years_experience} years
            </div>
            <div>
              <span className="font-medium">Pricing:</span> {application.pricing_range || 'Not specified'}
            </div>
            <div>
              <span className="font-medium">Languages:</span> {application.languages?.join(', ') || 'Not specified'}
            </div>
          </div>

          {isExpanded && (
            <div className="space-y-4 border-t pt-4">
              <div>
                <h4 className="font-medium mb-2">Bio:</h4>
                <p className="text-sm bg-gray-50 p-3 rounded">{application.bio}</p>
              </div>

              <div>
                <h4 className="font-medium mb-2">Training Background:</h4>
                <p className="text-sm bg-gray-50 p-3 rounded">{application.training_background}</p>
              </div>

              <div>
                <h4 className="font-medium mb-2">Safety Protocols:</h4>
                <p className="text-sm bg-gray-50 p-3 rounded">{application.safety_protocols}</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <h4 className="font-medium mb-2">Documents:</h4>
                  <div className="space-y-2">
                    {application.cpr_certification_url && (
                      <a 
                        href={application.cpr_certification_url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 text-sm text-blue-600 hover:underline"
                      >
                        <ExternalLink className="w-3 h-3" />
                        CPR Certification
                      </a>
                    )}
                    {application.kambo_certification_url && (
                      <a 
                        href={application.kambo_certification_url} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-2 text-sm text-blue-600 hover:underline"
                      >
                        <ExternalLink className="w-3 h-3" />
                        Kambo Training Certificate
