export default function VerificationManagement() {
  const [pendingApps, setPendingApps] = useState([]);
  const [approvedApps, setApprovedApps] = useState([]);
  const [rejectedApps, setRejectedApps] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [currentTab, setCurrentTab] = useState("pending");

  const loadApplications = async (tab) => {
    setIsLoading(true);
    try {
      if (tab === "pending") {
        const applications = await Practitioner.filter({ verification_level: "pending" }, '-created_date');
        setPendingApps(applications);
      } else if (tab === "approved") {
        // Fetch all verified levels
        const basic = await Practitioner.filter({ verification_level: "basic" }, '-created_date');
        const advanced = await Practitioner.filter({ verification_level: "advanced" }, '-created_date');
        const master = await Practitioner.filter({ verification_level: "master" }, '-created_date');
        setApprovedApps([...basic, ...advanced, ...master]);
      } else if (tab === "rejected") {
        const applications = await Practitioner.filter({ verification_level: "rejected" }, '-created_date');
        setRejectedApps(applications);
      }
    } catch (error) {
      console.error("Failed to load applications:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadApplications(currentTab);
  }, [currentTab]);

  const refreshData = () => {
    loadApplications(currentTab);
  };

  const handleAction = async (applicationId, action) => {
    try {
      if (action === 'approve') {
        await Practitioner.update(applicationId, {
          is_verified: true,
          verification_level: 'basic'
        });
      } else if (action === 'reject') {
        const reason = prompt('Please provide a reason for rejection:');
        if (reason) {
          await Practitioner.update(applicationId, {
            verification_level: 'rejected',
            rejection_reason: reason
          });
        }
      }
      refreshData(); // Refresh current tab
    } catch (error) {
      console.error(`Failed to ${action} application:`, error);
    }
  };

  const handleUpgrade = async (id, level) => {
    try {
        await Practitioner.update(id, { verification_level: level });
        refreshData();
    } catch(e) {
        console.error("Failed to upgrade practitioner:", e);
    }
  };


  const renderContent = (applications) => {
    if (isLoading) {
      return (
        <Card>
          <CardContent className="p-8 text-center text-gray-500">
            <Loader2 className="w-12 h-12 mx-auto mb-4 animate-spin" />
            <p>Loading applications...</p>
          </CardContent>
        </Card>
      );
    }

    if (applications.length === 0) {
       return (
         <Card>
           <CardContent className="p-8 text-center text-gray-500">
             <Clock className="w-12 h-12 mx-auto mb-4" />
             <p>No applications in this category.</p>
           </CardContent>
         </Card>
       );
    }

    return applications.map(app => (
      <ApplicationCard key={app.id} application={app} onAction={handleAction} onUpgrade={handleUpgrade} />
    ));
  }


  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ShieldCheck className="w-5 h-5 text-purple-600" />
            Practitioner Verification
          </CardTitle>
        </CardHeader>
      </Card>

      <Tabs defaultValue="pending" onValueChange={setCurrentTab}>
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="pending">
            Pending ({pendingApps.length})
          </TabsTrigger>
          <TabsTrigger value="approved">
            Approved ({approvedApps.length})
          </TabsTrigger>
          <TabsTrigger value="rejected">
            Rejected ({rejectedApps.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="pending" className="space-y-4">
          {renderContent(pendingApps)}
        </TabsContent>

        <TabsContent value="approved" className="space-y-4">
          {renderContent(approvedApps)}
        </TabsContent>

        <TabsContent value="rejected" className="space-y-4">
          {renderContent(rejectedApps)}
        </TabsContent>
      </Tabs>
    </div>
  );
}

components.admin/PlatformAnalytics:
import React, { useState, useEffect } from "react";
import { User, Practitioner, Booking, Post, Event } from "@/entities/all";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { 
  BarChart3, 
  TrendingUp, 
  Users, 
  Calendar,
  MessageSquare,
  Star
} from "lucide-react";

export default function PlatformAnalytics() {
  const [analytics, setAnalytics] = useState({
    totalUsers: 0,
    totalPractitioners: 0,
    totalBookings: 0,
    totalPosts: 0,
    totalEvents: 0,
    verifiedPractitioners: 0,
    monthlyGrowth: {
      users: 0,
      bookings: 0
    }
  });
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadAnalytics = async () => {
      try {
        const [users, practitioners, bookings, posts, events] = await Promise.all([
          User.list(),
          Practitioner.list(),
          Booking.list(),
          Post.list(),
          Event.list()
        ]);

        const verifiedCount = practitioners.filter(p => p.is_verified).length;

        // Calculate monthly growth (simplified)
        const thisMonth = new Date();
        thisMonth.setDate(1);

        const recentUsers = users.filter(u => new Date(u.created_date) >= thisMonth);
        const recentBookings = bookings.filter(b => new Date(b.created_date) >= thisMonth);

        setAnalytics({
          totalUsers: users.length,
          totalPractitioners: practitioners.length,
          totalBookings: bookings.length,
          totalPosts: posts.length,
          totalEvents: events.length,
          verifiedPractitioners: verifiedCount,
          monthlyGrowth: {
            users: recentUsers.length,
            bookings: recentBookings.length
          }
        });
      } catch (error) {
        console.error("Failed to load analytics:", error);
      } finally {
        setIsLoading(false);
      }
    };

    loadAnalytics();
  }, []);

  const StatCard = ({ title, value, icon: Icon, color, trend }) => (
    <Card>
      <CardContent className="p-6">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-gray-600">{title}</p>
            <p className="text-2xl font-bold text-gray-900">{value}</p>
            {trend && (
              <p className="text-xs text-gray-500 mt-1">
                +{trend} this month
              </p>
            )}
          </div>
          <Icon className={`w-8 h-8 ${color}`} />
        </div>
      </CardContent>
    </Card>
  );

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <BarChart3 className="w-5 h-5 text-indigo-600" />
            Platform Analytics
          </CardTitle>
        </CardHeader>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <StatCard
          title="Total Users"
          value={analytics.totalUsers}
          icon={Users}
          color="text-blue-600"
          trend={analytics.monthlyGrowth.users}
        />

        <StatCard
          title="Total Practitioners"
          value={analytics.totalPractitioners}
          icon={Star}
          color="text-emerald-600"
        />

        <StatCard
          title="Verified Practitioners"
          value={analytics.verifiedPractitioners}
          icon={TrendingUp}
          color="text-purple-600"
        />

        <StatCard
          title="Total Bookings"
          value={analytics.totalBookings}
          icon={Calendar}
          color="text-orange-600"
          trend={analytics.monthlyGrowth.bookings}
        />

        <StatCard
          title="Community Posts"
          value={analytics.totalPosts}
          icon={MessageSquare}
          color="text-pink-600"
        />

        <StatCard
          title="Events Created"
          value={analytics.totalEvents}
          icon={Calendar}
          color="text-indigo-600"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Platform Health</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-sm">Verification Rate</span>
                <span className="font-medium">
                  {analytics.totalPractitioners > 0 
