import React, { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { User } from "@/entities/User";
import { Search, Users, Calendar, Store, BookOpen, Menu, Heart, User as UserIcon, LogOut, Shield, Briefcase, Settings, LogIn, MessageSquare, ShieldCheck, PlusCircle } from "lucide-react";
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import NotificationCenter from "../components/notifications/NotificationCenter";

// Main navigation for Desktop Sidebar and Mobile Sheet
const mainNavItems = [
  { title: "Directory", url: createPageUrl("Directory"), icon: Search, isPublic: true },
  { title: "Community", url: createPageUrl("Community"), icon: Users, isPublic: true },
  { title: "Events", url: createPageUrl("Events"), icon: Calendar, isPublic: true },
  { title: "My Bookings", url: createPageUrl("Bookings"), icon: Briefcase, isPublic: false },
  { title: "Messages", url: createPageUrl("Messages"), icon: MessageSquare, isPublic: false },
  { title: "My Favorites", url: createPageUrl("Favorites"), icon: Heart, isPublic: false },
  { title: "Market", url: createPageUrl("Market"), icon: Store, isPublic: true },
  { title: "Learn", url: createPageUrl("Education"), icon: BookOpen, isPublic: true },
];

// User-specific items for sidebar/sheet
const userDrawerItems = [
    { title: "Profile", url: createPageUrl("Profile"), icon: UserIcon },
    { title: "My Account", url: createPageUrl("MyAccount"), icon: Settings },
    { title: "Practitioner Dashboard", url: createPageUrl("PractitionerDashboard"), icon: Briefcase },
    { title: "Admin Dashboard", url: createPageUrl("AdminDashboard"), icon: ShieldCheck, adminOnly: true },
    { title: "Admin Verification", url: createPageUrl("Verification"), icon: ShieldCheck, adminOnly: true },
    { title: "Legal Disclaimer", url: createPageUrl("Disclaimer"), icon: Shield },
];

// --- New: Mobile Bottom Navigation Items ---
const mobileBottomNavItems = [
  { title: "Search", url: createPageUrl("Directory"), icon: Search },
  { title: "Events", url: createPageUrl("Events"), icon: Calendar },
  { title: "Bookings", url: createPageUrl("Bookings"), icon: Briefcase },
  { title: "Community", url: createPageUrl("Community"), icon: Users },
  { title: "Profile", url: createPageUrl("Profile"), icon: UserIcon },
];

// --- New: Helper to get page titles ---
const getPageTitle = (pathname) => {
    const allNavItems = [...mainNavItems, ...userDrawerItems];
    const item = allNavItems.find(item => item.url === pathname);
    if (item) return item.title;

    if (pathname.startsWith(createPageUrl('Post'))) return 'Forum Post';
    if (pathname.startsWith(createPageUrl('NewPost'))) return 'New Post';
    if (pathname.startsWith(createPageUrl('BookingRequest'))) return 'Booking Request';

    // Fallback title
    return "KamboConnect";
};


export default function Layout({ children }) {
  const location = useLocation();
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSheetOpen, setIsSheetOpen] = useState(false);

  useEffect(() => {
    const checkUser = async () => {
      try {
        const currentUser = await User.me();
        setUser(currentUser);
      } catch (e) {
        setUser(null);
      } finally {
        setIsLoading(false);
      }
    };
    checkUser();
  }, [location.pathname]);

  const handleLogout = async () => {
    await User.logout();
    setUser(null);
    setIsSheetOpen(false); // Close sheet on logout
    navigate(createPageUrl('Directory'));
  };

  const handleLogin = async () => {
    await User.login();
  };

  const visibleMainNav = mainNavItems.filter(item => item.isPublic || !!user);
  const visibleUserDrawerItems = userDrawerItems.filter(item => 
    !item.adminOnly || (user && user.role === 'admin')
  );

  const pageTitle = getPageTitle(location.pathname);

  // --- New: Contextual action button logic ---
  const getContextualAction = () => {
    if (location.pathname === createPageUrl("Community")) {
      return {
        icon: PlusCircle,
        label: "New Post",
        action: () => navigate(createPageUrl("NewPost")),
      };
    }
    // Add more conditions here for other pages in the future
    // e.g., if (location.pathname === createPageUrl("Events") && user?.is_practitioner) ...
    return null;
  };

  const contextualAction = getContextualAction();

  return (
    <div className="min-h-screen w-full bg-gray-50 text-gray-900 md:flex">
      <style>{`
        :root {
          --background: 0 0% 100%;
          --foreground: 222.2 84% 4.9%;
          --card: 0 0% 100%;
          --card-foreground: 222.2 84% 4.9%;
          --popover: 0 0% 100%;
          --popover-foreground: 222.2 84% 4.9%;
          --primary: 142.1 76.2% 36.3%;
          --primary-foreground: 355.7 100% 97.3%;
          --secondary: 210 40% 96%;
          --secondary-foreground: 222.2 84% 4.9%;
          --muted: 210 40% 96%;
          --muted-foreground: 215.4 16.3% 46.9%;
          --accent: 210 40% 96%;
          --accent-foreground: 222.2 84% 4.9%;
          --destructive: 0 84.2% 60.2%;
          --destructive-foreground: 210 40% 98%;
          --border: 214.3 31.8% 91.4%;
          --input: 214.3 31.8% 91.4%;
          --ring: 142.1 76.2% 36.3%;
          --radius: 0.75rem;
        }
        html {
          -webkit-tap-highlight-color: transparent;
        }
        body {
            background-color: hsl(var(--background));
            color: hsl(var(--foreground));
            font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        }
        * {
          border-color: hsl(var(--border));
        }
      `}</style>

      {/* --- New: Mobile Header --- */}
      <header className="sticky top-0 z-40 flex h-16 items-center justify-between border-b border-gray-200 bg-white/95 backdrop-blur-sm px-4 md:hidden">
        <Sheet open={isSheetOpen} onOpenChange={setIsSheetOpen}>
          <SheetTrigger asChild>
            <Button variant="ghost" size="icon" className="shrink-0">
              <Menu className="h-6 w-6" />
              <span className="sr-only">Open menu</span>
            </Button>
          </SheetTrigger>
          <SheetContent side="left" className="w-72 bg-white p-0 flex flex-col">
              <div className="flex flex-col h-full">
                  {/* Fixed Header */}
                  <div className="flex-shrink-0 p-6 pb-4 border-b">
                      <Link to={createPageUrl('Directory')} onClick={() => setIsSheetOpen(false)} className="block">
                          <h2 className="font-bold text-2xl bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent">KamboConnect</h2>
                      </Link>
                  </div>

                  {/* Scrollable Content */}
                  <div className="flex-1 overflow-y-auto px-4 py-4">
                      {/* Main Navigation */}
                      <nav className="flex flex-col space-y-1">
                          {visibleMainNav.map(item => (
                              <Link 
                                  key={item.title} 
                                  to={item.url} 
                                  onClick={() => setIsSheetOpen(false)}
                                  className={`flex items-center gap-3 rounded-lg px-3 py-2.5 font-medium transition-all text-base ${
                                      location.pathname === item.url
                                          ? 'bg-emerald-50 text-emerald-700'
                                          : 'text-gray-700 hover:bg-gray-100'
                                  }`}
                              >
                                  <item.icon className="h-5 w-5" />
                                  <span>{item.title}</span>
                              </Link>
                          ))}
                      </nav>

                      {user && (
                        <>
                          <div className="my-4 h-px bg-gray-200" />
                          <nav className="flex flex-col space-y-1">
                            {visibleUserDrawerItems.map(item => (
                                <Link key={item.title} to={item.url} onClick={() => setIsSheetOpen(false)} className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-gray-700 transition-all hover:bg-gray-100 text-base">
                                    <item.icon className="h-5 w-5" />
                                    <span className="font-medium">{item.title}</span>
                                </Link>
                            ))}
                          </nav>
                        </>
                      )}
                  </div>
                  {/* Footer for Login/Logout */}
                  <div className="mt-auto border-t p-4">
                    {user ? (
                       <button
                            onClick={handleLogout}
                            className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-gray-700 transition-all hover:bg-gray-100 w-full text-left text-base"
                        >
                            <LogOut className="h-5 w-5" />
                            <span className="font-medium">Sign Out</span>
                        </button>
                    ) : (
                       <button
                            onClick={handleLogin}
                            className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-gray-700 transition-all hover:bg-gray-100 w-full text-left text-base"
                        >
                            <LogIn className="h-5 w-5" />
                            <span className="font-medium">Sign In</span>
                        </button>
                    )}
                  </div>
              </div>
          </SheetContent>
        </Sheet>

        <h1 className="text-lg font-semibold truncate">{pageTitle}</h1>

        <div className="flex items-center gap-2">
            {contextualAction && (
                <Button variant="ghost" size="icon" onClick={contextualAction.action}>
                    <contextualAction.icon className="h-6 w-6" />
                    <span className="sr-only">{contextualAction.label}</span>
                </Button>
            )}
            {user && <NotificationCenter />}
        </div>
      </header>

      {/* Desktop Sidebar */}
      <aside className="hidden w-64 flex-col border-r bg-white md:flex">
        <div className="flex h-16 items-center justify-between border-b px-6">
            <Link to={createPageUrl('Directory')} className="flex items-center gap-2">
                <h2 className="font-bold text-2xl bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent">KamboConnect</h2>
            </Link>
            {user && (
              <NotificationCenter />
            )}
        </div>
        <div className="flex-1 overflow-y-auto p-4">
             <nav className="flex flex-col space-y-1">
                {visibleMainNav.map(item => (
                    <Link
                        key={item.title}
                        to={item.url}
                        className={`flex items-center gap-3 rounded-lg px-4 py-2.5 font-medium transition-all text-base ${
                            location.pathname === item.url
                            ? 'bg-emerald-50 text-emerald-700'
                            : 'text-gray-700 hover:bg-gray-100'
                        }`}
                    >
                        <item.icon className="h-5 w-5" />
                        {item.title}
                    </Link>
                ))}
            </nav>
            {user && (
              <>
                <div className="my-4 h-px bg-gray-200" />
                <nav className="flex flex-col space-y-1">
                    {visibleUserDrawerItems.map(item => (
                        <Link
                            key={item.title}
                            to={item.url}
                            className={`flex items-center gap-3 rounded-lg px-4 py-2.5 font-medium transition-all text-base ${
                                location.pathname === item.url
                                ? 'bg-emerald-50 text-emerald-700'
                                : 'text-gray-600 hover:bg-gray-100'
                            }`}
                        >
                            <item.icon className="h-5 w-5" />
                            {item.title}
                        </Link>
                    ))}
                </nav>
              </>
            )}
        </div>
         <div className="mt-auto border-t p-4">
            {user ? (
              <button
                onClick={handleLogout}
                className="flex items-center gap-3 rounded-lg px-4 py-2.5 font-medium transition-all text-gray-600 hover:bg-gray-100 w-full text-left text-base"
              >
                <LogOut className="h-5 w-5" />
                Sign Out
              </button>
            ) : (
              <Button onClick={handleLogin} className="w-full bg-emerald-600 hover:bg-emerald-700">
                <LogIn className="w-4 h-4 mr-2" />
                Sign In
              </Button>
            )}
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 bg-gray-50">
        {/* --- New: Added padding-bottom for mobile nav --- */}
        <main className="pb-24 md:pb-0">{children}</main>
      </div>

      {/* --- New: Mobile Bottom Navigation --- */}
      <footer className="fixed bottom-0 z-30 w-full border-t bg-white/95 backdrop-blur-sm md:hidden">
        <nav className="grid grid-cols-5 items-center justify-items-center px-2 py-1">
          {mobileBottomNavItems.map((item) => (
            <Link
              key={item.title}
              to={item.url}
              aria-label={item.title}
              className={`flex flex-col items-center justify-center rounded-lg p-2 h-16 w-full transition-colors duration-200 ${
                location.pathname === item.url
                  ? "text-emerald-600"
                  : "text-gray-500 hover:text-emerald-600"
              }`}
            >
              <item.icon className="h-6 w-6" />
              <span className="text-xs font-medium">{item.title}</span>
            </Link>
          ))}
        </nav>
      </footer>
    </div>
  );
}
